import{A as e,E as t,_ as n,d as r,l as i,m as a,p as o,u as s}from"./vue.runtime.esm-bundler-bwlOp816.js";import{n as c,t as l}from"./index-C03y6Sp7.js";var u={},d={class:`rules`},f={ref:`8`};function p(e,n){return t(),o(`div`,d,[n[0]||=a(`<h1 class="rules-heading">SRA säännöt</h1><p class="rules-heading">Versio 8.1. Lähde <a href="https://resul.fi/sra/">https://resul.fi/sra/</a></p><hr><ul class="toc"><li><a href="#1">1. Johdanto</a></li><ul><li><a href="#1.1">1.1 Yleiset periaatteet</a></li><li><a href="#1.2">1.2 Kilpailut</a></li><li><a href="#1.3">1.3 Rastit</a></li><li><a href="#1.4">1.4 Ratalaitteet</a></li><li><a href="#1.5">1.5 Ajanotto</a></li></ul><li><a href="#2">2. Kilpailun toimihenkilöt</a></li><ul><li><a href="#2.1">2.1 Tekninen asiantuntija</a></li><li><a href="#2.2">2.2 Kilpailunjohtaja</a></li><li><a href="#2.3">2.3 Ratamestari</a></li><li><a href="#2.4">2.4 Tuloslaskentavastaava</a></li><li><a href="#2.5">2.5 Tuomari</a></li><li><a href="#2.6">2.6 Kirjuri</a></li><li><a href="#2.7">2.7 Muu organisaatio</a></li></ul><li><a href="#3">3. Turvamääräykset</a></li><ul><li><a href="#3.1">3.1 Turvallisen aseenkäsittelyn perusperiaatteet</a></li><li><a href="#3.2">3.2 Yleinen turvallisuus</a></li><li><a href="#3.3">3.3 Aseenkäsittely</a></li><li><a href="#3.4">3.4 Sektorit</a></li></ul><li><a href="#4">4. Toiminta rastilla</a></li><ul><li><a href="#4.1">4.1 Yleistä</a></li><li><a href="#4.2">4.2 Ratakomennot ja suorituksen aikainen toiminta</a></li></ul><li><a href="#5">5. Ase- ja varustemääräykset</a></li><ul><li><a href="#5.1">5.1 Yleistä</a></li><li><a href="#5.2">5.2 Aseet</a></li><li><a href="#5.3">5.3 Varusteet</a></li></ul><li><a href="#6">6. Käytettävät taulut ja pistelaskenta</a></li><ul><li><a href="#6.1">6.1 Yleiset periaatteet</a></li><li><a href="#6.2">6.2 Taulut</a></li><li><a href="#6.3">6.3 Osumien tulkkaus</a></li><li><a href="#6.4">6.4 Taulupisteet</a></li><li><a href="#6.5">6.5 Pistelaskutavat</a></li><li><a href="#6.6">6.6 Pistelaskun rangaistukset</a></li><li><a href="#6.7">6.7 Tuloslaskenta</a></li></ul><li><a href="#7">7. Tuloslaskentajärjestelmä</a></li><li><a href="#8">8. Uusinnat ja protestointi</a></li><li><a href="#8.1">8.1 Uusinnat</a></li><li><a href="#8.2">8.2 Valitusmenettely</a></li><li><a href="#liite1">Liite 1 - Pahvitaulu 2024</a></li><li><a href="#liite2">Liite 2 - Pahvitaulu</a></li><li><a href="#liite3">Liite 3 - Kivääri</a></li><li><a href="#liite4">Liite 4 - Pistooli ja revolveri</a></li><li><a href="#liite5">Liite 5 - Tarkka-ampujakivääri</a></li><li><a href="#liite6">Liite 6 - Haulikko</a></li><li><a href="#liite7">Liite 7 - TST-luokan varusteet</a></li></ul><hr><a id="1"></a><h2>1. Johdanto</h2><div id="1.1"><h3>1.1 Yleiset periaatteet</h3><ul><li>Sovellettu reserviläisammunta (SRA) on vapaaehtoisten maanpuolustusjärjestöjen jäsenille tarkoitettua toiminnallista ja turvallista aseenkäsittely- ja ampumataitoa sekä aseiden käyttöä kehittävää ja mittaavaa urheiluammuntaa.</li><li>Ammuntaan voi osallistua Reserviläisurheiluliitto ry:n (RESUL) jäsenliiton tai RESUL:n hyväksymän yhteistyötahon jäsen, joka on suorittanut RESUL:n SRA toimikunnan hyväksymän SRA ampujan kurssin ja siihen liittyvän aseenkäsittelykokeen hyväksyttävästi. Alle 18-vuotiaalla tulee lisäksi olla huoltajan allekirjoittama kirjallinen osallistumislupa.</li><li>Harjoituksiin voi tuomarin valvonnassa ja suostumuksella osallistua teoriakokeen suorittanut henkilö, joka harjoittelee aseenkäsittelykoetta varten.</li><li>Ampujalla tulee olla voimassa oleva Reserviläisurheiluliiton hyväksymä ammunnan harjoittelu- ja kilpailutoiminnan kattava vakuutusturva.</li><li>Näitä sääntöjä noudatetaan lajin kaikissa kilpailuissa ja harjoituksissa.</li><li>Lajin kilpailuissa noudatetaan lisäksi asetarkastus- ja kilpailunjärjestämisohjeita.</li><li>Sääntökohtien tulkintaa varten SRA toimikunta voi ylläpitää teknistä sääntöliitettä sekä antaa erillisiä ohjeita ja määräyksiä.</li></ul></div><a id="1.2"></a><h3>1.2 Kilpailut</h3><p id="1.2.1"><a href="#1.2.1"><span class="sk">1.2.1</span></a> Kilpailu koostuu rasteista, joilla kullakin voidaan käyttää useampaa kuin yhtä asetta ja asetyyppiä. </p><p id="1.2.2"><a href="#1.2.2"><span class="sk">1.2.2</span></a> Kilpailuja voidaan järjestää joko pelkästään yhdelle asetyypille tai pitää useamman asetyypin yhdistelmäkilpailuja. </p><p id="1.2.3"><a href="#1.2.3"><span class="sk">1.2.3</span></a> Kilpailukutsussa on ilmoitettava käytettävät asetyypit, rastien lukumäärä, minimilaukausmäärät asetyypeittäin, maksimiampumaetäisyydet ja mahdolliset erityispainotukset. </p><p id="1.2.4"><a href="#1.2.4"><span class="sk">1.2.4</span></a> Kilpailuissa on kolme eri luokkaa, vakio, avoin ja TST, jotka määräytyvät ampujan aseiden ja varusteiden mukaan. </p><p id="1.2.5"><a href="#1.2.5"><span class="sk">1.2.5</span></a> Kilpailuissa lasketaan tulokset vakio-, avoin ja tst-luokkien lisäksi 50-v, 60-v ja naisten sarjoille luokittain. 50-v tai 60-v sarjassa kilpaillakseen tulee henkilön täyttää tai olla täyttänyt 50 tai 60 vuotta kyseisenä vuonna. Mahdollisen palkitsemisen suorittaa kilpailunjärjestäjä tulosten perusteella ottaen huomioon muut ohjeet ja määräykset palkitsemisesta. Kilpailunjärjestäjä voi laskea myös muita tuloksia ja jakaa muita palkintoja. Näistä tulee ilmoittaa osallistujille kilpailukutsussa. </p><p id="1.2.6"><a href="#1.2.6"><span class="sk">1.2.6</span></a> Kilpailunjärjestäjä voi ennen kilpailun alkua pitää alkupuhuttelun kilpailijoille ja toimihenkilöille. Kansallisissa ja kansainvälisissä mestaruuskilpailuissa pidetään aina alkupuhuttelu. Alkupuhuttelussa käydään läpi kilpailuun liittyviä yleisiä asioita ja tarkennetaan kilpailunjärjestämisohjeessa mainitut asiat ottaen huomioon paikalliset olosuhteet ja ratakohtaiset erityismääräykset, esim. liikkuminen kilpailualueella ja muut toimintaan vaikuttavat seikat. </p><p id="1.2.7"><a href="#1.2.7"><span class="sk">1.2.7</span></a> Kilpailu päättyy, kun kaikki kilpailijat ovat ampuneet suorituksensa, mahdolliset protestit on käsitelty ja lopullisten rastitulosten tarkistusaika on päättynyt. </p><p id="1.2.8"><a href="#1.2.8"><span class="sk">1.2.8</span></a> Kilpailualue on ampumarata tai ampuma-alue, jossa SRA- kilpailu käydään. Jollei järjestäjä ole muuta määrännyt niin kilpailualueeseen kuuluvat ilmoittautumistila, asetarkastusalue, rastit, rastien odotusalueet, aseenkäsittelyalueet ja turvalliset siirtymistiet em. paikkojen välillä. </p><p id="1.2.9"><a href="#1.2.9"><span class="sk">1.2.9</span></a> Teemakilpailussa voidaan kilpailutapahtumien elävöittämiseksi ja monipuolistamiseksi tehtäviin sisällyttää erityisaiheita tai painotuksia. Aiheet eivät kuitenkaan saa olla sillä tavoin rajaavia, että kilpailijat joutuvat omistamansa välineistön suhteen eriarvoiseen asemaan. Kilpailuissa ei esimerkiksi saa vaatia tarkasti tietyn tyyppisiä tai rajattujen valmistajien aseita tai varusteita. Useimmilla ampujilla on käytettävissään yksi kivääri ja pistooli, ilman mahdollisuutta vaihtaa varustusta tai luokkaa olosuhteiden mukaan. </p><a id="1.3"></a><h3>1.3 Rastit</h3><p id="1.3.1"><a href="#1.3.1"><span class="sk">1.3.1</span></a> Yksi rasti sisältää yhden rastikuvauksen mukaisen pisteytettävän suorituksen. Kilpailuihin tulee aina suunnitella kilpailukohtaiset rastit. </p><p id="1.3.2"><a href="#1.3.2"><span class="sk">1.3.2</span></a> Kilpailun voittajat ratkaistaan laskemalla yhteen eri rastien tulokset luvun 6 mukaisesti. </p><p id="1.3.3"><a href="#1.3.3"><span class="sk">1.3.3</span></a> Rasti sisältää aina ampumasuorituksen. Siihen voidaan liittää yksinkertaisia oheistehtäviä kuten kranaatinheittoa. Rastin suorittamiseen voi kuulua myös asennonvaihtoja, liikettä yms. Tehtävät, asennonvaihto ja liike eivät saa kuitenkaan olla hallitseva osa tuloksen muodostumisessa. Tuloksen tulee muodostua pääasiallisesti aseenkäsittelytaidosta ja tilanteenhallintakyvystä kuvattavassa tilanteessa.</p><p id="1.3.4"><a href="#1.3.4"><span class="sk">1.3.4</span></a> Rastien suunnittelussa tulee ammunnan nopeutta ja tarkkuutta painottaa tasapuolisesti eli ammuttavan laukausmäärän tulee olla tarpeeksi suuri käytettävään aikaan nähden.</p><p id="1.3.5"><a href="#1.3.5"><span class="sk">1.3.5</span></a> Rastien tulee olla monipuolisia, todenmukaisia ja käytettäville asetyypeille sopivia sekä sisältää tilanteenmukaista toimintaa. Rastisuunnittelun perusteista on lisätietoa kilpailunjärjestämisohjeessa.</p><p id="1.3.6"><a href="#1.3.6"><span class="sk">1.3.6</span></a> Ammunnan suoritustapa on vapaa. Ampumapaikkaa tai asentoa ei saa määrätä. Kuitenkin rastin toteutuksella voidaan luoda olosuhteet, jotka ohjaavat ampujan tiettyyn ampumapaikkaan tai asentoon. Nämä olosuhteet voivat sisältää esteitä ja muita fyysisiä rajoitteita. Ampujan pitää saada ratkaista esitetty tehtävä vapaavalintaisella tavalla ja pyritään siihen, että tauluja voi ampua periaatteella &quot;aina kun ne ovat näkyvissä&quot;.</p><p id="1.3.7"><a href="#1.3.7"><span class="sk">1.3.7</span></a> Pakollinen lippaanvaihto voidaan määrätä suoritettavaksi rastilla ensimmäisen ja viimeisen laukauksen välisenä aikana. Ampujan on voitava valita missä kohtaa suoritusta lipas vaihdetaan.</p><p id="1.3.8"><a href="#1.3.8"><span class="sk">1.3.8</span></a> Ampujalla saa suoritukseen lähtiessään olla mukanaan tai rastikuvauksessa määrätyssä paikassa haluamansa määrä haluamallaan tavalla lipastettuja lippaita. Suorituksen aikaista lipastamista ei saa vaatia. Rastikuvauksella voidaan kuitenkin asettaa rastin aloitukseen patruunamäärärajoitus.</p><p id="1.3.9"><a href="#1.3.9"><span class="sk">1.3.9</span></a> Pistoolilla ampumaosuus tai osa siitä voidaan määrätä suoritettavaksi käyttäen vain vahvempaa tai heikompaa kättä.</p><p id="1.3.10"><a href="#1.3.10"><span class="sk">1.3.10</span></a> Rastin sisältöä tai ratalaitteita voidaan muuttaa kilpailun aikana vain turvallisuuden sitä vaatiessa. Jos rastia muutetaan kesken kilpailun tavalla, jonka merkitys sen suorituksen kannalta ei ole vähäinen, on kaikkien rastin jo suorittaneiden uusittava suoritus. Mikäli rastia ei pystytä aikataulullisista tai muista syistä suorittamaan uudelleen, on rasti hylättävä kilpailusta. Rastin hylkäämisestä päättää kilpailun johtaja.</p><p id="1.3.11"><a href="#1.3.11"><span class="sk">1.3.11</span></a> Haulikkorastin laukausmäärä ei saa olla yli 15 laukausta ellei kyseessä ole teemakilpailu.</p><p id="1.3.12"><a href="#1.3.12"><span class="sk">1.3.12</span></a> Kilpailijaa ei saa pakottaa ampumaan pistoolilla SRA-taulun kokoiseen tauluun yli 25 m etäisyydeltä tai vastaavan kokoiseen osumaan reagoivaan tauluun yli 50 m etäisyydeltä. Pienempien taulujen tulee olla lähempänä.</p><a id="1.4"></a><h3>1.4 Ratalaitteet</h3><p id="1.4.1"><a href="#1.4.1"><span class="sk">1.4.1</span></a> Kilpailun järjestäjä voi asettaa rastille ampujan liikkumista tai ampumista ohjaavia tai rajoittavia esteitä kuten seiniä, tunneleita, raja- ja rikelinjoja.</p><p id="1.4.2"><a href="#1.4.2"><span class="sk">1.4.2</span></a> Rajalinjaa käytetään ohjaamaan ampuja liikkumaan suorituksen aikana määrätyllä alueella. Niitä ei saa asentaa siten, että ne voidaan sekoittaa käsittely- tai ampumasektoreihin. Ampuja ei saa ylittää rajalinjaa suorituksen aikana. Rajalinjan ylittämisestä seuraa toimintavirherangaistus luvun 6.6.2 mukaisesti.</p><p id="1.4.3"><a href="#1.4.3"><span class="sk">1.4.3</span></a> Rikelinjoja käytettäessä pakotetaan ampuja ampumaan maaleja fyysisen esteen takaa. Ne voivat olla sijoitettu millaiseen kulmaan tahansa esteen takaosan jatkeeksi. Rikelinjan on oltava vähintään yhden metrin pituinen ja jos rastikuvauksessa ei muuta sanota, niiden oletetaan jatkuvan äärettömyyteen. Rikelinjoilla kuvataan suojan käyttöä ammunnan aikana. Rikelinjat tulee kiinnittää vankasti ja varmistaa että ne ovat yhtenäiset jokaiselle kilpailijalle koko kilpailun ajan.</p><p id="1.4.4"><a href="#1.4.4"><span class="sk">1.4.4</span></a> Tunneli voi olla kiinteä putki tai Tiitinen-tunneli, jonka katto koostuu irtonaisista rimoista. Tiitinen-tunneli kuvaa tilannetta, jossa ampuja joutuu etenemään matalana.</p><p id="1.4.5"><a href="#1.4.5"><span class="sk">1.4.5</span></a> Mikäli taulujen näkyvyyttä rajoittavien rakenteiden toteuttaminen ei olosuhteista kuten radasta, aikataulusta, materiaalin puutteesta tms. johtuen ole mahdollista, voidaan käyttää vain rike- ja rajalinjoja, jotka estävät taulujen ampumisen kielletyltä alueelta. Tätä sääntökohtaa voidaan käyttää vain piiritason ja pienemmissä kilpailuissa. Lisätietoa ratarakennevaatimuksista ja suositeltavista rakenteista on kilpailunjärjestämisohjeessa. </p><a id="1.5"></a><h3>1.5 Ajanotto</h3><p id="1.5.1"><a href="#1.5.1"><span class="sk">1.5.1</span></a> Ajanottoon käytetään yleisesti kaupan olevia tai muita luotettavia ja tasapuolisiatähän tarkoitukseensoveltuvia ajanottolaitteita, jotka antavat aloitusmerkin ja rekisteröivät jokaisen sen jälkeen ammutun laukauksen ja siihen kuluneen ajan. Jokaisen yksittäisen laukauksen - paitsi viimeisen - rekisteröintiä ei vaadita, ellei se ole välttämätöntä esim. &quot;rajoitettu laukausmäärä&quot; rastilla.</p><p id="1.5.2"><a href="#1.5.2"><span class="sk">1.5.2</span></a> Viimeisen laukauksen jälkeen tuomarin on varmistuttava siitä, ettei aseen tyhjentämisen ja tyhjälaukauksen aikana syntyvä lukon liike tai muu ääni enää vaikuta aikaan.</p><p id="1.5.3"><a href="#1.5.3"><span class="sk">1.5.3</span></a> Mikäli aseessa olevan äänenvaimentimen takia laukaukset eivät rekisteröidy, päättää tuomari tavan, jolla viimeisen laukauksen jälkeen saadaan ajanottolaitteeseen lopetusmerkki.</p><a id="2"></a><h2>2. Kilpailun toimihenkilöt</h2><a id="2.1"></a><h3>2.1 Tekninen asiantuntija</h3><a></a><p id="2.1.1"><a href="#2.1.1"><span class="sk">2.1.1</span></a> Kansallisissa ja kansainvälisissä mestaruuskilpailuissa on oltava vastaavan liiton hallituksen hyväksymä tekninen asiantuntija, jolla on SRA-kouluttajan tai -ylituomarin pätevyys.</p><a id="2.2"></a><h3>2.2 Kilpailunjohtaja</h3><p id="2.2.1"><a href="#2.2.1"><span class="sk">2.2.1</span></a> Kilpailunjohtajana voi toimia SRA-tuomarin pätevyyden omaava henkilö.</p><p id="2.2.2"><a href="#2.2.2"><span class="sk">2.2.2</span></a> Kilpailunjohtaja on vastuussa koko kilpailusta ja sen hallinnosta, ajoituksista, rastimateriaaleista ja tarvittavasta ruoka-, lääkintä- yms. huollosta sekä turvallisuudesta.</p><p id="2.2.3"><a href="#2.2.3"><span class="sk">2.2.3</span></a> Kilpailujohtajalla on ylin päätäntävalta mainituissa asioissa lukuun ottamatta protestipäätöksiä.</p><p id="2.2.4"><a href="#2.2.4"><span class="sk">2.2.4</span></a> Kilpailunjohtaja toimii juryn puheenjohtajana ilman äänivaltaa.</p><a></a><p id="2.2.4"><a href="#2.2.5"><span class="sk">2.2.5</span></a> Kilpailunjohtaja voi piiritason ja pienemmissä kilpailuissa toimia myös muissa tehtävissä kuten ratamestarina tai tuomarina.</p><a id="2.3"></a><h3>2.3 Ratamestari</h3><p id="2.3.1"><a href="#2.3.1"><span class="sk">2.3.1</span></a> Ratamestarina voi toimia SRA-tuomarin pätevyyden omaava henkilö. Ratamestarin nimittää kilpailunjohtaja.</p><p id="2.3.2"><a href="#2.3.2"><span class="sk">2.3.2</span></a> Ratamestarin tehtävät:</p><ol type="a"><li>On vastuussa rastien turvallisuudesta ja turvallisten tehtävien suunnittelusta.</li><li>Valvoo, että kaikkia ohjeita ja sääntöjä noudatetaan ja on vastuussa ratahenkilöstön koulutuksesta ja ohjauksesta. </li><li>Kaikki protestiasiat kulkevat ratamestarin kautta ja kaikki turvallisuusrikkomukset on saatettava hänen tietoonsa. </li><li>Ratamestari johtaa rastihenkilöstöä kilpailun aikana.</li><li>On vastuussa siitä, että rasteilla noudatetaan kaikkia toiminta- ja pistelaskusääntöjä tasapuolisesti kaikkien ampujien osalta. </li></ol><p id="2.3.3"><a href="#2.3.3"><span class="sk">2.3.3</span></a> Ratamestari voi piiritason ja pienemmissä kilpailuissa toimia myös muissa tehtävissä kuten tuomarina.</p><a id="2.4"></a><h3>2.4 Tuloslaskentavastaava</h3><p id="2.4.1"><a href="#2.4.1"><span class="sk">2.4.1</span></a> On kilpailun toimihenkilö, joka vastaa kaikkien kilpailun tulosten keräämisestä, lajittelusta, säilyttämisestä ja väli- ja lopullisten tulosten ja tilastojen laskemisesta, tarkistamisesta ja julkaisusta.</p><p id="2.4.2"><a href="#2.4.2"><span class="sk">2.4.2</span></a> Varmistaa, että epätäydellisesti tai epätarkasti täytetty tulos välittömästi tarkistutetaan ratamestarilla. Tuloslaskentavastaava toimii ratamestarin välittömässä alaisuudessa.</p><p id="2.4.3"><a href="#2.4.3"><span class="sk">2.4.3</span></a> Tuloslaskentavastaavana kansallisissa ja kansainvälisissä mestaruuskilpailuissa voi toimia SRA-tuomarin pätevyyden omaava henkilö.</p><a id="2.5"></a><h3>2.5 Tuomari</h3><p id="2.5.1"><a href="#2.5.1"><span class="sk">2.5.1</span></a> SRA-tuomarina voi toimia SRA- tuomarikoulutuksen hyväksytysti suorittanut ja SRA-rekisteriin merkitty henkilö.</p><div id="2.5.2"><p><a href="#2.5.2"><span class="sk">2.5.2</span></a> Tuomarin tehtävät:</p><ol type="a"><li>Vastaa rastin turvallisuudesta.</li><li>Huolehtii rastikuvauksen antamisesta.</li><li>Valvoo ampujan suoritusta rastilla ja varmistaa rastikuvauksen mukaisen toiminnan.</li><li>Antaa ratakomennot.</li><li>Ottaa ajan, tulkitsee taulut ja huolehtii tulosten kirjauksesta.Tuomarilla voi olla apunaan kirjuri.</li><li>Huolehtii rastin rakenteiden ja taulujen kunnosta.</li><li>Huolehtii rastin suoritus-, odotus- ja käsittelyalueen yleisestä järjestyksestä ja rakentamisesta.</li></ol></div><p id="2.5.3"><a href="#2.5.3"><span class="sk">2.5.3</span></a> Tuomarilla on käskyvalta kaikkiin rastialueella oleviin henkilöihin.</p><p id="2.5.4"><a href="#2.5.4"><span class="sk">2.5.4</span></a> Tuomariksi katsotaan rastin toimihenkilöihin kuuluva, jolla on voimassa oleva SRA-tuomarin pätevyys. Mikäli rastilla on useampi tuomari, niin yksi tuomari nimetään päävastuulliseksi, rastivastaavaksi.</p><a id="2.6"></a><h3>2.6 Kirjuri</h3><p id="2.6.1"><a href="#2.6.1"><span class="sk">2.6.1</span></a> Kirjurin tulee hallita tuloslaskentajärjestelmän kirjausmenettely. Kirjurin tehtävä voi olla yhdistetty muihin toimihenkilötehtäviin, paitsi kansallisissa ja kansainvälissä mestaruuskilpailuissa.</p><div id="2.6.2"><p><a href="#2.6.2"><span class="sk">2.6.2</span></a> Kirjurin tehtävät:</p><ol type="a"><li>Tarvittaessa asettaa kilpailijat ampumajärjestykseen.</li><li>Huolehtii rastilla tulosten kirjaamisesta.</li><li>Kirjaa tulokset selkeästi sekä ottaa tuomarilta ja ampujalta tuloslaskentajärjestelmän edellyttämät kuittaukset.</li><li>Kuuluttaa seuraavana ampumavuorossa olevan ja sitä seuraavien ampujien valmistautumisen.</li></ol></div><a id="2.7"></a><h3>2.7 Muu organisaatio</h3><p id="2.7.1"><a href="#2.7.1"><span class="sk">2.7.1</span></a> SRA-kilpailunjärjestämisohjeessa on lisätietoa mahdollisesta muusta kilpailutapahtumiin liittyvästä organisaatiosta suuria kilpailutapahtumia (esimerkiksi mestaruuskilpailuja) varten. Ohjeessa voidaan myös tarkentaa toimihenkilöiden tehtäväkuvauksia.</p><a id="3"></a><h2>3. Turvamääräykset</h2><div id="3.1"><h3><a href="#3.1"><span class="sk">3.1</span></a> Turvallisen aseenkäsittelyn perusperiaatteet</h3><p>Noudatettavat turvallisen aseenkäsittelyn perusperiaatteet ovat:</p><ul><li>Käsittele kaikkia ampuma-aseita aina niin kuin ne olisivat ladattuja.</li><li>Pidä aseen piippu aina suunnattuna turvalliseen suuntaan.</li><li>Laita sormi liipaisimelle vasta kun olet tähdännyt ja tehnyt ampumapäätöksen.</li><li>Tunnista maali sekä mitä on sen edessä ja takana.</li></ul></div><a id="3.2"></a><h3>3.2 Yleinen turvallisuus</h3><p id="3.2.1"><a href="#3.2.1"><span class="sk">3.2.1</span></a> Kilpailun johtajan ja ratamestarin tulee yhdessä varmistaa, että rastit on suunniteltu ja rakennettu, sekä rastikuvaukset laadittu siten, että turvallisuus ei vaarannu, eikä ampujilta vaadita sääntöjen vastaista toimintaa.</p><p id="3.2.2"><a href="#3.2.2"><span class="sk">3.2.2</span></a> Kilpailussa tulee selkeästi rajata turvalliset alueet ampujille, katselijoille ja toimihenkilöille.</p><p id="3.2.3"><a href="#3.2.3"><span class="sk">3.2.3</span></a> Tuomarin päätöksellä ampuja hylätään kilpailusta selkeän sääntöjen vastaisen turvallisuusrikkeen takia. Hylkäyksen antaneen tuomarin on välittömästi tiedotettava asiasta ratamestaria, joka varmentaa hylkäysperusteen sääntöjen mukaisuuden.</p><p id="3.2.4"><a href="#3.2.4"><span class="sk">3.2.4</span></a> Henkilö, joka syyllistyy epäurheilijamaiseen käytökseen tai vaarantaa turvallisuuden, voidaan ratamestarin tai kilpailunjohtajan päätöksellä poistaa kilpailualueelta ja hylätä kilpailusta.</p><p id="3.2.5"><a href="#3.2.5"><span class="sk">3.2.5</span></a> Ampujien ja toimihenkilöiden sekä tarvittaessa myös katsojien tulee aina ammunnan aikana suojautua silmä- ja kuulosuojaimilla. Tuomari ei saa antaa rastin aloituskomentoa ennen kuin suojaimet ovat käytössä. Tuomarin havaitessa kilpailijan silmä- tai kuulosuojainten olevan poissa paikaltaan rastisuorituksen aikana tulee hänen keskeyttää suoritus ja kilpailija joutuu uusimaan rastisuorituksen. Mikäli kilpailija vahingossa menettää silmä- tai kuulosuojaimet tulee hänen joko korjata suojaus tai keskeyttää rastisuorituksensa ja ase turvalliseen suuntaan osoittaen huomauttaa tästä tuomarille, minkä jälkeen kilpailija joutuu uusimaan rastisuorituksen. Mikäli kilpailija tarkoituksellisesti pyrkii saamaan uusinnan tai kilpailullista etua poistamalla silmä- tai kuulosuojaimet rastisuorituksen aikana, tulkitaan tämä epäurheilijamaiseksi käytökseksi mikä aiheuttaa kilpailusta hylkäyksen.</p><a id="3.3"></a><h3>3.3 Aseenkäsittely</h3><p>Seuraavien määräysten rikkominen johtaa välittömään kilpailusta hylkäämiseen.</p><b>Kilpailualueella yleensä</b><p id="3.3.1"><a href="#3.3.1"><span class="sk">3.3.1</span></a> Rastin suoritusalueen ja käsittelyalueen ulkopuolella aseen on joka hetki oltava ilman lipasta tai makasiini tyhjänä sekä lataamattomana ja virittämättömänä. Turvalipun käyttäminen aseessa on sallittu.</p><div id="3.3.2"><a href="#3.3.2"><span class="sk">3.3.2</span></a><span>Ase tulkitaan ladatuksi, mikäli:</span><ul><li>aseen patruunapesässä on patruuna tai</li><li>lukko on takana ja patruunoita sisältävä lipas on kiinni aseessa.</li></ul></div><p id="3.3.3"><a href="#3.3.3"><span class="sk">3.3.3</span></a> Rastin suoritusalueen ulkopuolella pistoolia kuljetetaan kotelossa tai suojuksessa. Kivääriä, haulikkoa tai tarkka-ampujakivääriä kannettaessa tulee piipun osoittaa ylös- tai alaspäin, ellei ase ole suojuksessa. Sormen on oltava poissa liipaisinkaaren sisältä.</p><p id="3.3.4"><a href="#3.3.4"><span class="sk">3.3.4</span></a> Mikäli ase putoaa maahan rastin suoritusalueen ulkopuolella, vain tuomari saa nostaa aseen ja siirtyä sen kanssa rastin suoritusalueelle (ei käsittelyalueelle), missä hän varmistaa että ase täyttää luvun 3.3.1 vaatimukset. Ampujaa ei hylätä, mikäli muita turvallisuussääntöjen rikkomuksia ei sisälly tapaukseen.</p><p id="3.3.5"><a href="#3.3.5"><span class="sk">3.3.5</span></a> Rastin suoritusalueen ulkopuolella asetta saa käsitellä ainoastaan erikseen merkityllä ja rajatulla käsittelyalueella, jossa on oltava merkitty käsittelysektori, jonka sisäpuolelle aseen piipun tulee olla suunnattu asetta käsiteltäessä. Aseenkäsittelyksi katsotaan paljaasta aseesta ampumaotteen ottamista kahvasta tai tukista, aseella tähtäämistä, aseen hallintalaitteiden käsittelyä sekä aseen purkamista tai kokoamista.</p><div id="3.3.6"><p><a href="#3.3.6"><span class="sk">3.3.6</span></a> Käsittelyalueet tulee sijoittaa sopiviin paikkoihin rastien läheisyyteen ja merkitä selkeästi havaittavin opastein.</p><p>Käsittelyalueen rajat on oltava selvästi merkitty. Ampujat voivat käyttää käsittelyalueita seuraaviin tarkoituksiin:</p><ul><li>Pakata laukkuun, purkaa laukusta ja koteloida lataamattomat aseet.</li><li>Harjoitella vetoa ja tyhjälaukauksia lataamattomalla aseella.</li><li>Harjoitella lippaanvaihtoja tyhjällä lippaalla.</li><li>Tarkastaa, puhdistaa, korjata ja huoltaa asetta, osaa tai muuta tarviketta.</li></ul><p>Käsiteltävän aseen piipun on osoitettava joka hetki aseenkäsittelyalueelle merkittyyn käsittelysektoriin.</p><p>Latausharjoituspatruunoita, hylsyjä, patruunoita sisältäviä lippaita tai rasioita, ladattuja pikalatauslaitteita ja patruunoita ei saa käsitellä käsittelyalueella missään tilanteessa. Aseeseen ei saa olla kiinnitetty patruunoita.</p></div><p id="3.3.7"><a href="#3.3.7"><span class="sk">3.3.7</span></a> Asetarkastusalue on kilpailunjärjestäjän asetarkastuksia varten osoittama paikka. Asetarkastusalueella aseita eivät saa käsitellä ilman lupaa muut kuin asetarkastusta suorittavat toimihenkilöt. Muutoin alueella noudatetaan käsittelyalueen määräyksiä.</p><b>Rastin suoritusalueella</b><p id="3.3.8"><a href="#3.3.8"><span class="sk">3.3.8</span></a> Asetta saa käsitellä ja aseen saa ladata ainoastaan tuomarin käskystä. </p><p id="3.3.8.1"><a href="#3.3.8.1"><span class="sk">3.3.8.1</span></a> Hylkäystä ei kuitenkaan anneta tilanteessa, missä rastin aloituksessa ase on “Lipas kiinnitä&quot; -komennon mukainen ja ampuja rutiininomaisesti saattaa aseensa “Lataa ja varmista&quot; tilaan. Tällöin tuomari komentaa aseen tyhjennyksen ja tyhjälaukauksen, kertaa oikean aloitusasennon ja komentaa ampujan uudestaan aloitusasentoon. </p><p id="3.3.8.2"><a href="#3.3.8.2"><span class="sk">3.3.8.2</span></a> Hylkäystä ei anneta mikäli ampuja on aloittanut rastin suorituksen virheellisestä aloitusmerkistä. </p><p id="3.3.9"><a href="#3.3.9"><span class="sk">3.3.9</span></a> Ladatun pistoolin tai revolverin koteloimista rastin suorituksen aikana (aloitusmerkin jälkeen) ei saa pakottaa tai vaatia rastikuvauksella. Mikäli ampuja haluaa kesken rastisuorituksen koteloida pistoolin tai revolverin, tulee se saattaa ennen kotelointia turvalliseen tilaan. Aseen, jossa ei ole ampujan käytettävissä olevaa varmistinta saa koteloida rastin suorituksen aikana vain viritettämättömänä tai patruunapesä tyhjänä. </p><p id="3.3.10"><a href="#3.3.10"><span class="sk">3.3.10</span></a> Aseen ollessa esillä tulee piipun aina osoittaa käsittelysektorin sisäpuolelle. Pistoolin ja revolverin on osoitettava koteloitaessa, kotelosta vedettäessä sekä rastin suoritukseen valmistautumisen, rastin suorituksen ja rastin suorituksen päättämisen aikana ladattuna kotelossa ollessaan käsittelysektoriin tai enintään 2 metriä ampujasta taaksepäin. </p><p id="3.3.11"><a href="#3.3.11"><span class="sk">3.3.11</span></a> Ladatun aseen piippu ei saa osoittaa ampujaa. Tämä kohta ei ole voimassa aseen ollessa kotelossa, asetta kotelosta vedettäessä tai koteloitaessa niin kauan kun aseen piipun pää on kotelon sisäpuolella ja osoittaminen on lievää. </p><p id="3.3.12"><a href="#3.3.12"><span class="sk">3.3.12</span></a> Asetta kotelosta vedettäessä, koteloitaessa, ladattaessa, häiriötä poistettaessa, lippaanvaihdon aikana tai patruunaa poistettaessa sormen on oltava poissa liipaisinkaaren sisältä. Mikäli aseen tyhjentäminen vaatii sormea liipaisinkaaren sisäpuolelle, on ampujan ilmoitettava tästä tuomarille etukäteen.</p><p id="3.3.13"><a href="#3.3.13"><span class="sk">3.3.13</span></a> Mikäli sormi on liipaisinkaaren sisällä rastin suoritusalueella ennen aloitusmerkkiä ilman tuomarin lupaa.</p><p id="3.3.14"><a href="#3.3.14"><span class="sk">3.3.14</span></a> Ampujan liikkuessa enemmän kuin yhden askeleen tai vaihtaessa ampuma-asentoa, sormi saa olla liipasinkaaren sisällä vain, mikäli samanaikaisesti ammutaan tai tähdätään näkyvissä olevia tauluja. Tähtäämistä on aseen piipun suuntaaminen hallitusti ammuttavissa olevaa taulua kohden.</p><p id="3.3.15"><a href="#3.3.15"><span class="sk">3.3.15</span></a> Rastin suorittamisen aikana ampuja saa menettää kosketuksen aseeseen vain rastikuvauksessa määritetyllä tavalla, tai tarvittaessa laskemalla varmistettu tai lataamaton ase hallitusti maahan tai muulle tukevalle alustalle. Tällöin ampuja ei saa poistua yli 1 m päähän aseesta. Mikäli ampuja menettää kosketuksen aseeseen muutoin kuin em. tapauksissa, tuomari keskeyttää suorituksen, nostaa ja tyhjentää aseen. Mikäli ase on määritetty rastikuvauksessa käsittelyaseeksi, niin siihen kosketuksen menettäminen ei ole keskeytys- tai hylkäysperuste.</p><p id="3.3.16"><a href="#3.3.16"><span class="sk">3.3.16</span></a> Rastikuvauksessa voidaan määrätä kiväärin tai haulikon varmistaminen liikkeen aikana, mikäli turvallisuus sitä edellyttää.</p><p id="3.3.17"><a href="#3.3.17"><span class="sk">3.3.17</span></a> Sarjatulen käyttö on kielletty, ellei rastikuvauksessa muuta määrätä.</p><div id="3.3.18"><p><a href="#3.3.18"><span class="sk">3.3.18</span></a> Mikäli ampuja ampuu vahingonlaukauksen, tuomari keskeyttää suorituksen välittömästi ja ampuja hylätään kilpailusta.</p><p>Vahingonlaukaukseksi katsotaan</p><ol type="a"><li>laukaus, joka ammutaan ennen aloitusmerkkiä tai ampumisen lopettavan &quot;liikkuvat taakse&quot; -komennon jälkeen,</li><li>laukaus, joka ammutaan ohi ampumasektorin,</li><li>laukaus, joka osuu maahan lähempänä kuin 3 metriä ampujasta, ellei tehtävä sitä edellytä, sekä</li><li>mikä tahansa laukaus, jota selvästi ei ollut tarkoitus ampua.</li></ol></div><p id="3.3.19"><a href="#3.3.19"><span class="sk">3.3.19</span></a> Aserikosta johtuva vahingonlaukaus tai pursketuli ampumasektoriin ei ole hylkäyksen peruste, jos voidaan todentaa, että vika on aseessa. Tällöin rastin tulokseksi tulee nolla ja ase tulee korjata tai poistaa kilpailusta, mikäli korjaus ei ole mahdollinen. Tapahtumasta tulee ilmoittaa ratamestarille. Vian toistuminen kilpailussa johtaa hylkäykseen.</p><p id="3.3.20"><a href="#3.3.20"><span class="sk">3.3.20</span></a> Rastilla kiellettyjen ampumatarvikkeiden ampuminen on hylkäykseen johtava turvallisuusrike.</p><a id="3.4"></a><h3>3.4 Sektorit</h3><p id="3.4.1"><a href="#3.4.1"><span class="sk">3.4.1</span></a> Rastilla tulee olla selvästi määritellyt käsittely- ja ampumasektorit, jotta ampujat voivat suorittaa rastin turvallisesti ja tuomari valvoa suoritusta. Sektorit eivät koske rastikuvauksessa käsittelyaseeksi määritettyä asetta.</p><p id="3.4.2"><a href="#3.4.2"><span class="sk">3.4.2</span></a> Käsittelysektori tarkoittaa suuntaa, johon aseen piipun tulee aina olla suunnattuna aseen ollessa esillä rastin suorituksen aikana.</p><p id="3.4.3"><a href="#3.4.3"><span class="sk">3.4.3</span></a> Pystysuunnassa käsittelysektori on 180 astetta, huomioiden muut rajoitukset.</p><p id="3.4.4"><a href="#3.4.4"><span class="sk">3.4.4</span></a> Sivusuunnassa käsittelysektori on 180 astetta, ellei rastikuvauksessa ole muuta mainittu.</p><p id="3.4.5"><a href="#3.4.5"><span class="sk">3.4.5</span></a> Ampumasektori tarkoittaa suuntaa, johon laukauksen voi turvallisesti ampua. Ampumasektori on kapeampi tai enintään saman suuruinen kuin käsittelysektori.</p><div id="3.4.6"><a href="#3.4.6"><span class="sk">3.4.6</span></a> <span>Ampumasektorin yläraja on tyypillisesti takavallin tai vastaavan yläreuna, elleivät olosuhteet edellytä muuta.</span><p>Sivurajat ovat rastikohtaisesti määrätyt ja merkityt.</p></div><a id="4"></a><h2>4. Toiminta rastilla</h2><a id="4.1"></a><h3>4.1 Yleistä</h3><p id="4.1.1"><a href="#4.1.1"><span class="sk">4.1.1</span></a> Ampuja on velvollinen noudattamaan kaikkia toimihenkilöiden antamia käskyjä, edellyttäen että se voi tapahtua turvallisesti.</p><p id="4.1.2"><a href="#4.1.2"><span class="sk">4.1.2</span></a> Suomalaisissa kansallisissa kilpailuissa komentokieli on suomi ja kansainvälisissä kilpailuissa englanti. Päätöksen komentokielestä tekee kilpailunjohtaja. Tuomari voi ampujan pyynnöstä käyttää ampujan parhaiten ymmärtämää kieltä. Komennot on annettava kuuluvalla ja selkeällä äänellä.</p><div id="4.1.3"><p><a href="#4.1.3"><span class="sk">4.1.3</span></a> Ennen rastin suorittamista ampujille annetaan suullinen rastikuvaus. Rastikuvauksen tulee olla selkeä ja sisältää kaikki tarpeellinen tieto rastin suorittamiseen turvallisesti. Rastikuvauksessa tulee aina kertoa: </p><ol type="a"><li>käytettävät ampuma-aseet</li><li>ammuttavien ja ei-ammuttavien taulujen lukumäärä, ulkonäkö, osuma-alue ja pisteytys</li><li>ampumaetäisyydet lähimpään ja kauimpaan tauluun</li><li>minimilaukausmäärä</li><li>maksimipisteet</li><li>rastin ampuma- ja käsittelysektorit</li><li>suoritus-, käsittely-, odotus- ja katsomoalueiden sijainnit</li><li>rastin suoritustapa</li><li>rastiin tutustumisaika</li><p>Lisäksi rastikuvauksessa tulee kertoa, mikäli tarpeen:</p><li>mahdolliset rajoitukset ampumatarvikkeissa</li><li>tehtävien pisteytys</li><li>rastin pistelaskutapa, jos muu kuin rajoittamaton</li><li>rastin ajanottotapa, jos muu kuin äänimerkistä viimeiseen laukaukseen</li><li>mahdollinen rastin maksimisuoritusaika</li><li>aloitusasento, jos muu kuin normaalisti seisten</li><li>aseiden ja varusteiden tila aloituksessa</li><li>mahdolliset erityiset rajoitukset</li><li>mahdolliset erityiset rangaistukset</li><li>mahdolliset erityiset huomiot rastin turvalliseen suorittamiseen</li><p>Kirjallisessa rastikuvauksessa, joka tulee olla nähtävillä, voi olla lisäksi kerrottu:</p><li>ratkaistava tilanne</li></ol></div><p id="4.1.4"><a href="#4.1.4"><span class="sk">4.1.4</span></a> Tuomarin tulee aina varmistaa, että ampuja on ymmärtänyt rastikuvauksen vaatimukset. Mikäli tuomari huomaa, että ampuja ei ole oikeassa aloitusasennossa on tuomarin korjattava asia ennen aloitusmerkkiä. Jos ampuja ennakoi liikkumalla ennen aloitusmerkkiä, on aloitus keskeytettävä heti ja uusittava.</p><p id="4.1.5"><a href="#4.1.5"><span class="sk">4.1.5</span></a> Ampuja vastaa aseensa oikeasta patruunamäärästä, kun se on rajoitettu rastin aloituksessa. Jokaisesta ylimääräisestä aseeseen ladatusta patruunasta tuomitaan 1 toimintavirhe.</p><p id="4.1.6"><a href="#4.1.6"><span class="sk">4.1.6</span></a> Jos TST-luokan ampujalla ei ole rastin aloituksessa mukana tarvittavaa määrää varusteita, hän voi joko korjata asian tai hänet siirretään avoimeen luokkaan.</p><p id="4.1.7"><a href="#4.1.7"><span class="sk">4.1.7</span></a> Tähtäinkuvan otto “lipas kiinnitä&quot; tai &quot;lataa ja varmista&quot; komennon jälkeen tai tuomarin luvalla on sallittu yhteen tauluun.</p><p id="4.1.8"><a href="#4.1.8"><span class="sk">4.1.8</span></a> Tuomarin on liikuttava siten, että hän ei häiritse ampujan toimintaa. Tuomarin on pystyttävä valvomaan ampujaa kaikissa tilanteissa.</p><p id="4.1.9"><a href="#4.1.9"><span class="sk">4.1.9</span></a> Mikäli ampuja ei ole valmiina suorituksen aloitukseen vuorollaan, voi tuomari muuttaa ampujien suoritusjärjestyksen.</p><p id="4.1.10"><a href="#4.1.10"><span class="sk">4.1.10</span></a> Ampuja voi erityisten syiden vaatiessa ampua rastilla kilpailusuorituksensa lisäksi tuomarin luvalla aseen toiminnan tarkistamiseksi, aseen kohdistamiseksi tai häiriön poistamiseksi. Näitä laukauksia ei kuitenkaan saa ampua rastilla ammuttaviin tauluihin vaan erilliseen tauluun tai osoitettuun paikkaan.</p><a id="4.2"></a><h3>4.2 Ratakomennot ja suorituksen aikainen toiminta</h3><div id="4.2.1"><p><a href="#4.2.1"><span class="sk">4.2.1</span></a> Seuraavat komennot ovat peruskomentoja, joita käytetään esitetyssä järjestyksessä. Kansainvälisissä kilpailuissa käytettävät englanninkieliset komennot ovat suluissa suomenkielisen komennon jälkeen.</p><p class="range-command">AMMUTAAN (RANGE IS CLOSED)</p><p>Komento annetaan rastin suoritusalueen tyhjentämiseksi. Kaikkien rastin suoritukseen osallistumattomien henkilöiden tulee poistua odotusalueelle, ellei tuomari ole antanut lupaa muuhun. Tuomari varmistaa, että ampuminen rastilla voi turvallisesti alkaa. Silmä- ja kuulosuojaimet tulee asettaa paikoilleen.</p><p class="range-command">SEURAAVA AMPUJA (NEXT SHOOTER)</p><p>Ampumavuorossa oleva ampuja saapuu rastin aloituspaikalle mukanaan kaikki rastin suorittamiseen tarvittavat aseet ja varusteet ja jää odottamaan tuomarin komentoja.</p><p class="range-command">ONKO KYSYTTÄVÄÄ? (ANY QUESTIONS?)</p><p>Rastisuoritukseen valmistautuminen alkaa. Tuomari varmistaa, että ampuja on ymmärtänyt rastikuvauksen oikein. Ampuja voi vielä tarkentaa tuomarilta rastin suorittamiseen liittyvää asiaa.</p><p class="range-command">LIPAS KIINNITÄ (INSERT MAGAZINE or LOAD MAGAZINE)</p><p>Kiinnitetään lipas aseeseen. Komento annetaan vain, jos rastin suoritus alkaa aseen ollessa patruunapesä tyhjänä ja lipas kiinnitettynä. Tarkoittaa myös makasiinin täyttöä. Aseen lukko ei saa olla taka-asennossa.</p><p class="range-command">LATAA JA VARMISTA (LOAD AND MAKE READY)</p><p>Ladataan ase. Tehdään haluttaessa latausliike ja varmistetaan ase, jos mahdollista tai päästetään se vireestä, mikäli aseessa on vireestäpäästölaite. Mikäli vireestäpäästäminen edellyttää liipaisimen painamista, tulee siitä ilmoittaa tuomarille etukäteen. Mikäli rastilla käytetään useampaa kuin yhtä asetta, joista yksi on pistooli ja aloitus tapahtuu muulla kuin pistoolilla, tulee pistoolin patruunapesän olla aloituksessa tyhjä.</p><p class="range-command">ALOITUSASENTOON (STARTING POSITION)</p><p>Mikäli muuta ei ole määrätty, ovat aloitusasennot seuraavat:</p><ul><li>Pistooli: Luonnollinen seisoma-asento rintamasuunta kohti tauluja, kädet suorina sivuilla, pistooli kotelossa, kotelon lukitus asetettuna.</li><li>Kivääri, haulikko tai tarkka-ampujakivääri: Luonnollinen seisoma-asento rintamasuunta kohti tauluja aseen perä olkapäätä vasten, piippu alaviistoon n. 45° käsittelysektoriin osoittaen. Asekäsi kahvalla ja tukikäsi etutukilla tai jos aseessa ei sellaista ole, lipassolan etupuolelta kiinni. Lippaita ja muita varusteita kun käsineitä ei saa pitää käsissä.</li><li>Jalka ei ole rikelinjan päällä.</li></ul><p class="range-command">VARMISTIN POIS (SAFETY OFF)</p><p>Tätä lisäkomentoa käytetään vain, mikäli rastikuvauksen mukaisesti aloitetaan suoritus varmistamattomalla aseella. Ampuja on asettunut rastikuvauksen edellyttämään aloitusasentoon ennen käskyn antamista. </p><p class="range-command">ONKO AMPUJA VALMIS? (ARE YOU READY?)</p><p>Kysytään, kun edellä mainittujen komentojen aiheuttama liike on lakannut. Ampuja ilmaisee valmiutensa tuomarille sanomalla: &quot;Valmis&quot; (“Ready&quot;).</p><p class="range-command">HUOMIO (STANDBY)</p><p>Suorituksen aloitusmerkki annetaan 2-5 s sisällä tästä komennosta.</p><p class="range-command">TULTA (FIRE)</p><p>Ampuja voi aloittaa rastisuorituksen. Komento voi olla myös muu ennalta kerrottu merkki, kuten ääni- tai valomerkki. Kun ampuja on lopettanut rastin suorittamisen, tai ennalta kerrottu lopetusmerkki on tullut, hän jää paikoilleen odottamaan tuomarin seuraavia komentoja.</p><p class="range-command">OLETKO LOPETTANUT? (ARE YOU FINISHED?)</p><p>Kysytään, kun on oletettavissa, että ampuja on lopettanut rastin suorittamisen. Mikäli tehtävään ei kuulu lopetusmerkkiä ja ampuja ei ole vielä lopettanut suoritustaan, saa hän jatkaa ampumalla tarvitsemansa laukaukset. Ajanotto loppuu viimeiseen laukaukseen. Ampuja ilmaisee lopettaneensa suorituksen vastaamalla &quot;valmis&quot;, &quot;kyllä&quot; tai muuten selkeästi ilmaisemalla lopettaneensa.</p><p class="range-command">LIPAS IRTI, LIIKKUVAT TAAKSE / PATRUUNAT POIS, LIIKKUVAT TAAKSE (UNLOAD AND SHOW CLEAR)</p><p>Rastisuorituksen päättäminen alkaa. Ampuja poistaa aseesta lippaan. Haulikolla, revolverilla tms. komento kuuluu &quot;Patruunat pois&quot;, jolloin makasiini tms. tyhjennetään ja mahdollinen patruuna poistetaan pesästä. Tuomari tarkistaa patruunapesän. Komennon jälkeen sattunut laukaus on vahingonlaukaus, josta seuraa sääntöjen mukaiset toimenpiteet. Ampuja vastaa aina siitä, että ase on tyhjä.</p><p class="range-command">TYHJÄ LAUKAUS (HAMMER DOWN)</p><p>Ammutaan tähdätty tyhjä laukaus kohti tauluja. Lipasvarmistimellisella aseella lasketaan luisti eteen, laitetaan aseeseen tyhjä lipas, ammutaan tyhjä laukaus kohti tauluja ja poistetaan lipas. </p><p class="range-command">ASE KOTELOON tai ASE KANTOASENTOON (HOLSTER or MUZZLE UP)</p><p>Rastisuorituksen päättäminen loppuu tämän komennon mukaisiin toimenpiteisiin. &quot;Ase koteloon&quot; komennolla pistooli tai revolveri koteloidaan turvallisesti, jonka jälkeen tuomari antaa luvan poistua suoritusalueelta. &quot;Ase kantoasentoon&quot; komennolla kivääri tai haulikko siirretään asentoon, jossa se on turvallisesti kannettavissa piippu joko ylös- tai alaspäin osoittaen. Ase voidaan myös laittaa suojukseen, jolloin sitä voi kantaa vaakatasossa.</p><p class="range-command">TAULUILLE (RANGE IS CLEAR)</p><p>Ampuja lähtee tuomarin ja kirjurin kanssa tarkastamaan taulut. Mahdolliset paikkaajat tulevat tehtäviinsä. Seuraavana vuorossa oleva ampuja voi tulla valmistautumaan. Muut henkilöt pysyttelevät odotusalueella.</p><p class="range-command">SEIS (STOP)</p><p>Ehdoton käsky lopettaa ampuminen. Ampuja pysähtyy paikoilleen ase suunnattuna käsittelysektoriin, sormi pois liipaisinkaaren sisältä ja jää odottamaan tuomarin komentoja. Käskyn voi huutaa jokainen, joka huomaa välittömän vaaratilanteen. Käskyn noudattamatta jättäminen aiheuttaa välittömän kilpailusta hylkäämisen.</p><p class="range-command">VARO (WATCH OUT)</p><p>Varoitus jolla varoitetaan vaarallisesta toiminnasta. Varoituksella voidaan varoittaa ampujaa esim. seuraavissa vaaratilanteissa:</p><ul><li>Ampuja aikoo ampua metallimaaleja liian läheltä.</li><li>Ampujan liike suuntautuu niin että käsittelysektori on ylittymässä.</li><li>Ampuja ampuu rastin rakenteisiin aiheuttaen esim. kimmoke- tai sirpalevaaraa.</li></ul><p>Mikäli ampuja reagoi varoitukseen eikä tee turvallisuusrikettä rastin suoritus voi jatkua. Mikäli ampuja ei reagoi ja jatkaa vaarallista toimintaa keskeytetään suoritus SEIS -käskyllä.</p></div><p id="4.2.2"><a href="#4.2.2"><span class="sk">4.2.2</span></a> Mikäli samalla rastilla käytetään useampaa asetta, tulee komennot toistaa erikseen jokaiselle aseelle ilmoittaen ensiksi asetyypin. Esim. &quot;pistooli: lataa ja varmista...&quot; jne.</p><p id="4.2.3"><a href="#4.2.3"><span class="sk">4.2.3</span></a> Tarvittaessa voidaan käyttää rastikuvauksen edellyttämiä lisäkomentoja kuten &quot;ajoneuvoon nouse&quot; yms. Mikäli Lisäkomentoja käytetään, tulee niiden merkitys selvittää ampujille etukäteen. On suositeltavaa kerrata lisäkomennot vielä juuri ennen ammunnan aloitusta ja siten varmistua niiden ymmärtämisestä.</p><a id="5"></a><h2>5. Ase- ja varustemääräykset</h2><a id="5.1"></a><h3>5.1 Yleistä</h3><p id="5.1.1"><a href="#5.1.1"><span class="sk">5.1.1</span></a> Ampuja osallistuu kilpailussa ilmoittamaansa luokkaan. Hänen käyttämiensä aseiden ja varusteiden tulee täyttää luokan vaatimukset. Vähintään kansallisen tason kilpailuissa järjestetään ennen kilpailun alkua asetarkastus, jossa tarkistetaan aseiden turvallisuus ja luokka asetarkastusohjeen mukaisesti.</p><p id="5.1.2"><a href="#5.1.2"><span class="sk">5.1.2</span></a> Kaikkien kilpailussa käytettävien aseiden ja varusteiden tulee olla turvallisia. Tämä on ampujan vastuulla.</p><p id="5.1.3"><a href="#5.1.3"><span class="sk">5.1.3</span></a> Aseisiin ei saa tehdä turvallisuutta heikentäviä muutoksia, kuten poistaa toiminnasta aseen turvallisuuteen vaikuttavia ominaisuuksia. Kahva- ja lipasvarmistimen poistaminen on sallittu, jos aseessa on muu luotettava ampujan käytettävä varmistin.</p><p id="5.1.4"><a href="#5.1.4"><span class="sk">5.1.4</span></a> Asetta tai luokkaa ei saa vaihtaa kesken kilpailun ilman ratamestarin tai kilpailunjohtajan lupaa. Luokka voi vaihtua vain vakiosta tai TST-luokasta avoimeen luokkaan. Aseen ja sen pääosien vaihtamiseen tarvitaan ratamestarin tai kilpailunjohtajan lupa. Muita varusteista voi vaihtaa kilpailun aikana tarpeen mukaan. Aseen pääosia ovat runko-osat, sulkulaite, olkatuki, tähtäinlaitteet ja piippu. Erillinen tähtäimen suurentaja ei kuulu pääosiin. TA-rastia varten saa kiväärin tähtäinlaitteen tilapäisesti vaihtaa.</p><p id="5.1.5"><a href="#5.1.5"><span class="sk">5.1.5</span></a> Aseen tai varusteiden ollessa kaikkien luokkien sääntöjen vastaiset, ei ampuja saa kilpailusta tulosta.</p><p id="5.1.6"><a href="#5.1.6"><span class="sk">5.1.6</span></a> Kilpailunjohtajalla, ratamestarilla ja tuomareilla on oikeus tarkastaa ampujan aseet ja varusteet kilpailualueella, milloin tahansa kilpailun aikana.</p><p id="5.1.7"><a href="#5.1.7"><span class="sk">5.1.7</span></a> Mikäli ase tai varuste todetaan vaaralliseksi, on ampujan korjattava tai vaihdettava ase tai varuste ennen ammunnan jatkamista.</p><p id="5.1.8"><a href="#5.1.8"><span class="sk">5.1.8</span></a> Ase todetaan vaaralliseksi, jos varmistin, puolivirekynsi, sulkuvarmistin tai iskuvasaravarmistin ei toimi tai ase ampuu purske- tai sarjatulta. Ase ei saa laueta liipaisinta palautettaessa, tai aseen pudotessaan ampujan kädestä tai kotelosta kovalle alustalle.</p><p id="5.1.9"><a href="#5.1.9"><span class="sk">5.1.9</span></a> Ratamestari tekee päätökset aseiden, vaatetuksen, jalkineiden ja varusteiden sääntöjenmukaisuudesta.</p><p id="5.1.10"><a href="#5.1.10"><span class="sk">5.1.10</span></a> Ratamestarilla on oikeus kieltää jonkin aseen tai erikoispatruunoiden käyttö koko kilpailussa tai joillakin rasteilla ampumaratasääntöjen, ratalaitteiden rikkoutumisvaaran tai turvallisuusriskin vuoksi.</p><p id="5.1.11"><a href="#5.1.11"><span class="sk">5.1.11</span></a> Kaikkien käytettävien patruunoiden voimakertoimen on oltava vähintään 2450 (luodin paino grammoina x lähtönopeus m/s). Voimakertoimen täsmällistä mittausta ei yleensä vaadita. Mittaus voidaan kuitenkin tehdä, epäiltäessä vaatimuksen täyttymistä. Tällöin mitataan yhdestä patruunasta luodin paino ja neljästä patruunasta nopeuksien keskiarvo.</p><p id="5.1.12"><a href="#5.1.12"><span class="sk">5.1.12</span></a> Ase, jolla ei ammuta rastilla, voidaan määrittää rastikuvauksessa käsittelyaseeksi. Tuomarin tulee tarkastaa ase ennen suoritusta. Aseen patruunapesään tulee laittaa turvalippu merkiksi tarkastuksessa, mikäli mahdollista.</p><a id="5.2"></a><h3>5.2 Aseet</h3><div id="5.2.1"><p><a href="#5.2.1"><span class="sk">5.2.1</span></a> Kilpailuissa voidaan käyttää seuraavia asetyyppejä: </p><ul><li>Kivääri</li><li>Pistooli ja revolveri</li><li>Tarkka-ampujakivääri</li><li>Haulikko</li></ul><p>Näihin liittyvät tarkemmat asemääräykset ovat liitteissä 3-6.</p></div><a id="5.3"></a><h3>5.3 Varusteet</h3><p id="5.3.1"><a href="#5.3.1"><span class="sk">5.3.1</span></a> Aseiden ja lippaiden kantotapaa ei ole rajoitettu, mikäli se on kenttäkelpoinen ja turvallinen. Rastin aloituksessa varalippaat ja varapatruunat ovat ampujan varusteissa tai aseessa olevissa pidikkeissä, ellei rastikuvauksessa muuta määrätä.</p><p id="5.3.2"><a href="#5.3.2"><span class="sk">5.3.2</span></a> Pistoolia varten tulee ampujalla olla turvallinen päivittäiseen palveluskäyttöön soveltuva kotelo.</p><p id="5.3.2.1"><a href="#5.3.2.1"><span class="sk">5.3.2.1</span></a> Kotelot, jossa ase pääsee liikkumaan siten, että varmistin voi mennä pois päältä tai ase voi laueta vahingossa kotelon sisällä ovat kiellettyjä. Kiellettyjä ovat myös kotelot, joissa lukituksen vapauttava sormi voi osua liipaisimeen asetta kotelosta vedettäessä.</p><p id="5.3.2.2"><a href="#5.3.2.2"><span class="sk">5.3.2.2</span></a> Kotelon tulee suojata asetta lialta ja kolhuilta. Sen on peitettävä vähintään aseen etutähtäin, luistin ylä- ja sivupinnat piipun suusta hylsynpoistoaukon etureunaan asti sekä liipaisin. Avoluistisissa aseissa suojaus tulee olla vähintään luistin puoleen väliin asti ja revolvereissä koko piipun mitalla.</p><p id="5.3.2.3"><a href="#5.3.2.3"><span class="sk">5.3.2.3</span></a> Kotelossa on oltava luotettava lukitus, joka estää aseen putoamisen. Ampujan tulee tuomarin pyytäessä osoittaa kotelon pitävyys ennen suoritusta. Kääntötestin tekee tuomari rastin suoritusalueella. Lataamattomaan pistooliin laitetaan täysi lipas kiinni. Revolveri testataan rulla tyhjänä. Kotelo irrotetaan aseen kanssa ja käännetään rauhallisesti ylösalaisin, piipun suunta käsittelysektoriin pitäen. Mikäli ase irtoaa, ei kyseistä koteloa saa käyttää ennen kuin se läpäisee testin.</p><p id="5.3.2.4"><a href="#5.3.2.4"><span class="sk">5.3.2.4</span></a> Kotelon rakenteen ja sijainnin tulee olla sellainen, että vedon aikana ase pysyy sallitussa suunnassa, eikä osoita ampujaa. Pistoolin ollessa kotelossa ja ampujan seistessä normaalisti, ei pistoolin piippu saa osoittaa yli 2 metriä kauemmaksi ampujasta.</p><p id="5.3.3"><a href="#5.3.3"><span class="sk">5.3.3</span></a> Ampujien ja toimihenkilöiden vaatetuksen, jalkineiden ja varusteiden tulee olla maastokelpoisia ja hyvien tapojen mukaisia. Ampujalla tulee olla rastisuorituksen aikana hillityn värinen vaatetus, jalkineet ja varustus sekä pitkälahkeiset housut.</p><p id="5.3.4"><a href="#5.3.4"><span class="sk">5.3.4</span></a> TST-luokan varustevaatimukset ovat <a href="#liite7">liitteessä 7</a>.</p><a id="6"></a><h2>6. Käytettävät taulut ja pistelaskenta</h2><a id="6.1"></a><h3>6.1 Yleiset periaatteet</h3><p id="6.1.1"><a href="#6.1.1"><span class="sk">6.1.1</span></a> Käytettävien taulujen tulee kuvata sellaisia kohteita, joita vastaan tuliaseita voidaan olettaa käytettävän.</p><p id="6.1.2"><a href="#6.1.2"><span class="sk">6.1.2</span></a> Pahvitauluista lasketaan 2 osumaa per taulu, ellei rastikuvauksessa muuta mainita.</p><p id="6.1.3"><a href="#6.1.3"><span class="sk">6.1.3</span></a> Yhdellä rastilla ei saa käyttää useampaa kuin viittä eri taulutyyppiä. Samalla rastilla ei saa käyttää samanlaisia tauluja toisistaan poikkeavilla osuma-alueilla.</p><p id="6.1.4"><a href="#6.1.4"><span class="sk">6.1.4</span></a> Rastilla voidaan antaa pisteitä erikseen määrättävistä tehtävistä (esim. kranaatinheitto). Tehtävistä saatava maksimipistemäärä saa olla korkeintaan 10% rastin maksimipistemäärästä.</p><p id="6.1.5"><a href="#6.1.5"><span class="sk">6.1.5</span></a> Rastien pisteytys perustuu rastin taulupisteistä ja mahdollisista erikseen määrättävistä tehtävistä saatavaan pistemäärään.</p><p id="6.1.6"><a href="#6.1.6"><span class="sk">6.1.6</span></a> Tarkentavia määräyksiä tauluista, osumien tulkinnasta sekä pistelaskusta annetaan kilpailunjärjestämisohjeessa.</p><a id="6.2"></a><h2>6.2 Taulut</h2><p id="6.2.1"><a href="#6.2.1"><span class="sk">6.2.1</span></a> Sopivia tauluja ovat liitteiden 1 ja 2 mukaiset pahvitaulut, osumaan reagoivat taulut, puolustusvoimain käyttämät taulut tai em. taulujen osat. Muitakin tauluja voidaan käyttää, kunhan niiden muoto ja pisteytys selvitetään ampujille.</p><p id="6.2.2"><a href="#6.2.2"><span class="sk">6.2.2</span></a> Taulujen tulee erottua taustastaan ja toisistaan sää- ja valaistusolosuhteiden vaihtelusta riippumatta ampumapaikalta katsoen. Taulut, jotka asetetaan yli 100 m ampumaetäisyydelle tulee varustaa kontrastitaustalla tai maalata kontrastivärillä kansallisissa ja kansainvälisissä mestaruuskilpailuissa. Taulujen muodon ja maaleina käytettyjen mahdollisten kuvien pitää noudattaa hyviä tapoja ja olla kaikille ampujille samalla tavalla havaittavissa ja tunnistettavissa. Ampumatehtävissä mitataan ampumataitoa eikä taulujen paikannuskykyä.</p><p id="6.2.3"><a href="#6.2.3"><span class="sk">6.2.3</span></a> Osumaan reagoivat taulut voivat olla esim. 20-30 cm halkaisijaltaan olevia ympyröitä tai neliöitä, jotka on valmistettu riittävän hyvälaatuisesta teräksestä, josta kimmokkeiden vaara on pieni. Levyt voivat olla muustakin materiaalista (esim. kumi).</p><p id="6.2.4"><a href="#6.2.4"><span class="sk">6.2.4</span></a> Osumaan reagoivien taulujen on aina kaaduttava tai rikkouduttava hyväksyttävästä osumasta (esim. savikiekossa on vähintään 1 haulin reikä) ja ne on asennettava siten, etteivät ne voi kääntyä sivuttain. Muissa kuin kansallisissa ja kansainvälisissä mestaruuskilpailuissa voidaan käyttää tauluna myös ns. kongeja eli osumasta heilahtavia tai kilahtavia metallitauluja, tai muuten osuman ilmaisevia tauluja. Ampuja voi halutessaan pyytää tuomarilta varmistuksen osumasta, jolloin tuomari huutaa: “OSUI&quot; (“HIT&quot;).</p><p id="6.2.5"><a href="#6.2.5"><span class="sk">6.2.5</span></a> Osumaan reagoiva taulu voidaan määrätä etenemisen estäväksi, jolloin taulu on kaadettava tai rikottava rastikuvauksessa esitetyllä tavalla ennen suorituksen jatkamista. Tällaista taulua ei käytetä rajoitettu laukausmäärä rastilla.</p><p id="6.2.6"><a href="#6.2.6"><span class="sk">6.2.6</span></a> Metallitauluja ammuttaessa tulee ampumaetäisyyden kimmokkeiden ja sirpalevaaran takia olla pistoolilla ja haulikolla vähintään 8 metriä. Kiväärillä ja haulikon täyteispatruunoilla metallitauluja ammuttaessa tulee ampumaetäisyyden olla vähintään 20 metriä.</p><p id="6.2.7"><a href="#6.2.7"><span class="sk">6.2.7</span></a> Kaatuvat taulut tulee kalibroida rastilla käytettävällä aseella. Laukaus ammutaan paikalta mistä ao. taulu on ammuttavissa ampumasuorituksen yhteydessä. Aseeltaan valinnaisilla rasteilla kalibrointi suoritetaan pistoolilla, mikäli se on valittavissa. Taulun tulee kaatua kokokaliiperin luodin tai täyteisen osumasta osuma-alueelle. Osuma-alue on se osa taulua, joka näkyy ampumapaikalle. Popper-tyyppisessä kaatuvissa taulussa osuma-alue on yläpallo, ellei rastikuvauksessa ole muuta määrätty. Kaatuvan taulun kalibrointi haulikolla suoritetaan enintään 28 g latauksella, enintään 66 cm (26&quot;) piipusta ja sylinterisupistuksella.</p><p id="6.2.8"><a href="#6.2.8"><span class="sk">6.2.8</span></a> Metallitaulujen osumakohdat tulee maalata suoritusten välillä, poislukien haulipatruunalla ammuttavat taulut ja jaster-tyyppiset metallitaulut. Piiritason ja pienemmissä kilpailuissa tämä sääntökohta voidaan jättää noudattamatta.</p><p id="6.2.9"><a href="#6.2.9"><span class="sk">6.2.9</span></a> Ei-ammuttavien taulujen tulee olla erivärisiä kuin ammuttavat taulut ja pahvitauluissa tulee olla näkyvä E/A- tai N/S-merkintä.</p><a id="6.3"></a><h3>6.3 Osumien tulkkaus</h3><p id="6.3.1"><a href="#6.3.1"><span class="sk">6.3.1</span></a> Osumien tulkkauksen suorittaa tuomari, jolla tulee olla käytössään rengastulkit.</p><p id="6.3.2"><a href="#6.3.2"><span class="sk">6.3.2</span></a> Kukaan ei saa koskettaa tauluja ennen niiden tulkkausta. Jos ampuja on mennyt metriä lähemmäs taulua ja tuomarin arvion mukaan on saattanut vaikuttaa taulun tuloksiin ennen tulkkausta, tuomitaan taulu ilman osumia olevaksi.</p><p id="6.3.3"><a href="#6.3.3"><span class="sk">6.3.3</span></a> Liitteen 1 mukaisissa tauluissa osumaksi katsotaan taulun reunassa olevan tulkkausrajan rikkova luodinreikä. Mikäli taulu on ositettu, tulee leikkaukseen lisätä tulkkausraja 5 mm:n päähän leikatusta reunasta. Läpäisevän esteen takana olevaa taulua ei tule osittaa. Muissa pahvitauluissa osumaksi katsotaan ilmoitetun osuma-alueen rajan rikkova luodinreikä. Missään taulussa ei hyväksytä sirpaloitunutta osumaa, joka selvästi ei ole luodin suoran osuman aiheuttama. Näköesteen läpi (läpäisevä este) ammuttu osuma tulee hyväksyä, vaikka luodin jälki olisi poikittain. (Ns avaimenkuva.) Mikäli taulun tulkkaus on mahdotonta sen rikkouduttua esimerkiksi lähilaukauksesta, on ampujan uusittava suorituksensa.</p><p id="6.3.4"><a href="#6.3.4"><span class="sk">6.3.4</span></a> Kääntyvissä tauluissa ei osumaksi hyväksytä luodinreikää, jonka halkaisija on yli kaksi kertaa käytetyn luodin halkaisija.</p><p id="6.3.5"><a href="#6.3.5"><span class="sk">6.3.5</span></a> Taulukepit ja taulujen sadesuojat ovat läpäiseviä. Kaikki taulut ja muut rastirakenteet ovat läpäisemättömiä, ellei rastikuvauksessa muuta määrätä.</p><p id="6.3.6"><a href="#6.3.6"><span class="sk">6.3.6</span></a> Mikäli sama laukaus on tuottanut osuman kahdessa taulussa ja luodinreikä päällimmäisessä taulussa on kokonaan osuma-alueella eikä riko tulkkausrajaa, osuma tulkitaan vain päällimmäisestä taulusta. Jos päällimmäinen taulu on läpäisevä, tulkitaan osuma myös alemmasta taulusta. Jos osuma päällimmäisessä taulussa rikkoo tulkkausrajan, tulkitaan osuma molemmista tauluista.</p><p id="6.3.7"><a href="#6.3.7"><span class="sk">6.3.7</span></a> Osuma-alueiden rajalla oleva osuma tulkitaan korkeamman pistemäärän antavaksi, jos osuma-alueiden rajaviiva on rikki.</p><p id="6.3.8"><a href="#6.3.8"><span class="sk">6.3.8</span></a> Mikäli ampuja on tyytymätön pahvitaulun tulkkaukseen, toimitetaan taulu ratamestarille tarkistettavaksi. Hänen päätöksensä on lopullinen.</p><p id="6.3.9"><a href="#6.3.9"><span class="sk">6.3.9</span></a> Mikäli ampuja on tyytymätön haulipatruunalla ammutun pystyyn jääneen kaatuvan taulun tulkintaan, hän voi pyytää kalibroinnin tarkastusta tuomarilta välittömästi ampumasuorituksen päättymisen jälkeen. Mikäli taulu kaatuu tarkastuksessa, tulkitaan taulu ohi ammutuksi. Mikäli taulu ei kaadu, tulee ampujan uusia suoritus ja tästä tulee ilmoittaa ratamestarille.</p><a id="6.4"></a><h3>6.4 Taulupisteet</h3><p id="6.4.1"><a href="#6.4.1"><span class="sk">6.4.1</span></a> Sääntöjen liitteen 1 mukaisessa pahvitaulussa osuma A-alueella tuottaa 5 pistettä, B-alueella 5 pistettä, C-alueella 3 pistettä ja D-alueella 1 pistettä.</p><p id="6.4.2"><a href="#6.4.2"><span class="sk">6.4.2</span></a> Jos ampujien loppupisteet ovat tasan, enemmän A-osumia ampunut voittaa.</p><p id="6.4.3"><a href="#6.4.3"><span class="sk">6.4.3</span></a> Tauluista lasketaan rastikuvauksen mukainen määrä korkeimpia osumia.</p><p id="6.4.4"><a href="#6.4.4"><span class="sk">6.4.4</span></a> Osuma kaatuvassa tai särkyvässä taulussa tuottaa 5 tai 10 pistettä ja etenemisen estävässä 10 pistettä.</p><p id="6.4.5"><a href="#6.4.5"><span class="sk">6.4.5</span></a> Muiden taulujen osuma-alueet voidaan pisteyttää vapaavalintaisesti arvoilla 10, 5, 3 ja 1 pistettä tai näiden monikerralla.</p><p id="6.4.6"><a href="#6.4.6"><span class="sk">6.4.6</span></a> Lisäksi tulevat mahdollisista oheistehtävistä saadut pisteet.</p><a id="6.5"></a><h3>6.5 Pistelaskutavat</h3><ol type="a"><li>Rajoittamaton: Suoritusaikaa ja laukausmäärää ei saa rajoittaa.</li><li>Rajoitettu aika: Suoritusaikaa on rajoitettu, mutta laukausmäärää ei. Tulos on ammutuista laukauksista saatujen pisteiden summa. Käytetään esim. kääntyvillä taululaitteilla.</li><li>Rajoitettu laukausmäärä: Suoritusaikaa ei ole rajoitettu, mutta käytettävä laukausmäärä on.</li><li>Rajoitettu aika ja laukausmäärä osumakertoimella: Sekä suoritusaikaa että laukausmäärää on rajoitettu, mutta osumakerroin lasketaan. Se määrittää kilpailijoiden järjestyksen kuten rajoittamattomassa pistelaskutavassa.</li></ol><a id="6.6"></a><h3>6.6 Pistelaskun rangaistukset</h3><p id="6.6.1"><a href="#6.6.1"><span class="sk">6.6.1</span></a> Mikäli ampujalta jää rastin suorittaminen kesken, lasketaan siihen asti ammutut pisteet ja aika. Puuttuvista osumista ja laukauksista annetaan sääntöjen mukaiset rangaistukset.</p><p id="6.6.2"><a href="#6.6.2"><span class="sk">6.6.2</span></a> Rastikuvauksessa on ennakkoon selvitettävä kilpailijoille toimintavirheiden määräytymisperusteet, eikä niitä saa antaa mielivaltaisesti. Toimintavirheellä tarkoitetaan suoritusta, jossa poiketaan rastikuvauksessa annetuista toimintatavoista. Rangaistuksena annetaan 10 virhepistettä jokaisesta virheestä. Tuomarin tulee määritellä virheiden lukumäärä sekä toimintavirheiden syy. Nämä tiedot merkitään selvästi tuloslaskentajärjestelmään. Toimintavirherangaistus siitä, ettei ampuja ole ampunut yhtään laukausta jotain taulua kohti voidaan antaa, jos tällainen rangaistusmahdollisuus on erikseen rastikuvauksessa määritelty. Ellei rastikuvauksessa muuta määrätä, kun ampuja ampuessaan koskettaa maata rikelinjan ulkopuolella ja saa tästä selvää etua, rangaistaan häntä toimintavirheellä jokaisesta väärin ammutusta laukauksesta. Mikäli ampuja ampuu rikkoessaan rikelinjaa, mutta ei saa tästä etua, rangaistaan häntä vain yhdellä toimintavirheellä. Toimintavirheidenmäärä ei saa ylittää kilpailijan saavutettavissa olevien pisteosumien maksimimäärää. Oikaisusta rajalinja ylittämällä seuraa yksi toimintavirhe jokaisesta oikaisemisen jälkeisestä laukauksesta. Vahingossa tehdyn oikaisun voi kilpailija peruuttaa palaamalla takaisin oikaisun alkuun.</p><p id="6.6.3"><a href="#6.6.3"><span class="sk">6.6.3</span></a> Jokaisesta Tiitinen tunnelin pudotetusta rimasta seuraa toimintavirhe.</p><p id="6.6.4"><a href="#6.6.4"><span class="sk">6.6.4</span></a> Osumasta ei-ammuttavassa taulussa rangaistaan 10 virhepisteellä. Yhdestä ei-ammuttavasta taulusta lasketaan enintään 2 osumaa, ellei rastikuvauksessa muuta määrätä.</p><p id="6.6.5"><a href="#6.6.5"><span class="sk">6.6.5</span></a> Katoavista ja pois kääntyvistä tauluista puuttuvista osumista ei rangaista.</p><p id="6.6.6"><a href="#6.6.6"><span class="sk">6.6.6</span></a> Mikäli kaatuva taulu jää pystyyn tai särkyvä taulu ehjäksi, annetaan rangaistus, joka on kaksi kertaa yhden osuman maksimipistemäärä.</p><p id="6.6.7"><a href="#6.6.7"><span class="sk">6.6.7</span></a> Tähtäinkuvan ottamisesta ennen aloitusta useampaan kuin yhteen kohteeseen seuraa yksi toimintavirhe.</p><p id="6.6.8"><a href="#6.6.8"><span class="sk">6.6.8</span></a> Useamman kuin yhden kiväärin tukijalan käyttämisestä tai tukijalan hylkäämisestä kesken rastia seuraa yksi toimintavirhe. Tukijalka tulkitaan hylätyksi jos tukijalka ei ole ampujalla mukana ennen viimeistä laukausta. </p><p id="6.6.9"><a href="#6.6.9"><span class="sk">6.6.9</span></a> Rajoittamattomassa –pistelaskutavassa puuttuvista osumista annetaan ohilaukausrangaistus, joka on kaksi kertaa yhden osuman maksimipisteet.</p><p id="6.6.10"><a href="#6.6.10"><span class="sk">6.6.10</span></a> Rajoitettu aika –pistelaskutavassa sekä rajoitettu aika ja laukausmäärä –pistelaskutavassa puuttuvista osumista ei rangaista. Aikarajan jälkeen ammutuista laukauksista vähennetään kustakin yhden laukauksen maksimipistemäärä. Ylimääräiset laukaukset merkitään tuloksiin sitä varten varattuun kohtaan.</p><p id="6.6.11"><a href="#6.6.11"><span class="sk">6.6.11</span></a> Rajoitettu laukausmäärä –pistelaskutavassa rangaistaan puuttuvista osumista ja ylimääräisistä laukauksista kaksi kertaa yhden osuman maksimipistemäärä. Ylimääräiset laukaukset merkitään tuloksiin sitä varten varattuun kohtaan.</p><p id="6.6.12"><a href="#6.6.12"><span class="sk">6.6.12</span></a> Jos taulu on määrätty etenemisen estäväksi, eikä ampuja kaada tai riko sitä rastikuvauksen mukaisesti, seuraa siitä yksi toimintavirhe. Jos puuttuvasta osumasta aiheutuu merkittävää etua, niin siitä seuraa virheen tekemisen jälkeen toimintavirhe joka laukaukselta.</p><p id="6.6.13"><a href="#6.6.13"><span class="sk">6.6.13</span></a> Ratamestari voi, kilpailijan pyynnön perusteella määrätä erillisen vähennyksen rastituloksesta, mikäli kilpailija ei fyysisen vamman tai vastaavan rajoitteen takia ole kykeneväinen suorittamaan rastisuoritusta rastikuvauksen mukaisesti. Mikäli ratamestari hyväksyy pyynnön, tulee hänen ennen kilpailijan rastisuoritusta määritellä 1-20% vähennys ammutuista rastipisteistä. Vähennys tehdään riittävällä määrällä toimintavirheitä. Rastimestari voi myös olla määräämättä vähennystä, mikäli kilpailijalla on erityisen merkittävä fyysinen vamma tai rajoite. Mikäli ratamestari hylkää pyynnön, huomioidaan rastisuorituksessa normaalit pistelaskun rangaistukset.</p><p id="6.6.14"><a href="#6.6.14"><span class="sk">6.6.14</span></a> Kaikissa pistelaskutavoissa voidaan määrätä rastin maksimi suoritusaika. Suositus on 180 sekuntia. Aikarajan jälkeen ammutuista laukauksista vähennetään kustakin yhden laukauksen maksimipistemäärä. Ylimääräiset laukaukset merkitään tuloksiin sitä varten varattuun kohtaan. Tuomarilla on oikeus keskeyttää suoritus aikarajan jälkeen.</p><a id="6.7"></a><h3>6.7 Tuloslaskenta</h3><p id="6.7.1"><a href="#6.7.1"><span class="sk">6.7.1</span></a> Tulokset lasketaan ja ilmoitetaan kullekin luokalle erikseen. Sarjojen tulokset ilmoitetaan luokittain.</p><p id="6.7.2"><a href="#6.7.2"><span class="sk">6.7.2</span></a> Rastin pistemäärää laskettaessa huomioidaan luvun 6.4 mukaiset suorituspisteet vähennettynä luvun 6.6 mukaisilla rangaistuksilla.</p><p id="6.7.3"><a href="#6.7.3"><span class="sk">6.7.3</span></a> Mikäli rastilla käytetään rajoittamaton laukausmäärä, rajoitettu laukausmäärä tai rajoitettu aika ja laukausmäärä osumakertoimella –pistelaskutapaa, lasketaan ampujille osumakerroin jakamalla pisteet ajalla. Suurimman osumakertoimen saavuttanut ampuja on rastin voittaja ja saa rastipisteikseen rastin maksimipisteet. Muiden ampujien rastipisteet saadaan jakamalla rastin maksimipisteet voittajan osumakertoimella ja kertomalla saatu tulos ampujan omalla osumakertoimella.</p><p id="6.7.4"><a href="#6.7.4"><span class="sk">6.7.4</span></a> Mikäli rastilla käytetään rajoitettu aika pistelaskutapaa, parhaat pisteet saavuttanut ampuja on rastin voittaja ja saa rastipisteikseen rastin maksimipisteet. Muiden ampujien rastipisteet saadaan jakamalla rastin maksimipisteet voittajan pisteillä ja kertomalla saatu tulos ampujan omilla pisteillä.</p><p id="6.7.5"><a href="#6.7.5"><span class="sk">6.7.5</span></a> Pienin mahdollinen rastipistemäärä on nolla.</p><p id="6.7.6"><a href="#6.7.6"><span class="sk">6.7.6</span></a> Ampujan kokonaispistemäärä saadaan laskemalla yhteen ampujan kaikkien rastien rastipisteet.</p><p id="6.7.7"><a href="#6.7.7"><span class="sk">6.7.7</span></a> Kilpailun voittaa ampuja, jonka kokonaispistemäärä on suurin.</p><p id="6.7.8"><a href="#6.7.8"><span class="sk">6.7.8</span></a> Tulosten laskentaan käytetään hyväksyttyä tuloslaskentaohjelmaa. Tulokset on laskettava neljän desimaalin tarkkuudella. Tulokset on esitettävä myös prosenttimuodossa kilpailijoiden välisten erojen selventämiseksi.</p><a id="7"></a><h2>7. Tuloslaskentajärjestelmä</h2><p id="7.1"><a href="#7.1"><span class="sk">7.1</span></a> Jokaisen ampujan velvollisuus on pitää kirjaa tuloksistaan virallisen tuloskirjanpidon lisäksi. Tuloslaskentajärjestelmä voi olla sähköinen tai paperinen. </p><p id="7.2"><a href="#7.2"><span class="sk">7.2</span></a> Tuomarin tulee varmistaa, että kaikki tiedot on merkitty tuloslaskentajärjestelmään ennen kuin hän allekirjoittaa tuloksen. Sen jälkeen ampuja allekirjoittaa sen. Tämän jälkeen tuloslaskentajärjestelmään ei saa tehdä muita muutoksia kuin laskuvirheiden korjauksia. </p><p id="7.3"><a href="#7.3"><span class="sk">7.3</span></a>Mikäli tuomari ja ampuja ovat erimielisiä jostain asiasta, se kirjataan tuloslaskentajärjestelmään ja toimitaan luvun 8.2 mukaisesti. </p><p id="7.4"><a href="#7.4"><span class="sk">7.4</span></a> Mikäli julkaistuissa rastituloksissa on virhe, ampujan velvollisuus on pyytää oikaisua viimeistään ennen alkupuhuttelussa määrätyn rastitulosten tarkastusajan päättymistä. Tuloslaskennan velvollisuus on korjata virhe, joka on tehty tuloksia laskettaessa. Muussa tapauksessa toimitaan luvun <a href="#8.1.2">8.1.2</a> mukaan. </p><p id="7.5"><a href="#7.5"><span class="sk">7.5</span></a> Kilpailun lopputuloksia ei saa virallistaa ennen kuin rastitulokset on julkaistu ja ampujilla on ollut tilaisuus tarkastaa ne.</p><a id="8"></a>`,253),s(`h2`,f,`8. Uusinnat ja protestointi`,512),n[1]||=a(`<a id="8.1"></a><h3>8.1 Uusinnat</h3><div id="8.1.1"><p><a href="#8.1.1"><span class="sk">8.1.1</span></a> Ampujalla on oikeus uusia suorituksensa rastilla mikäli:</p><ol type="a"><li>Tuomari koskee ampujaan tai häiritsee ampujaa.</li><li>Ampujasta riippumaton huomattava ulkoinen häiriö vaikuttaa ampujan suoritukseen.</li><li>Ampujalla ei ole ollut mahdollisuutta saada kaikkea tarpeellista tietoa rastin suorittamiseen tai hänelle on annettu väärää tietoa toimihenkilöiden taholta.</li><li>Suoritus keskeytetään, muun kuin hylkäykseen johtavan rikkeen johdosta.</li></ol></div><div id="8.1.2"><p><a href="#8.1.2"><span class="sk">8.1.2</span></a> Ampujan täytyy uusia suorituksensa jos:</p><ol type="a"><li>Tuloslaskentajärjestelmään on kirjattu väärä määrä osumia, aika puuttuu tai toinen allekirjoitus puuttuu. Ampujan kieltäytyminen allekirjoittamasta tulosta ei johda uusintaan.</li><li>Rastia muutetaan tavalla, jonka merkitys sen suorituksen kannalta ei ole vähäinen.</li><li>Ratalaitteessa olevan häiriön vuoksi suoritusta ei voi ampua rastikuvauksessa tarkoitetulla tavalla. Mikäli kaatuva tai rikkoutuva taulu ei toimi aiotulla tavalla, suoritus keskeytetään heti.</li><li>Toinen henkilö avustaa ampujaa suorituksen aikana.</li><li>Rekisteröitynyt suoritusaika on ilmeisen virheellinen tai tuomarilla on muu perusteltu syy epäillä, että kilpailijan tulos rastilta on merkittävästi vääristynyt.</li><li>Toimihenkilö koskee kaatuvaan tauluun ennen kalibroinnin tarkastusta tai kaatuva taulu ei kaadu kalibroinnin tarkastuksessa.</li></ol><p>Epäselvissä tapauksissa ratkaisuvalta uusinnasta on ratamestarilla. Mikäli kilpailija ei suostu uusintaan on kirjattava hänen tuloksekseen rastilta nolla pistettä.</p></div><p id="8.1.3"><a href="#8.1.3"><span class="sk">8.1.3</span></a> Ampujan uusiessa suorituksensa, rastin aikaisempi tulos mitätöityy. Jos ampujalla on oikeus uusintaan, ei ampuja ennen uusintaa saa mennä tauluille tuloksia katsomaan, eikä tuomari ilmoita aikaa.</p><div id="8.1.4"><p><a href="#8.1.4"><span class="sk">8.1.4</span></a> Jos uusinta ei ole mahdollinen:</p><ol type="a"><li>Tulokseksi tulee rastilta nolla, jos tuloslaskentajärjestelmästä puuttuu aika.</li><li>Kirjattu tulos jää voimaan, jos tuloslaskentajärjestelmään ei ole kirjattu kaikkia osumia tai puuttuvia osumia.</li><li>Tulokseen lasketaan mukaan vain rastinkuvauksen mukainen määrä korkeimpia osumia, jos tuloslaskentajärjestelmään on merkitty liikaa osumia.</li></ol></div><p id="8.1.5"><a href="#8.1.5"><span class="sk">8.1.5</span></a> Häiriö tai rikkoutuminen aseessa tai patruunoissa ei oikeuta uusintaan. </p><p id="8.1.6"><a href="#8.1.6"><span class="sk">8.1.6</span></a> Rasti voidaan mitätöidä, mikäli ampujilla ei ole ollut tasapuolista mahdollisuutta suorittaa sitä ja asian vaikutus on merkittävä kilpailun lopputulosten kannalta. </p><a id="8.2"></a><h3>8.2 Valitusmenettely</h3><p id="8.2.1"><a href="#8.2.1"><span class="sk">8.2.1</span></a> Mikäli ampuja on tyytymätön tuomarin päätökseen, hän voi valittaa siitä ratamestarille.</p><p id="8.2.2"><a href="#8.2.2"><span class="sk">8.2.2</span></a> Mikäli ampuja on tyytymätön ratamestarin päätökseen, hän voi tehdä protestin kilpailun jury:lle. Turvallisuusrikkeeseen liittyvästä tuomarin päätöksestä ei voi tehdä protestia, koska rikkeen arviointi jälkeenpäin ei ole mahdollista, mutta ratamestarin sääntöjenmukaisuuspäätöksestä voi tehdä protestin. Protestia ei voi myöskään tehdä taulun tulkkauksesta tai ratamestarin suorittamasta tuloslaskentajärjestelmän tulkinnasta. </p><p id="8.2.3"><a href="#8.2.3"><span class="sk">8.2.3</span></a> Muuhun kuin tuloslaskennan virheisiin liittyvissä asioissa on protesti jätettävä kahden tunnin kuluessa protestin aiheuttaneesta tapahtumasta tai sen tiedoksisaamisesta, kuitenkin ennen kilpailun päättymistä, jotta mahdolliset uusinnat voidaan toteuttaa.</p><p id="8.2.4"><a href="#8.2.4"><span class="sk">8.2.4</span></a> Kilpailun jury tekee päätöksensä ennen lopullisten rastituloksen julkaisemista, tutustuttuaan tilanteeseen ja kuultuaan protestin tekijää, tuomaria ja tapahtuman silminnäkijöitä sekä katsottuaan mahdollisen videomateriaalin. Päätös on kuitenkin tehtävä saman kilpailupäivän aikana, jona protesti on jätetty.</p><p id="8.2.5"><a href="#8.2.5"><span class="sk">8.2.5</span></a> Kilpailun jury tulee julkistaa kilpailun alkupuhuttelussa. Juryn jäsenet ovat kilpailunjohtaja, puheenjohtajana ilman äänivaltaa ja kolme kilpailuorganisaation ulkopuolista SRA-tuomaria. Juryn jäsenille on nimettävä varamiehet jääviyden varalta.</p><p id="8.2.6"><a href="#8.2.6"><span class="sk">8.2.6</span></a> Kun protesti esitetään jurylle, tulee samalla suorittaa protestimaksu, jonka suuruuden määrää Reserviläisurheiluliitto.</p><p id="8.2.7"><a href="#8.2.7"><span class="sk">8.2.7</span></a> Protestimaksu palautetaan protestin tekijälle, mikäli juryn päätös on hänelle myönteinen. Mikäli päätös on kielteinen, tilitetään protestimaksu Reserviläisurheiluliitolle.</p><p id="8.2.8"><a href="#8.2.8"><span class="sk">8.2.8</span></a> Muutkin osapuolet kuin ampuja, jota asia varsinaisesti koskee, voivat esittää protestin edellä määrätyllä tavalla. </p><p id="8.2.9"><a href="#8.2.9"><span class="sk">8.2.9</span></a> Kerho- ja piiritason kilpailuissa ei tarvitse nimetä juryä ja ylin päätösvalta on kilpailun johtajalla. Tällöin ei myöskään suoriteta protestimaksua.</p><p>Nämä Reserviläisurheiluliiton (RESUL) Sovelletun Reserviläisammunnan (SRA) säännöt on vahvistettu RESUL:n hallituksen toimesta 26.2.2024, Säännöt ovat voimassa 1.3.2024 alkaen.</p><a id="liite1"></a><h2>Liite 1 - Pahvitaulu 2024</h2><p>Mitat ovat millimetreissä.</p><img width="100%" src="/sra-test/assets/pahvitaulu2024-L1Xl53-n.png" alt="SRA pahvitaulu 2024"><a id="liite2"></a><h2>Liite 2 - Pahvitaulu</h2><img width="100%" src="/sra-test/assets/pahvitaulu-dTEIVQzu.png" alt="SRA pahvitaulu"><a id="liite3"></a><h2>Liite 3 - Kivääri</h2><table><tbody><tr><th></th><th></th><th>Vakio</th><th>Avoin</th><th>TST</th></tr><tr><td>1.</td><td>Keskisytytteistä patruunaa käyttävä olkaa vasten tuettava ase<sup>1</sup></td><td>Vaaditaan</td><td>Vaaditaan</td><td>Vaaditaan</td></tr><tr><td>2.</td><td>Vähintään 20 ptr lipas kiinnitettävissä</td><td>Vaaditaan</td><td>Vaaditaan</td><td>Vaaditaan</td></tr><tr><td>3.</td><td>Varustettavissa asekäyttöön soveltuvalla kantohihnalla</td><td>Vaaditaan</td><td>Vaaditaan</td><td>Vaaditaan</td></tr><tr><td>4.</td><td>Elektroniset tai optiset tähtäimet<sup>3</sup></td><td>Ei\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>5.</td><td>Tukijalat</td><td>Ei\xA0sallittu</td><td>Enintään 400 mm piipun keskilinjasta ulospäin<sup>2</sup></td><td>Enintään 400 mm piipun keskilinjasta ulospäin<sup>2</sup></td></tr><tr><td>6.</td><td>Etutukin pystykahva tai vastaava</td><td>Enintään 152 mm piipun keskilinjasta ulospäin </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>7.</td><td>Laukaisun parantaminen</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>8.</td><td>Karhennukset tai pintakäsittely</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>9.</td><td>Toimintavarmuutta ja käsittelyä parantavat pienet muutokset </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>10.</td><td>Jälkiasennetut varmistimet</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>11.</td><td>Suujarrut ja kompensaattorit</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>12.</td><td>Aänenvaimentimet ja eteenpäin paineen purkavat muut suulaitteet </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>13.</td><td>Toimiva valaisin</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr></tbody></table><p>(1) Esimerkiksi pitkä tai lyhyt kivääri (muu ase) sekä pistoolikarbiini.</p><p>(2) Tukijalkojen mittaus tehdään piipun keskilinjastasuoraan alaspäin kun jalka on avattu täyteen mittaansa.</p><p>(3) Optinen tähtäin on tähtäinlaite, jossa on linssi,prisma tai peili. Elektroniseksi tähtäinlaitteeksi katsotaan myös laserosoitin.</p><a id="liite4"></a><h2>Liite 4 - Pistooli ja revolveri</h2><table><tbody><tr><th></th><th></th><th>Vakio</th><th>Avoin</th><th>TST</th></tr><tr><td>1.</td><td>Vähimmäiskaliiperi</td><td>9 mm</td><td>9 mm</td><td>9 mm</td></tr><tr><td>2.</td><td>Olkatuki</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td></tr><tr><td>3.</td><td>Tähtäinten avartaminen tai vaihto</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>4.</td><td>Elektroniset tai optiset tähtäimet3</td><td>Ei\xA0sallittu</td><td>On\xA0sallittu luistiin kiinnitettävät elektroniset ja optiset tähtäimet sekä aseeseen kiinnitettävät lasertähtäimet1 </td><td>On\xA0sallittu luistiin kiinnitettävät elektroniset ja optiset tähtäimet sekä aseeseen kiinnitettävät lasertähtäimet1 </td></tr><tr><td>5.</td><td>Lisäpainot</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td></tr><tr><td>6.</td><td>Tukikäden peukalon tuki</td><td>Sallittu</td><td>Sallittu</td><td>Ei\xA0sallittu</td></tr><tr><td>7.</td><td>Laukaisun parantaminen</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>8.</td><td>Laukaisuvastus</td><td>Rajoitettu<sup>2</sup></td><td>Rajoitettu<sup>2</sup></td><td>Rajoitettu<sup>2</sup></td></tr><tr><td>9.</td><td>Karhennukset, pintakäsittely tai kahvalevyjen muokkaus </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>10.</td><td>Toimintavarmuutta ja käsittelyä parantavat pienet muutokset</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>11.</td><td>Jälkiasennetut varmistimet ja luistin salvat </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>12.</td><td>Suujarrut ja kompensaattorit</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td><td>Ei\xA0sallittu</td></tr><tr><td>13.</td><td>Äänenvaimentimet</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>14.</td><td>Toimiva, valaisukäyttöön suunniteltu asevalo </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr></tbody></table><p>(1) Revolverissa optisten tähtäimien kiinnityspaikkaaei ole rajoitettu.</p><p>(2) Mikäli aseessa ei ole ampujan käytettävissä olevaavarmistinta tai vireestäpäästintä, tulee laukaisuvastuksen olla vähintään 1500 g.</p><p>(3) Optinen tähtäin on tähtäinlaite, jossa on linssi,prisma tai peili. Elektroniseksi tähtäinlaitteeksi katsotaan myös laserosoitin.</p><a id="liite5"></a><h2>Liite 5 - Tarkka-ampujakivääri</h2><table><tbody><tr><th></th><th></th><th>Vakio</th><th>Avoin</th><th>TST</th></tr><tr><td>1.</td><td>Keskisytytteistä patruunaa käyttävä olkaa vasten tuettava ase </td><td>Vaaditaan</td><td>Vaaditaan</td><td>Vaaditaan</td></tr><tr><td>2.</td><td>Paino ampumakunnossa</td><td>Enintään 25 kg</td><td>Enintään 25 kg</td><td>Enintään 25 kg</td></tr><tr><td>3.</td><td>Tähtäimet</td><td>Kaikki sallittu</td><td>Kaikki sallittu</td><td>Kaikki sallittu</td></tr><tr><td>4.</td><td>Toimintavarmuutta ja käsittelyä parantavat sekä rakenteelliset muutokset </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>5.</td><td>Piipun suulaitteet</td><td>Kaikki sallittu</td><td>Kaikki sallittu</td><td>Kaikki sallittu</td></tr><tr><td>6.</td><td>Hiekkapussit ja ampumatuet</td><td>Sallittu, ellei rastikuvauksessa muuta määrätä </td><td>Sallittu, ellei rastikuvauksessa muuta määrätä </td><td>Sallittu, ellei rastikuvauksessa muuta määrätä </td></tr><tr><td>7.</td><td>Toimiva valaisin</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>8.</td><td>Lisäpaino</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr></tbody></table><a id="liite6"></a><h2>Liite 6 - Haulikko</h2><table><tbody><tr><th></th><th></th><th>Vakio</th><th>Avoin</th><th>TST</th></tr><tr><td>1.</td><td>Haulikon patruunaa käyttävä ase</td><td>Vaaditaan</td><td>Vaaditaan</td><td>Vaaditaan</td></tr><tr><td>2.</td><td>Tähtäinten avartaminen tai vaihto</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>3.</td><td>Elektroniset tai optiset tähtäimet<sup>1</sup></td><td>Ei\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>4.</td><td>Toimintavarmuutta ja käsittelyä parantavat sekä rakenteelliset muutokset </td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>5.</td><td>Suujarrut ja kompensaattorit</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>6.</td><td>Pikalaturit ja lippaat</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr><tr><td>7.</td><td>Toimiva valaisin</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td><td>On\xA0sallittu</td></tr></tbody></table> (1) Optinen tähtäin on tähtäinlaite, jossa on linssi,prisma tai peili. Elektroniseksi tähtäinlaitteeksi katsotaan myös laserosoitin. <a id="liite7"></a><h2>Liite 7 - TST-luokan varusteet</h2> TST-luokan ampujalla tulee olla rastia aloittaessaan mukanaan vähintään seuraavat varusteet: <table><tbody><tr><th>1.</th><td>Kilpailussa käytettävä pistooli kotelossaan. Mikäli rastilla ei käytetä pistoolia, tyhjän lippaan voi kiinnittää pistooliin rastin ajaksi tuomarin luvalla. </td></tr><tr><th>2.</th><td>Vähintään 90 kiväärin patruunaa lipastettuna vähintään kolmeen 30 patruunan tai suurempaan lippaaseen rastin aloituksessa. Ns. pitkää kiväärin patruunaa käyttävien, esim. 7.62x51/.308 Win, aseiden kanssa voi käyttää vähintään 20 patruunan lippaita. </td></tr><tr><th>3.</th><td>Vähintään 30 pistoolin patruunaa lipastettuna vähintään kahteen lippaaseen rastin aloituksessa.</td></tr><tr><th>4.</th><td>Koko rastisuorituksen ajan vähintään 1 litra vettä.</td></tr><tr><th>5.</th><td>Teräase, jonka terän pituus on vähintään 9 cm.</td></tr><tr><th>6.</th><td>Irrotettava asevalo tai muu toimiva valaisin.</td></tr><tr><th>7.</th><td>Kiväärin kantohihna.</td></tr><tr><th>8.</th><td>Ensiapuvälineet, vähintään kiristysside ja ensiside tai ensiapupeite.</td></tr><tr><th>9.</th><td>Taisteluliivi/varusteliivi (chest rig), sirpalesuojaliivi tai luotisuojaliivi (plate carrier).</td></tr><tr><th>10.</th><td>Palveluskäyttöön sopivat ja hillityn väriset käsineet.</td></tr><tr><th>11.</th><td> Kenttäkelpoinen vaatetus <ul><li>Palveluskäyttöön sopiva</li><li>Hillityn värinen</li><li>Pitkälahkeinen ja pitkähihainen</li></ul></td></tr><tr><th>12.</th><td>Kenttäkelpoiset jalkineet <ul><li>Palveluskäyttöön sopivat</li><li>Hillityn väriset</li><li>Pitkävartiset eli jalkineen varren tulee peittää nilkan kehräsluu</li></ul></td></tr></tbody></table><p>Ampujan varusteiden yhteispainon tulee olla vähintään 12 kg. Punnittavien varusteiden yhteispainoon lasketaan mukaan kohtien 1. - 9. lisäksi seuraavat: </p><ul><li>Taisteluvyö (battle belt), varustevyö tai vastaava.</li><li>Kypärä siihen kiinnitettyine varusteineen, kuten kuulosuojaimet ja suojalasit.</li><li>Kaikki muut varusteet, jotka ovat mukana ampujan varusteissa, kuten repussa tai liivissä.</li><li>Polvi- ja kyynärpääsuojat.</li></ul><p> Varusteiden tahallinen keventäminen rastisuorituksen aikana on kiellettyä. Pakolliset varusteet 1. - 8. ja 10. tulee olla saatavilla niin, että ampuja saa ne käyttöönsä yhdellä kädellä. Haulikko- tai tarkka-ampujarasteilla TST-luokan ampujan ei tarvitse kantaa varusteissaan pakollisia kiväärin lippaita, kunhan varusteiden minimipaino täyttyy. </p>`,53)])}var m=c(u,[[`render`,p]]),h={},g={class:`rules`};function _(e,n){return t(),o(`div`,g,[...n[0]||=[a(`<h1 class="rules-heading" data-v-22c77eeb>Regelbok för SRA / TTS</h1><p class="rules-heading" data-v-22c77eeb> Version 8.0. Källa <a href="https://www.pistolskytteforbundet.se/app/uploads/2025/03/sra-tts-regelbok-8.0-230622-gallande.pdf" target="_blank" rel="noopener" data-v-22c77eeb>sra-tts-regelbok-8.0-230622-gallande.pdf</a></p><p class="rules-heading" data-v-22c77eeb> Sovellettu ReserviläisAmmunta (SRA) — i Sverige även kallad Tillämpat TjänsteSkytte (TTS). Tilläggsregler som gäller särskilt i Sverige är markerade nedan. </p><hr data-v-22c77eeb><ul class="toc" data-v-22c77eeb><li data-v-22c77eeb><a href="#1" data-v-22c77eeb>1. Introduktion</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#1.1" data-v-22c77eeb>1.1 Generella principer</a></li><li data-v-22c77eeb><a href="#1.2" data-v-22c77eeb>1.2 Tävlingar</a></li><li data-v-22c77eeb><a href="#1.3" data-v-22c77eeb>1.3 Skjutstationer</a></li><li data-v-22c77eeb><a href="#1.4" data-v-22c77eeb>1.4 Skjutstationers uppbyggnad</a></li><li data-v-22c77eeb><a href="#1.5" data-v-22c77eeb>1.5 Tidtagning</a></li></ul><li data-v-22c77eeb><a href="#2" data-v-22c77eeb>2. Tävlingsledning</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#2.1" data-v-22c77eeb>2.1 Tävlingskommissarie</a></li><li data-v-22c77eeb><a href="#2.2" data-v-22c77eeb>2.2 Tävlingsledare</a></li><li data-v-22c77eeb><a href="#2.3" data-v-22c77eeb>2.3 Banchef</a></li><li data-v-22c77eeb><a href="#2.4" data-v-22c77eeb>2.4 Tävlingssekreterare</a></li><li data-v-22c77eeb><a href="#2.5" data-v-22c77eeb>2.5 Domare</a></li><li data-v-22c77eeb><a href="#2.6" data-v-22c77eeb>2.6 Protokollförare</a></li><li data-v-22c77eeb><a href="#2.7" data-v-22c77eeb>2.7 Övrig tävlingsorganisation</a></li></ul><li data-v-22c77eeb><a href="#3" data-v-22c77eeb>3. Säkerhetsregler</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#3.1" data-v-22c77eeb>3.1 Generella säkerhetsregler</a></li><li data-v-22c77eeb><a href="#3.2" data-v-22c77eeb>3.2 Övergripande säkerhet</a></li><li data-v-22c77eeb><a href="#3.3" data-v-22c77eeb>3.3 Osäker hantering av eldhandvapen</a></li><li data-v-22c77eeb><a href="#3.4" data-v-22c77eeb>3.4 Pekvinklar och skjutgränser</a></li></ul><li data-v-22c77eeb><a href="#4" data-v-22c77eeb>4. Vid Skjutstation</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#4.1" data-v-22c77eeb>4.1 Övergripande</a></li><li data-v-22c77eeb><a href="#4.2" data-v-22c77eeb>4.2 Kommandon och genomförande</a></li></ul><li data-v-22c77eeb><a href="#5" data-v-22c77eeb>5. Eldhandvapen och Utrustning</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#5.1" data-v-22c77eeb>5.1 Allmänt</a></li><li data-v-22c77eeb><a href="#5.2" data-v-22c77eeb>5.2 Eldhandvapen</a></li><li data-v-22c77eeb><a href="#5.3" data-v-22c77eeb>5.3 Utrustning</a></li></ul><li data-v-22c77eeb><a href="#6" data-v-22c77eeb>6. Mål och Poäng</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#6.1" data-v-22c77eeb>6.1 Allmänna principer</a></li><li data-v-22c77eeb><a href="#6.2" data-v-22c77eeb>6.2 Mål</a></li><li data-v-22c77eeb><a href="#6.3" data-v-22c77eeb>6.3 Poängmarkering</a></li><li data-v-22c77eeb><a href="#6.4" data-v-22c77eeb>6.4 Målens poäng</a></li><li data-v-22c77eeb><a href="#6.5" data-v-22c77eeb>6.5 Poängberäkningsmetoder</a></li><li data-v-22c77eeb><a href="#6.6" data-v-22c77eeb>6.6 Straffpoäng</a></li><li data-v-22c77eeb><a href="#6.7" data-v-22c77eeb>6.7 Tävlingsresultat</a></li></ul><li data-v-22c77eeb><a href="#7" data-v-22c77eeb>7. Poängräkning</a></li><li data-v-22c77eeb><a href="#8" data-v-22c77eeb>8. Omskjutning och protestförfarande</a></li><ul data-v-22c77eeb><li data-v-22c77eeb><a href="#8.1" data-v-22c77eeb>8.1 Omskjutning (Re-shoot)</a></li><li data-v-22c77eeb><a href="#8.2" data-v-22c77eeb>8.2 Protestförfarande</a></li></ul><li data-v-22c77eeb><a href="#bilaga1" data-v-22c77eeb>Bilaga 1 — Papptavla IPSC Metric</a></li><li data-v-22c77eeb><a href="#bilaga2" data-v-22c77eeb>Bilaga 2 — Gevär / Karbin</a></li><li data-v-22c77eeb><a href="#bilaga3" data-v-22c77eeb>Bilaga 3 — Pistol och revolver</a></li><li data-v-22c77eeb><a href="#bilaga4" data-v-22c77eeb>Bilaga 4 — Skarp- och prickskyttegevär</a></li><li data-v-22c77eeb><a href="#bilaga5" data-v-22c77eeb>Bilaga 5 — Hagelvapen</a></li><li data-v-22c77eeb><a href="#bilaga6" data-v-22c77eeb>Bilaga 6 — Utrustning för militära divisionerna</a></li></ul><hr data-v-22c77eeb><a id="1" data-v-22c77eeb></a><h2 data-v-22c77eeb>1. Introduktion</h2><div id="1.1" data-v-22c77eeb><h3 data-v-22c77eeb>1.1 Generella principer</h3><ul data-v-22c77eeb><li data-v-22c77eeb>Sovellettu ReserviläisAmmunta (SRA) eller Tillämpat tjänsteskytte (TTS) som det benämns i Försvarsmakten, är en dynamisk skyttesport som riktar sig till all försvarsmaktspersonal, värnpliktiga, anställda, avtalspersonal samt skytteinstruktör vid FFO (Frivillig FörsvarsOrganisation). Syftet är att medge en tjänstenära idrott där individen kan utveckla och bibehålla sin skjutförmåga på ett säkert sätt som överensstämmer med försvarsmaktens instruktioner och reglementen.</li><li data-v-22c77eeb>Den tävlande måste ha en anknytning till försvarsmakten enligt ovan. Den tävlande måste med godkänt resultat ha genomfört Teorikurs Grunder TTS (OBS. Gäller ej värnpliktiga under GU.) samt genomfört godkänt Kompetensprov BAS för de vapensystem som den tävlande avser tävla med.</li><li data-v-22c77eeb>En tävlande som med godkänt resultat har genomfört Teorikurs Grunder TTS, kan under uppsyn och med tillåtelse av en Domare (RO), få delta i skjutträning, ej tävling, i syfte att öva mot Kompetensprov BAS.</li><li data-v-22c77eeb>En tävlande som deltar i TTS utanför ordinarie tjänst (d.v.s vid föreningsverksamhet) måste vara medlem i en förening ansluten till Svenska Pistolskytteförbundet (SPSF).</li><li data-v-22c77eeb>Alla tävlingar och skjutträningar inom ramen för TTS, på internationell nivå, nationell nivå, regional nivå samt lokal nivå, ska genomföras enligt detta regelverk. Utöver detta regelverk tillkommer tvingande styrningar från den centrala SRA-kommittén och SPSF-förbundsstyrelse.</li><li data-v-22c77eeb>Den centrala SRA-kommittén och SPSF-förbundsstyrelse upprätthåller och utvecklar tekniska bilagor för detaljerade tolkningar och nedbrytningar av regelverket.</li></ul></div><a id="1.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>1.2 Tävlingar</h3><p id="1.2.1" data-v-22c77eeb><a href="#1.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.1</span></a> En tävling är uppdelad i ett antal skjutstationer (stages). Vid en skjutstation kan ett eller flera eldhandvapen brukas. </p><p id="1.2.2" data-v-22c77eeb><a href="#1.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.2</span></a> En tävling kan anordnas för en enskild typ av eldhandvapen eller en kombination av flera, t.ex. karbin och pistol. </p><p id="1.2.3" data-v-22c77eeb><a href="#1.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.3</span></a> En tävlingsinbjudan måste ange vilken eller vilka typer av eldhandvapen som kommer nyttjas i tävlingen samt antal skjutstationer (stages), minsta antal skott som åtgår för att genomföra tävlingen, tävlingens längsta skjutavstånd och andra eventuella särskilda förhållanden. </p><p id="1.2.4" data-v-22c77eeb><a href="#1.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.4</span></a> Internationellt finns tre divisioner inom SRA: Open, Standard samt Militär division. Den tävlandes brukade eldhandvapen och övrig buren utrustning styr vilken division som den tävlande får delta i. </p><p class="se-extension" data-v-22c77eeb> I Sverige finns tre divisioner inom TTS: Militär standard 5,56, Militär standard 7,62 samt Öppen (Open) division. </p><p id="1.2.5" data-v-22c77eeb><a href="#1.2.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.5</span></a> I tillägg till ovan nämnda divisioner förekommer även ett antal klasser inom divisionerna: </p><ul data-v-22c77eeb><li data-v-22c77eeb>Värnpliktsklass, nyttjas för värnpliktig personal under Grundutbildning (gäller i Sverige).</li><li data-v-22c77eeb>Seniorklass (50+)</li><li data-v-22c77eeb>Supersenior (60+)</li><li data-v-22c77eeb>Damklass</li></ul><p data-v-22c77eeb> I respektive seniorklass ska den tävlande under tävlingsåret fylla minst 50 respektive 60 år. Vid nationella och internationella tävlingar ska poängräkning för dessa separata klasser genomföras om det är minst 5 anmälda deltagare ur respektive klass. Senior och Supersenior kan vid tävling slås ihop till en klass om deltagarantalet underskrider 3 deltagare per klass. Tävlingsarrangör kan dela ut särskilda pris för dessa klasser. </p><p id="1.2.6" data-v-22c77eeb><a href="#1.2.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.6</span></a> I inledningsskedet av en tävling kan tävlingsledningen hålla en gemensam genomgång för både de tävlande och funktionärer. Vid nationella och internationella mästerskap ska en sådan genomgång hållas. Genomgången avhandlar generella frågor gällande tävlingen och ska klargöra eventuella frågeställningar kopplade till ”Riktlinjer för tävlingar” och beskriva lokala förhållanden såsom hur personal kommer att röra sig på tävlingsområdet samt andra faktorer som påverkar tävlingens genomförande. </p><p id="1.2.7" data-v-22c77eeb><a href="#1.2.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.7</span></a> Tävling är slutförd när samtliga tävlande har genomfört alla skjutstationer (stager), alla protester och klagomål är behandlade och avgjorda samt att sluttid för resultatöversyn av sista skjutstationen har passerats. </p><p id="1.2.8" data-v-22c77eeb><a href="#1.2.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.8</span></a> Tävlingsområdet är skjutbana eller skjutfält där SRA/TTS-tävling genomförs. Om inte annat anges av tävlingsledningen består tävlingsområdet av skjutstationer (stager), registrering och visitationsplats, skjutstationernas uppehållsområde, hanteringsområde för eldhandvapen samt säkra framryckningsvägar mellan ovan nämnda platser. </p><p id="1.2.9" data-v-22c77eeb><a href="#1.2.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.2.9</span></a> Tävlingar kan vara inriktade mot ett särskilt tema där tyngdpunkten ligger på ett särskilt ämne eller fördjupning i syfte att ge tävlingen en särskild anda eller omväxling. Dessa ämnen eller fördjupningar får dock ej vara så avgränsande till sin natur att den tävlandes innehavda utrustning blir otillbörligt begränsande. Exempelvis får ej tävlingar vara avgränsande till en specifik modell eller tillverkare av utrustning. Om tävling anordnas med särskilt tema ska detta tydligt anges i tävlingsinbjudan. </p><a id="1.3" data-v-22c77eeb></a><h3 data-v-22c77eeb>1.3 Skjutstationer (Stage)</h3><p id="1.3.1" data-v-22c77eeb><a href="#1.3.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.1</span></a> En skjutstation består av ett särskilt poängsatt och tidtaget skjutmoment som genomförs enligt en stationsbeskrivning (Stage Description). Varje tävling bör bestå av ett antal unika skjutstationer. </p><p id="1.3.2" data-v-22c77eeb><a href="#1.3.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.2</span></a> De individuella skjutstationernas resultat sammanställs till ett slutresultat som resulterar i att en tävlingsvinnare kan utses enligt paragraf 6. </p><p id="1.3.3" data-v-22c77eeb><a href="#1.3.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.3</span></a> En skjutstation innehåller alltid minst ett skjutmoment. Utöver detta kan skjutstationen innehålla andra prövningar, som t.ex. kast med blind handgranat. En skjutstation kan också innehålla förflyttningar och ställningsväxlingar. Moment som inte är direkta skjutmoment får inte ha en avgörande poängsättning för skjutstationen då den tävlandes skjutskicklighet ska vara tongivande för resultatet vid respektive skjutstation. </p><p id="1.3.4" data-v-22c77eeb><a href="#1.3.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.4</span></a> En skjutstation bör planeras så att krav på hastighet och träffsäkerhet vid genomförandet balanseras lika enligt principen tillräcklig verkan så snart som möjligt (TVSSSM). </p><p id="1.3.5" data-v-22c77eeb><a href="#1.3.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.5</span></a> Skjutstationer ska vara varierande, realistiska och lämpliga för skjutstationens angivna eldhandvapentyp samt ha relevanta övriga moment. Planeringsstyrningar för skjutstationsuppbyggnad återfinns i Riktlinjer för tävling. </p><p id="1.3.6" data-v-22c77eeb><a href="#1.3.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.6</span></a> TTS / SRA tävlingar genomförs i fri stil. Tävlingsledningen får inte styra den tävlandes val av skjutställning eller skjutplats vid genomförandet av en skjutstation. Dock får skjutstationen byggas upp så att den tävlande genom skjutstationens uppbyggnad tvingas till en specifik skjutplats eller skjutställning. Detta sker genom t.ex. att man begränsar den tävlandes valfrihet genom byggnation av hinder eller andra fysiska begränsningar. De tävlande måste få genomföra skjutstationen med valfrihet kopplat till praxis om när och hur ett specifikt mål kan bekämpas. </p><p id="1.3.7" data-v-22c77eeb><a href="#1.3.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.7</span></a> Ett tvingande magasinsbyte kan läggas in i en skjutstation mellan första och sista skott. Det tvingande magasinsbytet sker då när den tävlande så själv väljer att göra det. </p><p id="1.3.8" data-v-22c77eeb><a href="#1.3.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.8</span></a> Den tävlande får ha valfri mängd magasin buret på sin person eller på plats angiven i stationsbeskrivningen. Det är inte tillåtet att lägga in krav på magasinspåfyllnad under en skjutstation. Dock får en stationsbeskrivning ange en specifik mängd patroner i den tävlandes magasin och/eller vapen när genomförandet vid skjutstationen påbörjas. </p><p id="1.3.9" data-v-22c77eeb><a href="#1.3.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.9</span></a> Hela eller delar av skjutstationer får ha styrningar för om skjuthand eller stödhand ska nyttjas vid genomförandet. </p><p id="1.3.10" data-v-22c77eeb><a href="#1.3.10" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.10</span></a> En skjutstations uppbyggnad får endast ändras under pågående tävling om säkerheten kräver det. Om en skjutstation ändras under tävlingens gång på ett sätt som inte kan anses som försumbart så skall samtliga tävlande som redan hunnit genomföra skjutstationen, genomföra den igen genom en omskjutning, även kallad re-shoot. Om omskjutning inte är möjlig att genomföra p.g.a. yttre omständigheter eller liknande så ska den skjutstationen med tillhörande resultat strykas ur slutresultatet. Ett sådant beslut tas av Tävlingsledare (Match Director). </p><p id="1.3.11" data-v-22c77eeb><a href="#1.3.11" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.11</span></a> Minsta antal skott vid en hageltävling får inte överstiga 15 skott förutom vid särskilda tävlingar med särskilt tema som kräver detta. </p><p id="1.3.12" data-v-22c77eeb><a href="#1.3.12" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.12</span></a> Tävlande ska inte tvingas till att skjuta med enhandsvapen på papperstavla motsvarande IPSC metric där avståndet överstiger 25 m eller liknande reaktiva mål där avståndet överstiger 50 m. Mindre mål ska placeras hitom ovan nämnda avstånd. </p><p id="1.3.13" class="se-extension" data-v-22c77eeb><a href="#1.3.13" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.3.13</span></a> Vid samtliga gevärs-/karbintävlingar i Sverige skall 30 % av dukade mål vara på ett skjutavstånd överstigande 150 m. </p><a id="1.4" data-v-22c77eeb></a><h3 data-v-22c77eeb>1.4 Skjutstationers uppbyggnad</h3><p id="1.4.1" data-v-22c77eeb><a href="#1.4.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.4.1</span></a> Arrangören kan på en skjutstation uppföra konstruktioner som leder eller begränsar skyttens rörelser och skjutning, exempelvis barrikader, tunnlar, begränsningslinjer och spärrlinjer. </p><p id="1.4.2" data-v-22c77eeb><a href="#1.4.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.4.2</span></a> En begränsningslinje används för att styra den tävlande till att röra sig inom skjutområdet. Begränsningslinjerna skall vara så konstruerade att de ej kan förväxlas med markeringar för pekvinklar eller skjutgränser. Den tävlande får ej passera en begränsningslinje under skjutstationens genomförande. Passage av sådan linje innebär procedurfel och bestraffas enligt 6.6.2. </p><p id="1.4.3" data-v-22c77eeb><a href="#1.4.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.4.3</span></a> Spärrlinjer kan nyttjas för att tvinga skytten att skjuta från en plats bakom ett fysiskt skydd. De kan placeras i valfri vinkel bakom ett hinder/skydd. En spärrlinje måste vara minst en (1) meter i längd, och såvida inget annat angivits i stationsbeskrivningen så anses de löpa oändligt i längdriktningen. Spärrlinjer nyttjas för att representera nyttjandet av skydd under skjutning. En spärrlinje skall vara säkert fastsatt så att dess placering inte ändras mellan genomföranden under tävlingen. </p><p id="1.4.4" data-v-22c77eeb><a href="#1.4.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.4.4</span></a> En tunnel kan vara ett heltäckande rör eller en Tiitinen- (Cooper-) tunnel vars tak består av ej fastsatta käppar/pinnar. En Tiitinen-tunnel representerar en situation i vilken skytten behöver röra sig i låga ställningar. </p><p id="1.4.5" data-v-22c77eeb><a href="#1.4.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.4.5</span></a> I de fall det inte är möjligt att bygga skjutstationskonstruktioner med anledning av skjutbanebestämmelser, begränsad tid eller brist på byggmaterial m.m. så är det tillåtet att endast använda spärrlinjer och begränsningslinjer för att hindra beskjutning av mål från platser utanför förbjudet område. Denna regel gäller endast lokala tävlingar eller tävlingar på lägre nivå. Ytterligare information om krav på skjutstationskonstruktioner och rekommenderade konstruktioner finns i dokumentet ”Riktlinjer för tävlingar”. </p><a id="1.5" data-v-22c77eeb></a><h3 data-v-22c77eeb>1.5 Tidtagning</h3><p id="1.5.1" data-v-22c77eeb><a href="#1.5.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.5.1</span></a> Tidtagning utförs med kommersiella tidtagare (skjuttimer) eller andra lämpliga och pålitliga instrument. Tidtagaren måste avge en startsignal och registrera skjutna skott och tid. Det är inte nödvändigt att varje skott registreras utom det sista, såvida det inte krävs för poänggivningen, exempelvis vid ”begränsade skott”. </p><p id="1.5.2" data-v-22c77eeb><a href="#1.5.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.5.2</span></a> Efter att det sista skottet har avlossats skall domaren säkerställa att ljud som avges vid patron ur på vapnet, såsom mantelrörelse eller blindavfyring, inte registreras som ett skott i tidtagarinstrumentet. </p><p id="1.5.3" data-v-22c77eeb><a href="#1.5.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>1.5.3</span></a> Om en signaturdämpare förhindrar att skotten registreras av tidtagaren så skall domaren fastställa tillvägagångssätt för att det sista skottet skall registreras. Provskjutning enligt principen 4.1.10 må genomföras. Exempelvis kan domaren knacka på mikrofonen på skjuttimern för att tiden skall registreras. </p><hr data-v-22c77eeb><a id="2" data-v-22c77eeb></a><h2 data-v-22c77eeb>2. Tävlingsledning</h2><a id="2.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.1 Tävlingskommissarie (Supervisor)</h3><p id="2.1.1" data-v-22c77eeb><a href="#2.1.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.1.1</span></a> En tävlingskommissarie som är godkänd av ansvarig organisation skall utses för nationella och internationella mästerskap. Tävlingskommissarien skall vara förordnad instruktör eller överdomare inom TTS/SRA. </p><a id="2.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.2 Tävlingsledare (Match Director)</h3><p id="2.2.1" data-v-22c77eeb><a href="#2.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.2.1</span></a> En tävlingsledare (MD) måste vara förordnad som TTS-domare. </p><p id="2.2.2" data-v-22c77eeb><a href="#2.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.2.2</span></a> Tävlingsledaren (MD) är övergripande ansvarig för tävlingen och ansvarar för dess administration, tidtagning, skjutstationsmaterial samt mat, sjukvård, övriga tjänster och säkerheten. </p><p id="2.2.3" data-v-22c77eeb><a href="#2.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.2.3</span></a> Tävlingsledaren (MD) är den yttersta auktoriteten i alla uppräknade avseenden med undantag för protesthantering. </p><p id="2.2.4" data-v-22c77eeb><a href="#2.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.2.4</span></a> Tävlingsledaren (MD) är ordförande i tävlingsjuryn (arbitration committee) utan egen rösträtt. </p><p id="2.2.5" data-v-22c77eeb><a href="#2.2.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.2.5</span></a> Vid klubbtävlingar och lokala tävlingar kan tävlingsledaren (MD) även fullgöra andra roller, t.ex. banchef (RM) och domare (RO). </p><a id="2.3" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.3 Banchef (Range Master)</h3><p id="2.3.1" data-v-22c77eeb><a href="#2.3.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.3.1</span></a> Banchefen (RM) skall vara en förordnad TTS-domare. Banchef (RM) utses av tävlingsledaren (MD). </p><p id="2.3.2" data-v-22c77eeb><a href="#2.3.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.3.2</span></a> Banchefens (RM) åligganden: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Ansvarar för skjutstationernas säkerhet och deras säkerhetsmässiga planering.</li><li data-v-22c77eeb>Övervakar att alla regler och bestämmelser åtföljs och ansvarar för att utbilda och handleda skjutstationernas funktionärer.</li><li data-v-22c77eeb>Alla diskvalificeringar, protester och säkerhetsförseelser skall meddelas banchefen (RM).</li><li data-v-22c77eeb>Arbetsleder skjutstationsfunktionärer under tävlingen.</li><li data-v-22c77eeb>Ansvarar för att alla tävlingsregler följs och tillämpas lika för alla tävlande.</li></ol><p id="2.3.3" data-v-22c77eeb><a href="#2.3.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.3.3</span></a> Vid klubbtävlingar och lokala tävlingar så kan banchefen (RM) även fullgöra andra roller, t.ex. domare (RO). </p><a id="2.4" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.4 Tävlingssekreterare (Statisticals Officer)</h3><p id="2.4.1" data-v-22c77eeb><a href="#2.4.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.4.1</span></a> Tävlingssekreteraren (SO) är den funktionär som ansvarar för att samla in, sortera och förvara tävlingsprotokoll såväl samt producera, verifiera och publicera preliminära och slutliga tävlingsresultat och statistik. </p><p id="2.4.2" data-v-22c77eeb><a href="#2.4.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.4.2</span></a> Denne säkerställer att alla ofullständiga eller felaktiga protokollföringar omedelbart verifieras hos banchefen (RM). Tävlingssekreteraren (SO) är direkt underställd banchefen (RM). </p><p id="2.4.3" data-v-22c77eeb><a href="#2.4.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.4.3</span></a> Tävlingssekreteraren (SO) vid nationella och internationella mästerskap skall vara en förordnad TTS-domare (RO). </p><a id="2.5" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.5 Domare (Range Officer)</h3><p id="2.5.1" data-v-22c77eeb><a href="#2.5.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.5.1</span></a> En domare (RO) vid en TTS-tävling skall ha genomfört en godkänd utbildning till domare för TTS/SRA och inneha förordnande som sådan. </p><p id="2.5.2" data-v-22c77eeb><a href="#2.5.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.5.2</span></a> Domarens (RO) åligganden: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Ansvarar för skjutstationens säkerhet.</li><li data-v-22c77eeb>Håller stationsgenomgång.</li><li data-v-22c77eeb>Övervakar den tävlandes åtlydnad av stationsgenomgången och bevakar den tävlandes säkerhetsmässiga uppträdande.</li><li data-v-22c77eeb>Ger kommandon på skjutstation.</li><li data-v-22c77eeb>Kungör tid och poäng, och tillser att dessa protokollförs. Domaren (RO) kan biträdas av en protokollförare (SK).</li><li data-v-22c77eeb>Bevakar skjutstationsdukningens och målens skick.</li><li data-v-22c77eeb>Ansvarar för uppbyggnad och allmän ordning vid sin skjutstation och dess uppehållsområde och hanteringsområde.</li></ol><p id="2.5.3" data-v-22c77eeb><a href="#2.5.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.5.3</span></a> Domaren (RO) har beslutsrätt över all personal vid sin skjutstation. </p><p id="2.5.4" data-v-22c77eeb><a href="#2.5.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.5.4</span></a> Domaren (RO) är en tävlingsfunktionär som är förordnad som TTS-domare. Då en skjutstation har flera domare (RO), ska en utses till att föra befälet och ansvara för skjutstationen. </p><a id="2.6" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.6 Protokollförare (Score Keeper)</h3><p id="2.6.1" data-v-22c77eeb><a href="#2.6.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.6.1</span></a> Protokollföraren (SK) ska ha kompetens att nyttja poängräkningssystemet. Protokollförarens åligganden kan kombineras med andra roller förutom vid nationella och internationella mästerskap. </p><p id="2.6.2" data-v-22c77eeb><a href="#2.6.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.6.2</span></a> Protokollförarens (SK) åligganden: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Fastställer skjutordningen, om så krävs.</li><li data-v-22c77eeb>Hanterar poängräkningssystemet för skjutstationen.</li><li data-v-22c77eeb>Dokumenterar tydligt skjutstationens resultat i poängräkningssystemet och säkerställer att protokollen signeras av domaren (RO) och den tävlande.</li><li data-v-22c77eeb>Kungör nästa tävlande och tävlande därnäst.</li></ol><a id="2.7" data-v-22c77eeb></a><h3 data-v-22c77eeb>2.7 Övrig tävlingsorganisation</h3><p id="2.7.1" data-v-22c77eeb><a href="#2.7.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>2.7.1</span></a> I Riktlinjer för tävlingar listas ytterligare information om tävlingsfunktionärer som kan behövas för att arrangera större tävlingar såsom nationella mästerskap. Det dokumentet anger i vissa fall funktionärers åligganden ytterligare i detalj. </p><hr data-v-22c77eeb><a id="3" data-v-22c77eeb></a><h2 data-v-22c77eeb>3. Säkerhetsregler</h2><a id="3.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>3.1 Generella säkerhetsregler gällande eldhandvapen</h3><p data-v-22c77eeb>De grundläggande säkerhetsreglerna är:</p><ul data-v-22c77eeb><li data-v-22c77eeb>Hantera alltid vapen som om de är laddade!</li><li data-v-22c77eeb>Rikta inte mynningen mot något som du inte är beredd att bekämpa!</li><li data-v-22c77eeb>Håll fingret från avtryckaren tills vapnet riktas mot målet!</li><li data-v-22c77eeb>Var säker på ditt mål och dess omgivning!</li></ul><a id="3.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>3.2 Övergripande säkerhet</h3><p id="3.2.1" data-v-22c77eeb><a href="#3.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.2.1</span></a> Tävlingsledaren ska tillsammans med banchefen (RM) tillse att samtliga stationsbeskrivningar samt skjutstationer är utformade på ett sådant sätt att de tävlandes säkerhet inte äventyras. Likaså skall tävlingsledare (MD) och banchef (RO) tillse att stationsbeskrivningarna inte tvingar att de tävlande bryter mot säkerhetsreglerna för att kunna genomföra skjutstationen. </p><p id="3.2.2" data-v-22c77eeb><a href="#3.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.2.2</span></a> Tydligt utmärkta och definierade säkra uppehållsplatser för tävlande, besökare och funktionärer ska finnas. </p><p id="3.2.3" data-v-22c77eeb><a href="#3.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.2.3</span></a> En tävlande kan av en domare (RO) diskvalificeras från fortsatt deltagande i tävlingen på grund av den tävlandes bristande säkerhet. Domaren (RO) ska vid ett sådant tillfälle snarast meddela banchefen (RM) som säkerställer att diskvalificeringsgrunden är rätt och enligt reglerna och därefter verifierar om den tävlande ska diskvalificeras eller ej. </p><p id="3.2.4" data-v-22c77eeb><a href="#3.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.2.4</span></a> Tävlingsledaren (MD) kan avvisa och diskvalificera en tävlande från pågående tävling på grund av bristande sportmannaskap eller brott mot gällande säkerhetsregler. </p><p id="3.2.5" data-v-22c77eeb><a href="#3.2.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.2.5</span></a> Samtliga närvarande vid en tävling ska använda hörselskydd och skyddsglasögon under all pågående skjutning. En domare (RO) ska tillse att all personal vid sin skjutstation har applicerat hörselskydd och skyddsglasögon innan denne påbörjar skjutning vid sin skjutstation. Om domaren (RO) upptäcker att den tävlandes hörselskydd och/eller skyddsglasögon inte är korrekt applicerade under pågående skjutning ska skjutningen omedelbart avbrytas och skjutstationen ska efter att ovanstående är åtgärdat, skjutas om (re-shoot). Om den tävlande oavsiktligt tappar hörselskydd och/eller skyddsglasögon skall den tävlande omedelbart åtgärda detta eller avbryta skjutstationen med vapnet i skjutriktningen och meddela domaren (RO) om vad som har inträffat. Om så har skett, ska skjutstationen skjutas om. Om den tävlande genom medveten handling lösgör burna hörselskydd och/eller skyddsglasögon i syfte att få till en omskjutning så diskvalificeras den tävlande på grund av bristande sportmannaskap. </p><a id="3.3" data-v-22c77eeb></a><h3 data-v-22c77eeb>3.3 Osäker hantering av eldhandvapen</h3><p data-v-22c77eeb><em data-v-22c77eeb>Överträdelser mot nedan följande säkerhetsregler leder till omedelbar diskvalificering från tävling.</em></p><h4 data-v-22c77eeb>Tävlingsområde (Match area)</h4><p id="3.3.1" data-v-22c77eeb><a href="#3.3.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.1</span></a> När ett eldhandvapen befinner sig utanför en skjutstation ska vapnet vara oladdat, tomt på ammunition och slackat. Om möjligt ska vapnet också vara säkrat. Användning av ett monterat kontrolldon, kammarflagga eller säkerhetspropp är tillåtet. </p><p id="3.3.2" data-v-22c77eeb><a href="#3.3.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.2</span></a> Ett eldhandvapen är laddat om: </p><ul data-v-22c77eeb><li data-v-22c77eeb>Vapnet har en patron i patronläget.</li><li data-v-22c77eeb>Mekanismen är i öppet/tillbakafört läge och ett magasin innehållande ammunition är applicerat i magasinsstyrningen.</li></ul><p id="3.3.3" data-v-22c77eeb><a href="#3.3.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.3</span></a> Utanför skjutstation ska enhandsvapen endast transporteras antingen buret i ett hölster eller i en för ändamålet lämplig låda eller fodral. Tvåhandsvapen såsom gevär, karbin, hagelvapen transporteras i vapenrem med pipan antingen pekandes uppåt alternativt neråt om inte vapnet transporteras i för ändamålet lämplig låda eller fodral. Skjutfingret ska under all tid utanför skjutstation vara från avtryckaren. </p><p id="3.3.4" data-v-22c77eeb><a href="#3.3.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.4</span></a> Om ett eldhandvapen av någon anledning tappas utanför skjutstation får endast domare (RO) plocka upp vapnet. När så skett transporterar domaren (RO) vapnet till skjutstation, ej hanteringsområdet, där vapnet kontrolleras att det uppfyller kriterierna under punkten 3.3.1. Den tävlande kommer ej att diskvalificeras under förutsättning att inga överträdelser mot säkerheten skett. </p><p id="3.3.5" data-v-22c77eeb><a href="#3.3.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.5</span></a> Utanför skjutstation får ett eldhandvapen endast hanteras i ett särskilt definierat och utmärkt hanteringsområde (Safety Area). Hanteringsområdet ska ha utmärkta pekvinklar inom vilka vapnets pipa alltid skall riktas vid hantering (ofarlig riktning). Följande är ansett att hantera ett eldhandvapen: ihop-/isärtagning, samtliga eldhandgrepp, öva drag, inta skjutställningar/greppa pistolgreppet. </p><p id="3.3.6" data-v-22c77eeb><a href="#3.3.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.6</span></a> Hanteringsområdet (Safety Area) måste placeras vid lämplig plats nära skjutstation med tydligt märkta instruktioner. Hanteringsområdets gränser och vinklar ska vara tydligt definierade och utmärkta. Den tävlande nyttjar hanteringsområdet för följande: </p><ul data-v-22c77eeb><li data-v-22c77eeb>Packning och uppackning samt hölstring av oladdade eldhandvapen.</li><li data-v-22c77eeb>Torrövning med blindavfyrning samt för att öva drag med oladdade eldhandvapen.</li><li data-v-22c77eeb>Torrövning av magasinsbyte och omladdning med tomma magasin.</li><li data-v-22c77eeb>Visitation, vård och reparation av eldhandvapen och tillbehör.</li></ul><p data-v-22c77eeb> Vid all vapenhantering i ett hanteringsområde ska vapnets pipa riktas innanför utmärkta pekvinklar. Blind ammunition, fyllda magasin, snabbladdare, ammunitionslådor eller lös ammunition får under inga omständigheter hanteras i hanteringsområdet. Ej heller får någon ammunition där fästas på eller i vapnet. </p><p id="3.3.7" data-v-22c77eeb><a href="#3.3.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.7</span></a> En registrerings- och visitationsplats för eldhandvapen (Firearm compliance Inspection Area) upprättas av tävlingsledningen. Vid en registrerings- och visitationsplats för eldhandvapen får endast funktionärer hantera eldhandvapen om inte andra särskilda styrningar för detta har givits av tävlingsledningen. Vid denna plats gäller samma regler som under punkten 3.3.6. </p><h4 data-v-22c77eeb>Skjutstation / stage area (Stage)</h4><p id="3.3.8" data-v-22c77eeb><a href="#3.3.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.8</span></a> Ett eldhandvapen får endast laddas och hanteras efter instruktioner från skjutstationens domare (RO). </p><p id="3.3.8.1" data-v-22c77eeb><a href="#3.3.8.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.8.1</span></a> En tävlande blir inte diskvalificerad om denne vid kommando ”magasin i” (lipas kiinnitä) också laddar vapnet genom att göra mekanismrörelse. Om så sker ger domaren (RO) kommando ”patron ur, blindavfyra”. Efter så skett intar den tävlande till startposition och inväntar domarens kommandon för fortsatt verksamhet. </p><p id="3.3.8.2" data-v-22c77eeb><a href="#3.3.8.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.8.2</span></a> En tävlande blir ej diskvalificerad om denne startar sitt genomförande på grund av felaktig given startsignal. </p><p id="3.3.9" data-v-22c77eeb><a href="#3.3.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.9</span></a> En laddad pistol eller revolver får aldrig via stationsbeskrivning (stage description) tvingas till hölstring under genomförande av en skjutstation. Om den tävlande på eget bevåg väljer att hölstra en laddad pistol eller revolver under ett genomförande får detta endast ske om vapnet är säkrat. En pistol eller revolver som saknar yttre säkring får endast hölstras om mekanismen är slackad och/eller loppet är tomt. Pistol med avtryckarsäkring som t.ex. Glock räknas som säkrad när fingret är utanför varbygeln. </p><p id="3.3.10" data-v-22c77eeb><a href="#3.3.10" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.10</span></a> Under skjutmomentets genomförande ska den tävlandes eldhandvapen alltid vara riktad med pipan innanför skjutstationens pekvinklar. En pistol eller revolvers pipa ska alltid vara riktad innanför pekvinklarna vid hölstring, drag och buren laddad i hölster (detta gäller oavsett startposition) alternativt vara riktad mot en punkt maximalt två meter framför den tävlande i skjutriktningen. </p><p id="3.3.11" data-v-22c77eeb><a href="#3.3.11" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.11</span></a> Ett eldhandvapens mynning får aldrig vara riktat mot den tävlande själv. Detta gäller ej vid hölstrat vapen, under hölstring eller drag när vapnets pipa befinner sig i hölstret och den tävlandes hantering av ett riktat vapen mot sig själv kan anses som försumbar. </p><p id="3.3.12" data-v-22c77eeb><a href="#3.3.12" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.12</span></a> Fingret ska vara utanför varbygel vid drag, hölstring, magasinsbyte, omladdning och vid åtgärdande av eldavbrott. Om fingret måste vara innanför varbygeln vid åtgärdande av eldavbrott ska detta kommuniceras till domare (RO) som då beviljar eller avslår innan åtgärden vidtas. </p><p id="3.3.13" data-v-22c77eeb><a href="#3.3.13" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.13</span></a> Skjutfingret ska vara utanför varbygeln om den tävlande tar mer än ett steg och/eller byter skjutställning om detta inte sker i samband med skjutning eller siktande mot för den tävlande synliga mål. Att kontrollerat rikta ett eldhandvapen mot för den tävlande synliga mål är att betrakta som att sikta. </p><p id="3.3.14" data-v-22c77eeb><a href="#3.3.14" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.14</span></a> Den tävlande får endast släppa fysisk kontakt med sitt eldhandvapen enligt beskrivning i stationsbeskrivningen eller om situationen så kräver och då endast när vapnet är säkrat och det placeras på marken eller annat stadigt underlag på ett kontrollerat sätt. Om så skett får den tävlande ej röra sig längre bort än en meter ifrån eldhandvapnet. Om den tävlande släpper fysisk kontakt med sitt eldhandvapen på annat sätt än ovan beskrivet, avbryter domaren (RO) genomförandet och genomför patron ur på eldhandvapnet. Om den tävlandes fysiska kontakt med ett för skjutstationen buret men ej nyttjat eldhandvapen sker på ett kontrollerat sätt ska detta inte vara grund för av domaren (RO) avbrutet genomförande och/eller diskvalifikation. </p><p id="3.3.15" data-v-22c77eeb><a href="#3.3.15" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.15</span></a> En stationsbeskrivning får innehållande tvingande regel att gevär, karbin och hagelvapen ska säkras vid all förflyttning och ställningsväxling om säkerheten på platsen så kräver. </p><p id="3.3.16" data-v-22c77eeb><a href="#3.3.16" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.16</span></a> Automateld är inte tillåtet om inte annat specifikt anges aktuell stationsbeskrivning. </p><p id="3.3.17" data-v-22c77eeb><a href="#3.3.17" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.17</span></a> Om den tävlande skjuter vådaskott ska domaren (RO) omedelbart avbryta genomförandet och den tävlande är automatiskt diskvalificerad från tävlingen. </p><p id="3.3.18" data-v-22c77eeb><a href="#3.3.18" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.18</span></a> Inom TTS/SRA utgörs ett vådaskott av följande: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Alla skott som avfyras av den tävlande innan startsignal eller efter att ”Patron ur, spänn upp för visitation” (liikkuvat taakse) är kommenderat.</li><li data-v-22c77eeb>Alla skott som avfyras utanför angivna skjutgränser.</li><li data-v-22c77eeb>Alla skott som träffar marken närmare än 3 meter från den tävlande om inte annat anges i stationsbeskrivningen.</li><li data-v-22c77eeb>Alla skjutna skott som uppenbart inte var avfyrade avsiktligt.</li></ol><p id="3.3.19" data-v-22c77eeb><a href="#3.3.19" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.19</span></a> Ett vådaskott som avfyras innanför skjutgränserna leder inte automatiskt till diskvalificering av den tävlande om vådaskottet kan härledas till ett verifierbart tekniskt problem med vapnet. Om så sker så tilldelas den tävlande noll poäng för aktuell skjutstation och den tävlande ska innan fortsatt tävlande, utan dröjsmål reparera sitt vapen eller avfärda det från aktuell tävling om så ej kan ske. Ett sådant vådaskott ske genast rapporteras till banchefen (RM). Vid upprepat vådaskott under samma förutsättningar av samma tävlande ska denne diskvalificeras från tävlingen. </p><p id="3.3.20" data-v-22c77eeb><a href="#3.3.20" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.3.20</span></a> Om den tävlande nyttjar en för tävlingen otillåten ammunitionstyp, räknas detta som en överträdelse mot gällande säkerhetsregler och den tävlande diskvalificeras från tävlingen. </p><a id="3.4" data-v-22c77eeb></a><h3 data-v-22c77eeb>3.4 Pekvinklar och skjutgränser (Sectors)</h3><p id="3.4.1" data-v-22c77eeb><a href="#3.4.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.1</span></a> Alla skjutstationer ska ha tydligt utmärkta pekvinklar och skjutgränser. Dessa ska vara tydligt markerade så att både den tävlande och domaren (RO) kan försäkra sig om att skjutstationen kan genomföras på ett säkert sätt. Dessa pekvinklar och skjutgränser berör inte vapen som är att betrakta som för skjutstationen burna men ej nyttjade. </p><p id="3.4.2" data-v-22c77eeb><a href="#3.4.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.2</span></a> Pekvinklarna utgör den begränsning inom vilken ett eldhandvapens mynning alltid ska peka inom vid genomförandet av en skjutstation. </p><p id="3.4.3" data-v-22c77eeb><a href="#3.4.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.3</span></a> I vertikal riktning är pekvinkeln 180 grader om inte den fysiska miljön hindrar detta. </p><p id="3.4.4" data-v-22c77eeb><a href="#3.4.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.4</span></a> I horisontal riktning är pekvinklarna 180 grader om inte annat fastställs i stationsbeskrivningen. </p><p id="3.4.5" data-v-22c77eeb><a href="#3.4.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.5</span></a> Skjutgränserna är det definierade området inom vilket alla skott ska avfyras vid en skjutstation. Skjutgränserna är alltid innanför pekvinklarna. </p><p id="3.4.6" data-v-22c77eeb><a href="#3.4.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>3.4.6</span></a> Skjutgränsen i höjd är normalt sett nedanför toppen på målvallen/målväggen om inte annat är beskrivet i stationsbeskrivningen. Skjutgräns höger och vänster ska vara tydligt definierade och utmärkta. </p><hr data-v-22c77eeb><a id="4" data-v-22c77eeb></a><h2 data-v-22c77eeb>4. Vid Skjutstation (Stage)</h2><a id="4.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>4.1 Övergripande</h3><p id="4.1.1" data-v-22c77eeb><a href="#4.1.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.1</span></a> Den tävlande ska följa alla styrningar givna av funktionärer, förutsatt att dessa styrningar faller innanför ramen för gällande säkerhetsregler. </p><p id="4.1.2" data-v-22c77eeb><a href="#4.1.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.2</span></a> Vid tävlingsverksamhet i Sverige nyttjas i huvudsak svenska och i Finland, finska. Vid internationella tävlingar nyttjas engelska. Tävlingsledaren (MD) beslutar vilket språk som ska gälla vid aktuell tävling. Domare (RO) beslutar om vilket språk denne nyttjar för att på bästa sätt ge kommandon till den tävlande. Alla kommandon ska artikuleras och ges med tydlig stämma. </p><p id="4.1.3" data-v-22c77eeb><a href="#4.1.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.3</span></a> Före genomförandet av skjutstation påbörjas ska en stationsbeskrivning ges till de tävlande. Stationsbeskrivningen ska vara tydlig och innehålla all nödvändig information för att den tävlande ska kunna genomföra skjutstationen på ett säkert sätt. Den muntliga stationsbeskrivningen ska minst innehålla: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Vid skjutstationen nyttjade eldhandvapen.</li><li data-v-22c77eeb>Antal mål, målbeskrivning inklusive mål som ej ska bekämpas samt poängräkning.</li><li data-v-22c77eeb>Avstånd till närmsta och bortersta mål.</li><li data-v-22c77eeb>Minimal ammunitionsåtgång.</li><li data-v-22c77eeb>Maxpoäng.</li><li data-v-22c77eeb>Pekvinklar och skjutgränser.</li><li data-v-22c77eeb>Placering av hanterings- och uppehållsområde.</li><li data-v-22c77eeb>Spärr- och begränsningslinjer.</li><li data-v-22c77eeb>Tillåten tid för att torröva skjutstationen (walktrough) efter att stationsbeskrivning är given.</li></ol><p data-v-22c77eeb>Utöver detta kan en stationsbeskrivning vid behov innehålla följande information:</p><ol type="a" start="10" data-v-22c77eeb><li data-v-22c77eeb>Särskilda ammunitionsbegränsningar.</li><li data-v-22c77eeb>Poängräkning för ej skjutande moment.</li><li data-v-22c77eeb>Policy för poäng och tidräkning om annan än obegränsad (unlimited) gäller.</li><li data-v-22c77eeb>Hur tidräkning går till om det avviker från tidräkning från startsignal till sista skott.</li><li data-v-22c77eeb>Maximal tillåtna tid för genomförandet av skjutstationen.</li><li data-v-22c77eeb>Startposition om annan än stående grundställning.</li><li data-v-22c77eeb>Vapnets och övrig utrustnings status vid start.</li><li data-v-22c77eeb>Särskilda begränsningar.</li><li data-v-22c77eeb>Särskilda moment som ger straffpoäng.</li><li data-v-22c77eeb>Särskilda säkerhetsrelaterade bestämmelser för skjutstationen.</li></ol><p data-v-22c77eeb>Den skriftliga stationsbeskrivningen kan också innehålla följande:</p><ol type="a" start="20" data-v-22c77eeb><li data-v-22c77eeb>Skjutstationens scenario.</li></ol><p id="4.1.4" data-v-22c77eeb><a href="#4.1.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.4</span></a> Domaren (RO) måste alltid säkerställa att den tävlande har förstått de förhållanden som återgivits i stationsbeskrivningen. Om domaren (RO) uppfattar att den tävlande inte har intagit korrekt startposition innan påbörjat genomförande ska detta åtgärdas av domaren (RO) innan genomförandet får påbörjas. Om den tävlande förutser och påbörjar genomförandet innan startsignal har ljudit ska den tävlandes genomförande avbrytas och skjutstationen ska skjutas om (re-shoot). </p><p id="4.1.5" data-v-22c77eeb><a href="#4.1.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.5</span></a> Den tävlande är själv ansvarig för att tillse att genomförandet påbörjas med korrekt mängd ammunition laddat i vapnet när sådana restriktioner är givna för skjutstationen. Varje extra patron utöver tillåtna mängd ger straffpoäng. </p><p id="4.1.6" data-v-22c77eeb><a href="#4.1.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.6</span></a> Om en tävlande i militär standard division har brister i sin minsta tillåtna utrustning tillåts denne att få åtgärda detta, alternativt flyttas till öppen (Open) division. </p><p id="4.1.7" data-v-22c77eeb><a href="#4.1.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.7</span></a> Att ta siktbild efter att Magasin i / Ladda är kommenderat är tillåtet men då endast mot ett enstaka mål. </p><p id="4.1.8" data-v-22c77eeb><a href="#4.1.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.8</span></a> Domaren (RO) måste förhålla sig i förflyttningen så att denne inte stör den tävlande i dennes genomförande. Domaren (RO) måste kunna ha full uppsikt över den tävlande under hela genomförandet. </p><p id="4.1.9" data-v-22c77eeb><a href="#4.1.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.9</span></a> Om den tävlande inte är startklar när det är dennes tur att genomföra kan domaren (RO) ändra skjutordningen på de tävlande. </p><p id="4.1.10" data-v-22c77eeb><a href="#4.1.10" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.1.10</span></a> Den tävlande kan under särskilda förhållanden efter tillåtelse från domare (RO) få kontrollskjuta sitt vapen för att kontrollera funktionalitet eller för att åtgärda ett eldavbrott. Dessa skott får ej avfyras mot de mål som ingår i genomförandet utan endast mot för ändamålet utplacerade mål eller mot anvisad vall som ej ingår i tävlingen. </p><a id="4.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>4.2 Nyttjade kommandon och genomförande av skjutstation</h3><p id="4.2.1" data-v-22c77eeb><a href="#4.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.2.1</span></a> Följande grundläggande kommandon är de som nyttjas och i nedan angiven ordning. Efter beskrivet svenskt kommando återges detsamma på finska och engelska inom parentes. </p><p class="range-command" data-v-22c77eeb>UTRYM STATIONEN (AMMUTAAN — RANGE IS CLOSED)</p><p data-v-22c77eeb>Kommandot ges i syfte att utrymma skjutstationen. All personal utom den tävlande och domaren (RO) ska utan dröjsmål förflytta sig till uppehållsområdet om inte annat är särskilt angivet av domare (RO). Domaren (RO) ska säkerställa att det är säkert att påbörja genomförandet samt att hörselskydd och skyddsglasögon är applicerade.</p><p class="range-command" data-v-22c77eeb>NÄSTA SKYTT (SEURAAVA AMPUJA — NEXT SHOOTER)</p><p data-v-22c77eeb>Nästa tävlande ansluter till domaren (RO) med anbefalld utrustning medförd och buren enligt anvisningar och inväntar vidare kommandon.</p><p class="range-command" data-v-22c77eeb>HAR SKYTTEN NÅGRA FRÅGOR (ONKO KYSYTTÄVÄÄ — ANY QUESTIONS)</p><p data-v-22c77eeb>Domaren (RO) säkerställer att den tävlande har förstått stationsbeskrivningen. Den tävlande kan här ställa eventuellt uppkomna frågor om genomförandet.</p><p class="range-command" data-v-22c77eeb>MAGASIN I (LIPAS KIINNITÄ — INSERT MAGAZINE / LOAD MAGAZINE)</p><p data-v-22c77eeb>Den tävlande för in ett magasin i vapnet men genomför ingen laddrörelse. Detta kommando ges endast vid genomföranden som startar med ett tomt patronläge. Om vapnet ej är magasinsmatat så nyttjas adekvat laddprocedur för att uppnå ett motsvarande läge. Mekanism får ej vara öppen och/eller uppspänd vid start.</p><p class="range-command" data-v-22c77eeb>LADDA (LATAA JA VARMISTA — LOAD AND MAKE READY)</p><p data-v-22c77eeb>Vapnet laddas med en patron i patronläget och vapnet säkras om möjligt, alternativt slackas vapen med ”decocker” som inte har annan typ av säkring. Om slackning kräver att avtryckaren påverkas ska det vidtalas till domaren (RO). Om fler än ett vapen ska nyttjas av den tävlande vid en skjutstation och ett av dessa vapen är en pistol som ej heller nyttjas som vapen vid start av skjutstationen ska pistolen ej vara laddad med en patron i loppet.</p><p class="range-command" data-v-22c77eeb>STARTPOSITION (ALOITUSASENTOON — STARTING POSITION)</p><p data-v-22c77eeb>Om inget annat anges i stationsbeskrivningen så startar den tävlande i grundställning vilket är:</p><ul data-v-22c77eeb><li data-v-22c77eeb>Enhandsvapen: ståendes vänd mot målet, händerna längs sidorna på kroppen, pistolen hölstrad, om möjligt ska hölstret vara låst.</li><li data-v-22c77eeb>Tvåhandsvapen: vapnet ska bäras eller hållas hängande på bröstet med mynningen nedåt, med eller utan rem runt kroppen och med axelstöd eller kolv vid axeln. Rem avpassad så att vapnet kan föras upp i färdig- eller anläggningsställning. Skjuthanden fattar om pistolgreppet, stödhanden om handskyddet. Avtryckarfingret hålls utanför varbygeln. Saknas handskydd ska stödhanden fatta vapnet framför magasinsstyrningen. Förutom burna handskar får ingen övrig utrustning såsom t.ex. magasin hållas i händerna.</li><li data-v-22c77eeb>Båda fötterna ska vara hitom spärrlinjen.</li></ul><p class="range-command" data-v-22c77eeb>FÄRDIGSTÄLLNING / ANLÄGGNING (VARMISTIN POIS — SAFETY OFF)</p><p data-v-22c77eeb>Detta kommando nyttjas om stationsbeskrivningen anger att genomförandet börjar med ett osäkrat vapen, antingen i färdigställning eller anläggning. Den tävlande har före detta kommando ges intagit rätt startposition enligt stationsbeskrivning med sitt vapen säkrat.</p><p class="range-command" data-v-22c77eeb>ÄR SKYTTEN REDO (ONKO AMPUJA VALMIS — IS SHOOTER READY)</p><p data-v-22c77eeb>Detta kommando nyttjas när den tävlande intagit anbefalld startposition enligt ovan. Den tävlande bekräftar till domaren (RO) att denne är redo genom att anmäla ”REDO”.</p><p class="range-command" data-v-22c77eeb>FÄRDIGA (HUOMIO — STAND BY)</p><p data-v-22c77eeb>Domaren startar genomförandet genom att starta skjuttimern som 2–5 sekunder senare ger ifrån sig en startsignal.</p><p class="range-command" data-v-22c77eeb>ELD (TULTA — FIRE)</p><p data-v-22c77eeb>Om inte ovan nämnda metod med startsignal från skjuttimer nyttjas kan kommandot eld ges av domare (RO) för att starta genomförandet. När den tävlande självmant har avslutat sitt genomförande eller genomförandet avbryts av angiven slutsignal, står den tävlande still och inväntar vidare kommandon från domare (RO).</p><p class="range-command" data-v-22c77eeb>ÄR SKYTTEN KLAR (OLETKO LOPETTANUT — ARE YOU FINISHED)</p><p data-v-22c77eeb>Frågan ställs av domaren (RO) till den tävlande när den tävlande verkar vara klar med sitt genomförande. Om skjutstationen inte har en definierad slutsignal må den tävlande fortsätta genomförandet om så önskas till och med att sluttid är uppnådd. Tidräkning pågår då till och med sista skjutna skott alternativt sluttid är uppnådd. Den tävlande besvarar frågan om denne är klar med att svara ”JA” eller på annat sätt tydligt indikera att denne är klar.</p><p class="range-command" data-v-22c77eeb>PATRON UR, SPÄNN UPP FÖR VISITATION (LIPAS IRTI, LIIKKUVAT TAAKSE / PATRUUNAT POIS, LIIKKUVAT TAAKSE — UNLOAD AND SHOW CLEAR)</p><p data-v-22c77eeb>Den tävlande kontrollerar att vapnet är säkrat. Därefter tar den tävlande ur magasinet alternativt plundrar vapnet om det inte är magasinsmatat. Den tävlande spänner upp vapnet och låter eventuell patron falla till marken. Den tävlande kontrollerar att inget magasin finns fäst vid vapnet samt att ingen patron finns i patronläget genom att se in och känna med ett finger eller kontrolldon genom utkastaren och ut mot magasinsstyrningen samt in mot patronläget. Den tävlande släpper därefter fram mekanismen och för in stödhandens tumme i magasinsstyrningen och blindavfyrar därefter vapnet i skjutriktningen. Därefter spänner den tävlande upp mekanismen och låter domaren (RO) visitera patronläget. Vid tävling utomlands visiterar domaren (RO) patronläget INNAN den tävlande blindavfyrar sitt vapen. Eventuella skott som avfyras efter att kommandot PATRON UR är givet räknas som vådaskott och hanteras därefter enligt regelboken. Den tävlande är alltid ensamt ansvarig för att tillse att sitt vapen är oladdat och utan magasin efter ett genomförande har avslutats.</p><p class="range-command" data-v-22c77eeb>BLINDAVFYRA (TYHJÄ LAUKAUS — HAMMER DOWN)</p><p data-v-22c77eeb>Efter att domare (RO) har visiterat patronläget kommenderas BLINDAVFYRA och den tävlande blindavfyrar då sitt vapen i skjutriktningen. Om vapnet har magasinsstyrd säkring så släpps mekanismen fram och ett tomt magasin förs in i vapnet innan det blindavfyras i skjutriktningen. Efter genomförd blindavfyrning avlägsnas brukade tomma magasin.</p><p class="range-command" data-v-22c77eeb>HÖLSTRA / PIPA UPP (ASE KOTELOON / ASE KANTOASENTOON — HOLSTER / MUZZLE UP)</p><p data-v-22c77eeb>Efter att detta kommando är givet och efterföljt är den tävlande klar att lämna skjutstationen. Vid kommando HÖLSTRA så hölstrar den tävlande sitt enhandsvapen på ett säkert sätt och domaren (RO) ger därefter den tävlande tillåtelse att lämna skjutstationen. Vid kommando PIPA UPP tillser den tävlande att dennes brukade tvåhandsvapen bärs på ett sådant sätt att pipan är riktad rakt upp alternativt rakt ner. Den tävlande kan alternativt packa ner sitt tvåhandsvapen i ett fodral eller därför anpassad låda och kan då därefter förflytta vapnet med pipan riktad i horisontalplanet.</p><p class="range-command" data-v-22c77eeb>MARKERA (TAULUILLE — RANGE IS CLEAR)</p><p data-v-22c77eeb>Den tävlande tillsammans med domare (RO) och protokollförare (SK) kontrollerar träffresultat. Klistrare medföljer bakom och klistrar tavlan efter att de har fått klartecken från protokollföraren (SK). Nästa tävlande har då tillträde till skjutstationen och kan ställa upp inför startposition. Övriga tävlande kvarstannar i uppehållsområde.</p><p class="range-command" data-v-22c77eeb>AVBRYT (SEIS — STOP)</p><p data-v-22c77eeb>Vid kommando AVBRYT avbryter den tävlande all verksamhet och står still. Vapnet ska vara riktat innanför pekvinklarna, fingret ska vara utanför varbygeln och den tävlande inväntar vidare instruktioner från domaren (RO). ALLA har rätten att nyttja detta kommando då potentiell farlig situation uppstår. Detta gäller även om domare (RO) inte har uppfattat samma situation. Överträdelser mot kommandot AVBRYT leder till diskvalificering från tävlingen.</p><p class="range-command" data-v-22c77eeb>MANÖVER (VARO — WATCH OUT)</p><p data-v-22c77eeb>Kommandot MANÖVER nyttjas för att göra den tävlande medveten på att dennes uppträdande tangerar att överträda säkerhetsreglerna. Exempel på detta är:</p><ul data-v-22c77eeb><li data-v-22c77eeb>Den tävlande är på väg att avfyra sitt vapen mot stålmål på ett avstånd som är närmare än minsta tillåtna skjutavstånd för stålmål.</li><li data-v-22c77eeb>Den tävlande är på väg att föra sitt vapen utanför pekvinklarna.</li><li data-v-22c77eeb>Den tävlande avfyrar sitt vapen på ett sådant sätt att dukade barrikader träffas och kan orsaka splitter och rikoschetter.</li></ul><p data-v-22c77eeb>Om den tävlande uppmärksammar kommandot MANÖVER och ändrar sitt beteende så fortsätter genomförandet enligt tidigare givna instruktioner. Om den tävlande inte hörsammar kommandot MANÖVER och fortsätter genomförandet med ett beteende som påverkar säkerheten så ska kommandot AVBRYT kommenderas av domare (RO) och genomförandet avbryts.</p><p id="4.2.2" data-v-22c77eeb><a href="#4.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.2.2</span></a> Om skjutstationen innefattar flertalet vapentyper ska kommandon rörande vapnet ges specifikt för respektive vapentyp. Exempel: för pistol, MAGASIN I. För karbin, LADDA. </p><p id="4.2.3" data-v-22c77eeb><a href="#4.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>4.2.3</span></a> Vid behov kan ytterligare kommandon nyttjas vid skjutstationen. Exempelvis: TA PLATS I FORDONET. Om sådana kommandon förekommer ska dessa förmedlas till de tävlande i stationsbeskrivningen samt repeteras för den tävlande vid startposition innan HAR SKYTTEN NÅGRA FRÅGOR kommenderas. </p><hr data-v-22c77eeb><a id="5" data-v-22c77eeb></a><h2 data-v-22c77eeb>5. Eldhandvapen och Utrustning</h2><a id="5.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>5.1 Allmänt</h3><p id="5.1.1" data-v-22c77eeb><a href="#5.1.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.1</span></a> Den tävlande deltar i den division som denne registrerats i inför tävlingen. Den tävlandes eldhandvapen och utrustning skall uppfylla kraven för aktuell division. Vapenkontroll skall som minst genomföras vid nationellt mästerskap eller högre nivå, och skall omfatta eldhandvapnets säkerhet och överensstämmelse med bestämmelserna för avsedd division. </p><p class="se-extension" data-v-22c77eeb><strong data-v-22c77eeb>Militära bestämmelser:</strong> Vid Försvarsmaktsmästerskap bör behörig vapentekniker genomföra vapenkontroll på tjänstevapen (FM-klass 5,56 / 7,62). Kontrollen skall omfatta säkerhetskontroll (SK), och kontroll att grundtillsyn (GT) har genomförts inom godkänd period. </p><p id="5.1.2" data-v-22c77eeb><a href="#5.1.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.2</span></a> Alla eldhandvapen och all buren utrustning som nyttjas under tävlingen skall vara säkra att använda. Detta är den tävlandes ansvar att tillse. </p><p id="5.1.3" data-v-22c77eeb><a href="#5.1.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.3</span></a> Förändring eller modifiering som minskar ett vapens säkerhet är förbjudet. Det är inte tillåtet att åsidosätta en säkring, detta gäller dock inte grepp- och avtryckarsäkring som är tillåtna såvida vapnet är försett med en annan säkring som kan nyttjas av skytten. </p><p id="5.1.4" data-v-22c77eeb><a href="#5.1.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.4</span></a> Den tävlandes eldhandvapen eller division kan inte ändras under tävlingen utan tillstånd från tävlingsledaren (MD) eller banchefen (RM). Vapenklass kan endast ändras från Standarddivisioner eller Militär division till Öppen division. Att byta eldhandvapen eller dess huvuddelar kräver tillstånd från tävlingsledaren (MD) eller banchefen (RM). Annan utrustning kan bytas efter behov. Till ett vapens huvuddelar räknas sikte, pipa, låda, underbeslag och ramstycke, mekanism, slutstycke eller motsvarande del såvida den inte innefattar slutstyckshuvudet vilket är tillåtet att byta utan tillstånd. En förstoringssats är inte att betrakta som en huvuddel. Inför en skarpskyttestation är det, trots denna bestämmelse, tillåtet att byta sikte utan särskilt tillstånd. </p><p class="se-extension" data-v-22c77eeb><strong data-v-22c77eeb>Militära bestämmelser:</strong> Det är inte tillåtet att byta ett slutstyckshuvud eller motsvarande del i Försvarsmaktens vapen. Detta får endast göras av behörig vapentekniker. </p><p id="5.1.5" data-v-22c77eeb><a href="#5.1.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.5</span></a> Om en tävlandes eldhandvapen eller burna utrustning inte uppfyller kraven i någon division så registreras inget resultat för skytten. </p><p id="5.1.6" data-v-22c77eeb><a href="#5.1.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.6</span></a> Kontroll av en tävlandes eldhandvapen eller burna utrustning får göras av tävlingsledare (MD), banchef (RM) eller domare (RO) när som helst under en tävling. </p><p id="5.1.7" data-v-22c77eeb><a href="#5.1.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.7</span></a> Om ett eldhandvapen eller en buren utrustningsdetalj inte bedöms som säker så måste den/det repareras eller bytas för att den tävlande ska få fortsätta tävlingen. </p><p id="5.1.8" data-v-22c77eeb><a href="#5.1.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.8</span></a> Ett eldhandvapen bedöms inte som säkert om säkring, säkerhetsupphak (hanuppfång), hanspärr, avspänningsregel eller tändstiftssäkring inte fungerar, eller om det skjuter eldskurar eller helautomatisk eld då säkringsomställaren (motsv.) är ställd på patronvis eld. Ett eldhandvapen får inte avlossa skott då avtryckaren släpps fram eller om det tappas på ett hårt underlag. </p><p id="5.1.9" data-v-22c77eeb><a href="#5.1.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.9</span></a> Banchefen (RM) beslutar huruvida ett eldhandvapen eller buren utrustning uppfyller kraven i reglerna. </p><p id="5.1.10" data-v-22c77eeb><a href="#5.1.10" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.10</span></a> Banchefen (RM) äger rätt att förbjuda ett särskilt eldhandvapen eller en särskild typ av ammunition vid en tävling, eller för vissa stationer, med anledning av: </p><ul data-v-22c77eeb><li data-v-22c77eeb>tävlingsregler, skjutbanebestämmelser (motsv.) eller</li><li data-v-22c77eeb>om det annars finns risk att skada utrustning på skjutbanan</li><li data-v-22c77eeb>säkerhetsskäl.</li></ul><p id="5.1.11" data-v-22c77eeb><a href="#5.1.11" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.11</span></a> Alla patroner skall ha en kraftfaktor om minst 2450 [kulvikt i gram (g) × utgångshastighet i meter per sekund (m/s)]. </p><p data-v-22c77eeb> En exakt mätning av kraftfaktorn krävs vanligen inte. Emellertid så kan en mätning genomföras då det finns rimligt tvivel att kraftfaktorn inte uppfylls. Mätningen genomförs genom att väga kulan från en (1) patron och mäta utgångshastigheten från fyra (4) patroner, varvid medelvärdet av utgångshastigheterna nyttjas. </p><p id="5.1.12" data-v-22c77eeb><a href="#5.1.12" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.1.12</span></a> Eldhandvapen som inte används för att avlossa skott vid en station kan definieras som ’burna men ej nyttjade’. Domaren (RO) skall visitera eldhandvapnet före stationen påbörjas. Patronlägesflagga, kontrolldon eller motsvarande bör om möjligt monteras. </p><a id="5.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>5.2 Eldhandvapen</h3><p id="5.2.1" data-v-22c77eeb><a href="#5.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.2.1</span></a> Vid en tävling kan följande eldhandvapen nyttjas: </p><ul data-v-22c77eeb><li data-v-22c77eeb>Karbin</li><li data-v-22c77eeb>Gevär</li><li data-v-22c77eeb>Pistol</li><li data-v-22c77eeb>Revolver</li><li data-v-22c77eeb>Skarpskyttegevär</li><li data-v-22c77eeb>Prickskyttegevär</li><li data-v-22c77eeb>Hagelgevär</li></ul><p data-v-22c77eeb>Närmare bestämmelser anges i bilaga 2–5.</p><a id="5.3" data-v-22c77eeb></a><h3 data-v-22c77eeb>5.3 Utrustning</h3><p id="5.3.1" data-v-22c77eeb><a href="#5.3.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.1</span></a> Bärande av ett eldhandvapen eller magasin regleras inte, men det ska vara säkert och robust. Vid skjutstationens början bär den tävlande magasinen och ammunitionen i sin burna utrustning om inte stationsbestämmelserna anger annat. </p><p id="5.3.2" data-v-22c77eeb><a href="#5.3.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.2</span></a> Till en pistol skall den tävlande ha ett hölster av tjänstetyp. </p><p id="5.3.2.1" data-v-22c77eeb><a href="#5.3.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.2.1</span></a> Hölster som medger att vapnet rör sig inuti hölstret på ett sätt så att vapnet kan osäkras eller avfyras (i hölstret) är förbjudna. Vidare är hölster vars låsmekanism avaktiveras med ett finger som riskerar att (i draget) oavsiktligen hamna innanför varbygeln förbjudna. </p><p id="5.3.2.2" data-v-22c77eeb><a href="#5.3.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.2.2</span></a> Ett hölster ska skydda vapnet från smuts och skada. Det ska som minst täcka kornet, mantelns överdel och sidor från mynningen till främre delen av utkastaröppningen och avtryckaren (varbygeln). En mantel med öppning över pipan skall täckas minst halva dess längd, och en revolvers hela pipa skall vara täckt. </p><p id="5.3.2.3" data-v-22c77eeb><a href="#5.3.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.2.3</span></a> Hölster skall ha en pålitlig låsmekanism som förhindrar att vapnet kan tappas. Den tävlande skall, på anmodan av en tävlingsfunktionär, bevisa att låsningen är säker. Hölstret testas av en domare (RO) på stationsområdet. Förfarande: </p><ol data-v-22c77eeb><li data-v-22c77eeb>Ett fullt magasin sätts i den i övrigt oladdade pistolen. Revolver testas utan ammunition.</li><li data-v-22c77eeb>Det löstagna hölstret vänds uppochned med mynningen pekandes inom pekvinklarna.</li><li data-v-22c77eeb>Om vapnet lossnar från hölstret är hölstret förbjudet att använda vid tävlingen till dess att det reparerats och klarar testet.</li></ol><p id="5.3.2.4" data-v-22c77eeb><a href="#5.3.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.2.4</span></a> Hölstrets konstruktion och placering måste medge att den tävlande kan dra vapnet med mynningen i ofarlig riktning och utan att svepa sig själv. När vapnet är hölstrat och skytten står i grundställning skall mynningen inte peka mer än två meter bort från den tävlande (räknat där kärnlinjen träffar marken). </p><p id="5.3.3" data-v-22c77eeb><a href="#5.3.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.3</span></a> De tävlandes och domarnas (RO) klädsel skall vara tålig nog för fältbruk och ur allmän synpunkt anständig. Domare (RO) ska vara tydligt utmärkt t.ex. med varselväst. </p><p class="se-extension" data-v-22c77eeb><strong data-v-22c77eeb>Militära bestämmelser:</strong> Tävlande i FM-klass (5,56 och 7,62) skall bära reglementsenlig uniform. Fältlystran anses råda på tävlingsområdet varför lättnader och anpassning av klädsel är tillåten, utom vid prisutdelningar eller liknande ceremonier. Det är aldrig tillåtet att till uniform nyttja märken och tecken som inte utgör tjänstetecken, t.ex. ”patchar” med företagslogotyper (motsv.). </p><p id="5.3.4" data-v-22c77eeb><a href="#5.3.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>5.3.4</span></a> Militärdivisionens närmare bestämmelser framgår i bilaga 6. </p><hr data-v-22c77eeb><a id="6" data-v-22c77eeb></a><h2 data-v-22c77eeb>6. Mål och Poäng</h2><a id="6.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.1 Allmänna principer</h3><p id="6.1.1" data-v-22c77eeb><a href="#6.1.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.1</span></a> De måltavlor (motsv.) som används bör representera sådana mål som eldhandvapnen i fråga kan antas nyttjas mot. </p><p id="6.1.2" data-v-22c77eeb><a href="#6.1.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.2</span></a> Två träffar räknas för varje måltavla om inte stationsbestämmelserna anger annat. </p><p id="6.1.3" data-v-22c77eeb><a href="#6.1.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.3</span></a> En enskild skjutstation bör inte nyttja fler än fem olika typer av mål. </p><p id="6.1.4" data-v-22c77eeb><a href="#6.1.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.4</span></a> Upp till 10 % av skjutstationens maximala poäng kan ges för olika typer av särskilda uppgifter (såsom att kasta en handgranat t.ex.). </p><p id="6.1.5" data-v-22c77eeb><a href="#6.1.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.5</span></a> Skjutstationens poäng beräknas från träffar i målen och poäng för eventuella särskilda uppgifter. </p><p id="6.1.6" data-v-22c77eeb><a href="#6.1.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.1.6</span></a> Ytterligare detaljerade instruktioner avseende mål och poänggivning finns i de tekniska bilagorna och i ”Riktlinjer för tävlingar”. </p><a id="6.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.2 Mål</h3><p id="6.2.1" data-v-22c77eeb><a href="#6.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.1</span></a> Lämpliga mål är måltavlor enligt bilaga 1, reaktiva mål, mål som nyttjas av Försvarsmakten, eller delar av dessa. Andra mål får också nyttjas om deras form och poänggivning görs känt för de tävlande. </p><p id="6.2.2" data-v-22c77eeb><a href="#6.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.2</span></a> Målen måste tydligt kunna urskiljas från bakgrunden och från varandra när de observeras från skjutplats, oberoende av väder och ljusförhållanden (under tävlingen). Mål som är på mer än 100 m avstånd skall förses med tydligt kontrasterande bakgrund vid nationella eller internationella mästerskap. </p><p data-v-22c77eeb> Målens form och eventuell bild (t.ex. fototapet) skall följa god sed, och vara synliga och identifierbara för alla tävlande. Skjutstationer skall utvärdera skjutskicklighet, inte målupptäckt. </p><p class="se-extension" data-v-22c77eeb><strong data-v-22c77eeb>Militära bestämmelser:</strong> Vid vissa tävlingar kan målupptäckt vara ett delmoment. Det ska då särskilt anges i tävlingsinbjudan att regel 6.2.2 inte följs p.g.a. målupptäcktsmoment. </p><p id="6.2.3" data-v-22c77eeb><a href="#6.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.3</span></a> Reaktiva mål kan t.ex. vara fyrkanter och cirklar om 20–30 cm diameter, tillverkade av högkvalitetsstål (Hardox) för att motverka risk för rikoschetter. Målplattor kan också tillverkas av andra material (t.ex. gummi). </p><p id="6.2.4" data-v-22c77eeb><a href="#6.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.4</span></a> Reaktiva mål skall alltid falla eller gå sönder av en godtagbar träff (t.ex. en lerduva ska ha minst ett hål i sig), och de ska vara monterade och fastsatta på ett sådant sätt att de inte kan vridas i sidled. Förutom vid nationella och internationella mästerskap så får s.k. gong-mål nyttjas, alltså stålmål som då de träffas pendlar och/eller plingar eller på annat vis indikerar träffen. En tävlande kan be domaren att verifiera träffarna genom att anmäla ”TRÄFF!”. </p><p id="6.2.5" data-v-22c77eeb><a href="#6.2.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.5</span></a> Ett reaktivt mål kan anges vara ett ”blockerande mål”, vilket då måste falla eller gå sönder innan skytten får gå vidare till nästa mål. Det är inte möjligt att nyttja blockerande mål på skjutstationer som har ett begränsat antal skott (limited shots scoring). </p><p id="6.2.6" data-v-22c77eeb><a href="#6.2.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.6</span></a> Skjutavstånd till metallmål skall med anledning av risken för rikoschett och splitter vara minst 8 m för pistol, revolver och hagelgevär (med hagelpatron) respektive 20 m för karbin/gevär eller hagelgevär med slug/brenneke. </p><p class="se-extension" data-v-22c77eeb><strong data-v-22c77eeb>Militära bestämmelser:</strong> Vid försvarsmaktstävlingar är SäkR styrande och minsta avstånd till stålmål är då 50 m om inte fragmenterande ammunition nyttjas vid aktuell skjutstation. </p><p id="6.2.7" data-v-22c77eeb><a href="#6.2.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.7</span></a> Reaktiva metallmål skall kalibreras med den typ av eldhandvapen som skall nyttjas på skjutstationen. Kalibreringsskottet avfyras från en skjutplats som är tillgänglig för den tävlande under genomförandet. På skjutstationer där skytten kan välja vapen så skall kalibreringsskottet skjutas med pistol om sådan får nyttjas av den tävlande på skjutstationen. Reaktiva mål måste falla om en den träffas av en fullständig träff inom träffområdet. Träffområdet är det område som är synligt från skjutplats. När det gäller stålmål av Popper-typ så kalibreras för träff i det runda området om inte annat anges i stationsbestämmelserna. </p><p data-v-22c77eeb> Kalibrering av reaktiva mål med hagelgevär skall genomföras med en hagelladdning om max 28 g och från en pipa som inte är längre än 66 cm (26&quot;) försedd med cylinderchoke (ingen trångborrning). </p><p id="6.2.8" data-v-22c77eeb><a href="#6.2.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.8</span></a> Träffar på metallmål skall alltid målas innan nästa skytt skall starta, förutom hagelträffar eller plåtmål som är del i ett aktivt fallmålsystem (t.ex. ”SAAB-mål”, Fallmål 2010/2015/2020 o.s.v.). Vid tävlingar på lägre än nationell nivå bortses från denna regel. </p><p id="6.2.9" data-v-22c77eeb><a href="#6.2.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.2.9</span></a> ”Skjut-ej-mål” (no-shoot) skall vara i annan färg än mål som skall beskjutas, och skall vara tydligt uppmärkta med S/E eller N/S (i Finland och Estland E/A). </p><a id="6.3" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.3 Poängmarkering</h3><p id="6.3.1" data-v-22c77eeb><a href="#6.3.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.1</span></a> Markering genomförs av domaren (RO) som skall vara utrustad med en tolkskiva (scoring overlay/gauge card). </p><p id="6.3.2" data-v-22c77eeb><a href="#6.3.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.2</span></a> Mål får ej röras före markeringen sker. Om en tävlande rör sig närmare ett mål än en (1) m, och det är möjligt att vederbörande har påverkat målet före markering har skett, kan domaren (RO) fastställa att inga godtagbara träffar i det målet skall räknas. </p><p id="6.3.3" data-v-22c77eeb><a href="#6.3.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.3</span></a> I målet som beskrivs i bilaga 1 (metric-tavla) så räknas en träff som bryter poänglinjen som en träff. Om en sådan tavla kapas ned (motsv.) så måste en ny poänglinje ritas 5 mm in från snittet. Ett mål bakom skyl får inte kapas. På andra wellpappmål räknas ett hål som bryter in i den fastställda träffytan som en träff. Träff av splitter och andra fragment som uppenbart inte är en direkt träff av projektilen skall ej räknas som träff. En träff som skjutits genom skyl skall räknas som träff även om projektilen träffar med bredsida i målet (s.k. nyckelhål/tumling). Om målet är så pass skadat att markering inte kan ske, t.ex. för att det beskjutits på nära avstånd, skall den tävlande genomföra omskjutning (re-shoot) av skjutstationen. </p><p id="6.3.4" data-v-22c77eeb><a href="#6.3.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.4</span></a> I vridmål räknas inte hål som är större än dubbla kuldiametern som träff. </p><p id="6.3.5" data-v-22c77eeb><a href="#6.3.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.5</span></a> Käppar (läkt el. motsvarande) som endast håller upp mål eller regnskydd för mål är genomskjutningsbara. Alla mål och andra konstruktioner (kulisser etc.) på skjutstationen är ej genomskjutningsbara såvida inte annat angivits i stationsbestämmelserna. </p><p id="6.3.6" data-v-22c77eeb><a href="#6.3.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.6</span></a> Om samma projektil träffar två mål och hålet i det närmsta målet är helt och hållet i en poängzon, utan att bryta poänglinjen (ut från målet), så skall endast det närmsta målet räknas som träffat. Om det närmsta målet är genomskjutningsbart så räknas det bortre målet också som träffat. Om hålet i det närmsta målet bryter poänglinjen (ut från målet) så räknas båda målen som träffade. </p><p id="6.3.7" data-v-22c77eeb><a href="#6.3.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.7</span></a> En träff som bryter linjen mellan två poängzoner räknas som träff i den högre poängzonen. </p><p id="6.3.8" data-v-22c77eeb><a href="#6.3.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.8</span></a> Om den tävlande protesterar mot markeringen så skall målet bedömas av banchefen (RM), vars beslut är slutgiltigt. </p><p id="6.3.9" data-v-22c77eeb><a href="#6.3.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.3.9</span></a> Om den tävlande protesterar mot markeringen av ett reaktivt mål som beskjutits med hagelgevär så kan denne begära att kalibrering skall ske omedelbart efter genomförandet. </p><p data-v-22c77eeb> Om målet indikerar träff då det beskjuts (med kalibreringsskottet) så bedöms den markering som skytten protesterar mot vara en bom/miss. Om målet inte indikerar träff då det beskjuts skall skjutstationen skjutas om och banchefen (RM) skall meddelas. </p><a id="6.4" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.4 Målens poäng</h3><p id="6.4.1" data-v-22c77eeb><a href="#6.4.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.1</span></a> Om målet som beskrivs i bilaga 1 (metric-tavla) nyttjas ger: </p><ul data-v-22c77eeb><li data-v-22c77eeb>A-zon och B-zon 5 poäng,</li><li data-v-22c77eeb>C-zon 3 poäng och</li><li data-v-22c77eeb>D-zon 1 poäng.</li></ul><p id="6.4.2" data-v-22c77eeb><a href="#6.4.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.2</span></a> Vid särskiljning mellan tävlande med samma poängsumma vinner den som under tävlingen haft flest träffar i A-zon, därefter flest träffar i B-zon och därefter i C-zon. </p><p id="6.4.3" data-v-22c77eeb><a href="#6.4.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.3</span></a> Vid markering av mål räknas poäng genom att räkna de träffar med högst poäng. (Normalt räknas två träffar om inte annat anges i stationsbestämmelserna, se 6.1.2.) </p><p id="6.4.4" data-v-22c77eeb><a href="#6.4.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.4</span></a> En träff på ett fallande mål eller ett sönderfallande mål ger fem (5) eller tio (10) poäng. Blockerande mål ger alltid 10 poäng. </p><p id="6.4.5" data-v-22c77eeb><a href="#6.4.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.5</span></a> Poängzonerna på andra typer av mål kan ge tio (10), fem (5), tre (3) eller ett (1) poäng utefter vad som angivits. </p><p class="se-extension" data-v-22c77eeb>I Sverige nyttjas även 4 och 2 poäng enligt fastställande av FM.</p><p id="6.4.6" data-v-22c77eeb><a href="#6.4.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.4.6</span></a> Ytterligare uppgifter kan också generera poäng. </p><a id="6.5" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.5 Poängberäkningsmetoder</h3><ol type="a" data-v-22c77eeb><li data-v-22c77eeb><strong data-v-22c77eeb>Obegränsad:</strong> Tiden och antalet skott på skjutstationen är inte begränsade.</li><li data-v-22c77eeb><strong data-v-22c77eeb>Begränsad tid:</strong> Tiden för genomförandet är begränsad men antalet skott är obegränsade. Resultatet är summan av antalet poäng som markerats på målen. Denna metod används till exempel med uppdykande och försvinnande mål.</li><li data-v-22c77eeb><strong data-v-22c77eeb>Begränsade skott:</strong> Antalet skott för genomförandet är begränsade, men tiden är obegränsad.</li><li data-v-22c77eeb><strong data-v-22c77eeb>Begränsad tid och skott med poängkvot:</strong> Såväl tiden som antalet skott är begränsade med poängkvot beräknas som resultat. De tävlande placeras som vid obegränsad metod.</li></ol><a id="6.6" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.6 Straffpoäng</h3><p id="6.6.1" data-v-22c77eeb><a href="#6.6.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.1</span></a> Om en tävlande inte slutför en skjutstation så räknas poäng och tid fram till dess. Missar och icke beskjutna mål ger straffpoäng i enlighet med reglerna. </p><p id="6.6.2" data-v-22c77eeb><a href="#6.6.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.2</span></a> Vad som ger upphov till procedurfel skall anges i förväg i stationsbestämmelserna och får inte ges för andra anledningar än som angivits där eller i dessa regler. </p><p data-v-22c77eeb> Ett procedurfel är en handling som avviker från stationsbestämmelserna. Som straff ges tio (10) straffpoäng för varje sådant fel. Domaren (RO) skall fastställa antalet fel och anledningen till dessa. Detta protokollförs tydligt i resultathanteringssystemet. </p><p data-v-22c77eeb>Procedurfel får utdömas för att inte ha beskjutit ett mål, givet att detta anges i stationsbestämmelserna.</p><p data-v-22c77eeb> Om den tävlande nuddar marken utanför en spärrlinje under skjutning, och genom detta får en tydlig fördel, skall procedurfel utdömas för varje skott som avfyras under kontakt med marken utanför spärrlinjen. Om den tävlande inte får en tydlig fördel så utdöms ett procedurfel. Antalet procedurfel som utdöms får inte överstiga antalet tillgängliga poäng. </p><p data-v-22c77eeb> Om den tävlande genar och då överträder en begränsningslinje skall ett procedurfel utdömas för varje skott som avfyras efter genvägen togs. Den tävlande kan återställa en genväg som tagits av misstag genom att backa tillbaka till den plats där genvägen påbörjades och fortsätta genomförandet av skjutstationen från den platsen. </p><p id="6.6.3" data-v-22c77eeb><a href="#6.6.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.3</span></a> Varje stav som faller från en Tiitinen-tunnel ger ett procedurfel. </p><p id="6.6.4" data-v-22c77eeb><a href="#6.6.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.4</span></a> Träff i ett ”skjut-ej”-mål (S/E) ger tio (10) straffpoäng. Maximalt två (2) träffar räknas för varje S/E-mål om inget annat angivits i stationsbestämmelserna. </p><p id="6.6.5" data-v-22c77eeb><a href="#6.6.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.5</span></a> Missar/bommar på försvinnande eller vridmål bestraffas ej. </p><p id="6.6.6" data-v-22c77eeb><a href="#6.6.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.6</span></a> Om ett fallande mål står kvar eller ett sönderfallande mål förblir helt utdöms straffpoäng motsvarande dubbla maximala poängen av en träff. </p><p id="6.6.7" data-v-22c77eeb><a href="#6.6.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.7</span></a> Provanläggning mot mer än ett mål före skjutstationens genomförande startar ger ett procedurfel. </p><p id="6.6.8" data-v-22c77eeb><a href="#6.6.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.8</span></a> Att nyttja fler än ett benstöd eller att lämna benstöd under genomförandet ger ett procedurfel. </p><p id="6.6.9" data-v-22c77eeb><a href="#6.6.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.9</span></a> Vid obegränsad metod bestraffas en bom/miss med straffpoäng motsvarande dubbla maximala poängen för en träff. </p><p id="6.6.10" data-v-22c77eeb><a href="#6.6.10" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.10</span></a> Vid begränsad tid och vid begränsad tid och skott bestraffas inte bommar/missar. Varje skott som avlossas efter tidsgränsen ger straffpoäng motsvarande maximala poängen för en träff. Extraskott markeras i en särskild kolumn i resultathanteringssystemet. </p><p id="6.6.11" data-v-22c77eeb><a href="#6.6.11" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.11</span></a> Vid begränsade skott ger en bom/miss eller ett extraskott straffpoäng motsvarande dubbla maximala poängen för en träff. Extraskott markeras i en särskild kolumn i resultathanteringssystemet / protokollet. </p><p id="6.6.12" data-v-22c77eeb><a href="#6.6.12" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.12</span></a> Om ett blockerande mål inte fälls eller skjuts sönder av den tävlande utdöms ett procedurfel. Om felet ger tydlig fördel för den tävlande så utdöms ett procedurfel för varje skott som därefter skjuts. </p><p id="6.6.13" data-v-22c77eeb><a href="#6.6.13" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.13</span></a> Om en tävlande begär det så kan banchefen (RM) bestämma ett särskilt avdrag från en skjutstations poäng om en tävlande med anledning av fysisk skada el. dyl. begränsning är oförmögen att genomföra skjutstationen i enlighet med stationsbestämmelserna. Om banchefen (RM) accepterar begäran skall denne definiera ett avdrag om 1–20 % av skjutstationens poäng innan den tävlande påbörjar skjutstationen. Avdraget utförs genom erforderligt antal procedurfel. Banchefen (RM) kan också besluta att inte dra av några poäng om den tävlande har en särskilt omfattande fysisk begränsning. Om banchefen (RM) nekar begäran så tas bestraffningar med i resultatet som normalt. </p><p id="6.6.14" data-v-22c77eeb><a href="#6.6.14" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.6.14</span></a> Vid alla beräkningsmetoder kan en maximal tid fastställas för skjutstationens genomförande. Härvid rekommenderas 180 sekunder. För varje skott efter tidsgränsen dras maximala poängen för en träff av från resultatet. Extraskott markeras i en särskild kolumn i resultathanteringssystemet. Domaren (RO) äger rätt att avbryta genomförandet då tidsgränsen löpt ut. </p><a id="6.7" data-v-22c77eeb></a><h3 data-v-22c77eeb>6.7 Tävlingsresultat</h3><p id="6.7.1" data-v-22c77eeb><a href="#6.7.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.1</span></a> Resultat beräknas separat för varje division. Resultat i klasser tas fram från divisionsresultaten. </p><p id="6.7.2" data-v-22c77eeb><a href="#6.7.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.2</span></a> Vid resultatberäkningen skall poäng som givits enligt 6.4 i reglerna reduceras med straffpoäng enligt 6.6 i reglerna. </p><p id="6.7.3" data-v-22c77eeb><a href="#6.7.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.3</span></a> Om obegränsad metod eller metoden begränsade skott nyttjas så beräknas den tävlandes poängkvot genom att dela poängen med tiden (i sekunder). Den tävlande som har den högsta poängkvoten vinner skjutstationen, och tilldelas maximala stationspoäng. Stationspoängen för övriga tävlande beräknas genom att den maximala stationspoängen divideras med stationsvinnarens poängkvot, och produkten multipliceras med de tävlandes egna poängkvoter. </p><p id="6.7.4" data-v-22c77eeb><a href="#6.7.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.4</span></a> Om metoderna begränsad tid eller begränsad tid och skott nyttjas så vinns skjutstationen av den tävlande som har flest poäng, och tilldelas den maximala stationspoängen. Stationspoäng för övriga tävlande beräknas genom att dividera maximala stationspoängen med vinnarens poäng, varpå produkten multipliceras med de tävlandes egna poängsummor från skjutstationen. </p><p id="6.7.5" data-v-22c77eeb><a href="#6.7.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.5</span></a> Den minsta stationspoängen som kan ges är noll (0). </p><p id="6.7.6" data-v-22c77eeb><a href="#6.7.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.6</span></a> En tävlandes matchpoäng är summan av dennes stationspoäng. </p><p id="6.7.7" data-v-22c77eeb><a href="#6.7.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.7</span></a> Den tävlande som har högst matchpoäng är tävlingens segrare. </p><p id="6.7.8" data-v-22c77eeb><a href="#6.7.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>6.7.8</span></a> Resultat skall beräknas med ett program som godkänts av RESUL. Resultat beräknas med fyra decimaler. För att tydliggöra skillnaden mellan tävlande ska resultaten också presenteras som procent. </p><hr data-v-22c77eeb><a id="7" data-v-22c77eeb></a><h2 data-v-22c77eeb>7. Poängräkning</h2><p id="7.1" data-v-22c77eeb><a href="#7.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>7.1</span></a> Varje tävlande är ansvarig för att föra sin egen poängräkning vid sidan av protokollföraren (SK) och att kontrollera att dessa överensstämmer. Poängräkning kan ske elektroniskt eller på pappersblankett. </p><p id="7.2" data-v-22c77eeb><a href="#7.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>7.2</span></a> Domaren (RO) är ansvarig för att kontrollera att nedtecknad information är korrekt innan denne skriver under. Därefter skriver den tävlande under. Efter att båda har signerat protokollet får inga ändringar göras i protokollet utom för att korrigera eventuell felberäkning av totalsumman för skjutstationen. </p><p id="7.3" data-v-22c77eeb><a href="#7.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>7.3</span></a> Om domaren (RO) och den tävlande är oense om poängräkningen ska detta noteras i protokollet och därefter träder regel 8.2 i kraft. </p><p id="7.4" data-v-22c77eeb><a href="#7.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>7.4</span></a> Om det föreligger ett misstag i det officiella resultatet för en skjutstation ska den tävlande som drabbats begära korrigering inom i för tävlingen i tävlingsgenomgången annonserad verifikationstid. Funktionärer ska då genomföra kontrollräkning med eventuell korrigering. Om så inte sker träder regel 8.1.2 i kraft. </p><p id="7.5" data-v-22c77eeb><a href="#7.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>7.5</span></a> Det officiella tävlingsresultatet får inte publiceras innan skjutstationsresultaten är publicerade och samtliga tävlande har haft möjlighet att verifiera sina resultat. </p><hr data-v-22c77eeb><a id="8" data-v-22c77eeb></a><h2 data-v-22c77eeb>8. Omskjutning (Re-shoots) och protestförfarande</h2><a id="8.1" data-v-22c77eeb></a><h3 data-v-22c77eeb>8.1 Omskjutning (Re-shoot)</h3><p id="8.1.1" data-v-22c77eeb><a href="#8.1.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.1</span></a> Den tävlande har rätt till omskjutning (re-shoot) om: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Domaren (RO) vidrör eller på annat sätt stör den tävlande i sitt genomförande.</li><li data-v-22c77eeb>En betydelsefull yttre störning sker som tydligt påverkar den tävlande i sitt genomförande.</li><li data-v-22c77eeb>Den tävlande har inte haft möjlighet att få korrekt information om hur skjutstationen ska genomföras, alternativt den av funktionär förmedlade informationen har varit felaktig.</li><li data-v-22c77eeb>Den tävlande stoppas i sitt genomförande av andra skäl än diskvalificerande säkerhetsöverträdelser.</li></ol><p id="8.1.2" data-v-22c77eeb><a href="#8.1.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.2</span></a> Den tävlande ska genomföra omskjutning (re-shoot) om: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Ifyllt protokoll saknar registrerade träffar, missar, sluttid och/eller signatur. Om den tävlande själv har vägrat att skriva på protokollet så medger detta inte rätten till en omskjutning.</li><li data-v-22c77eeb>Skjutstationens dukning och/eller förfarande har förändrats på ett sådant sätt som inte kan anses försumbart efter att den tävlande har genomfört skjutstationen.</li><li data-v-22c77eeb>Det uppstår en felfunktion på skjutstationsdukningen som gör att skjutstationen inte kan genomföras enligt stationsbeskrivningen. Om ett reaktivt eller fragmenterande mål inte fungerar enligt plan ska genomförandet genast avbrytas.</li><li data-v-22c77eeb>Den tävlande assisteras av någon person under sitt genomförande.</li><li data-v-22c77eeb>Den registrerade sluttiden är uppenbart felaktig eller domaren (RO) uppfattar att den tävlandes registrerade poäng för skjutstationen är uppenbart felaktig.</li><li data-v-22c77eeb>Domaren (RO) eller annan skjutstationsfunktionär på något sätt påverkar/vidrör ett reaktivt mål innan en kalibreringsbegäran är utförd eller om det reaktiva målet inte uppfyller kravet efter en kalibreringsbegäran.</li></ol><p data-v-22c77eeb> Vid oklara fall fattas beslutet om omskjutning (re-shoot) av banchef (RM). Om den tävlande vägrar att genomföra en re-shoot så registreras noll poäng för den tävlande som resultat för aktuell skjutstation. </p><p id="8.1.3" data-v-22c77eeb><a href="#8.1.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.3</span></a> Vid en eventuell omskjutning (re-shoot) räknas föregående resultat bort. Om den tävlande har rätt till en omskjutning ska denne inte tillåtas att markera tavlorna och ej heller ska domare (RO) avslöja föregående sluttid innan den tävlande tar beslut om att genomföra en omskjutning eller inte. </p><p id="8.1.4" data-v-22c77eeb><a href="#8.1.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.4</span></a> Om en omskjutning inte kan genomföras: </p><ol type="a" data-v-22c77eeb><li data-v-22c77eeb>Och sluttid saknas i protokollet registreras noll poäng för genomförd skjutstation.</li><li data-v-22c77eeb>Och protokollet saknar enstaka träffar/missar, fastställs protokollförd poäng.</li><li data-v-22c77eeb>Och protokollet har fler träffar registrerade än vad som vid skjutstationen är möjligt, ska de högst poänggivande träffarna räknas.</li></ol><p id="8.1.5" data-v-22c77eeb><a href="#8.1.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.5</span></a> En felfunktion i eller haveri av den tävlandes eldhandvapen under pågående genomförande leder inte till en omskjutning (re-shoot). </p><p id="8.1.6" data-v-22c77eeb><a href="#8.1.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.1.6</span></a> En hel skjutstation kan strykas om de tävlande inte har haft likartade förutsättningar för att genomföra den och detta kan ha haft en betydlig inverkan på slutgiltigt tävlingsresultat. </p><a id="8.2" data-v-22c77eeb></a><h3 data-v-22c77eeb>8.2 Protestförfarande</h3><p id="8.2.1" data-v-22c77eeb><a href="#8.2.1" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.1</span></a> Om den tävlande är missnöjd med av domare (RO) fattat beslut kan denne klaga hos banchef (RM). </p><p id="8.2.2" data-v-22c77eeb><a href="#8.2.2" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.2</span></a> Om den tävlande är missnöjd med ett av banchefen (RM) fattat beslut kan denne lämna in en protest till tävlingsjuryn. En protest kan inte göras gällande säkerhetsöverträdelser. En tävlande kan dock lämna in en protest kring beslut som tas i motstridighet till gällande regelverk. Protest kan ej heller lämnas in kring frågor rörande markering av tavlor eller banchefens (RM) tolkning av protokollet. </p><p id="8.2.3" data-v-22c77eeb><a href="#8.2.3" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.3</span></a> En protest rörande alla frågor utom poängberäkning ska lämnas in senast två timmar efter berörd incident eller från det att den tävlande blev informerad av incidenten som denne vill protestera. I samtliga fall måste protest lämnas in innan tävlingen formellt avslutas så att en omskjutning (re-shoot) fortfarande är möjlig. </p><p id="8.2.4" data-v-22c77eeb><a href="#8.2.4" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.4</span></a> En tävlingsjury måste fatta beslut kring en protest innan slutgiltigt skjutstationsresultat är publicerat. Tävlingsjuryn måste skapa sig kännedom kring ärendet genom att höra den tävlande, domaren (RO), eventuella ögonvittnen och om möjligt ta del av filmat material rörande incidenten. Beslut ska fattas samma dag som protesten är inlämnad. </p><p id="8.2.5" data-v-22c77eeb><a href="#8.2.5" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.5</span></a> Tävlingsjuryn ska utses vid tävlingsgenomgången innan tävling. Tävlingsjuryns medlemmar består av: tävlingsledaren (MD) som är sammanhållande och är utan rösträtt samt tre utbildade TTS/SRA Domare (RO) som i övrigt inte tillhör tävlingsorganisationen. Tävlingsjuryns medlemmar ska ha utsedda suppleanter som kan träda in vid eventuella jävsituationer. </p><p id="8.2.6" data-v-22c77eeb><a href="#8.2.6" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.6</span></a> När en protest lämnas in till tävlingsjuryn vid tävlingar som ej anordnas av Försvarsmakten ska en protestavgift även betalas vid inlämnandet. Avgiftens storlek fastställs internationellt av RESUL och i Sverige av Svenska Pistolskytteförbundet (SPSF). </p><p id="8.2.7" data-v-22c77eeb><a href="#8.2.7" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.7</span></a> Om utfallet av tävlingsjuryns beslut är till den tävlandes fördel ska avgiften återbetalas till den tävlande. Om utfallet av tävlingsjuryns beslut är till den tävlandes nackdel tillfaller avgiften till RESUL eller i Sverige, Svenska Pistolskytteförbundet (SPSF). </p><p id="8.2.8" data-v-22c77eeb><a href="#8.2.8" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.8</span></a> Det är möjligt för andra förutom den aktuellt genomförande tävlande att lämna in protester kring en incident. Samma procedur som ovan är beskrivet gäller då. </p><p id="8.2.9" data-v-22c77eeb><a href="#8.2.9" data-v-22c77eeb><span class="sk" data-v-22c77eeb>8.2.9</span></a> I tävlingar under riksnivå och vid lokala tävlingar förekommer inte krav på en tävlingsjury. I dessa fall är tävlingsledaren (MD) beslutande organ. Det förekommer då ej heller någon avgift för att lämna in en protest. </p><p class="approved" data-v-22c77eeb> Dessa regler för TTS / SRA har granskats och godkänts av RESUL, FMIF (2023-05-16) och SPSF (2023-06-07). </p><hr data-v-22c77eeb><a id="bilaga1" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 1 — Papptavla IPSC Metric</h2><p data-v-22c77eeb>Alla angivna mått är i millimeter. Se originalregelboken för måttsatt skiss av tavlan.</p><a id="bilaga2" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 2 — Gevär / Karbin</h2><table class="appendix" data-v-22c77eeb><thead data-v-22c77eeb><tr data-v-22c77eeb><th data-v-22c77eeb></th><th data-v-22c77eeb>Öppen</th><th data-v-22c77eeb>Militär standard</th><th data-v-22c77eeb>Standard (Vakio)<sup data-v-22c77eeb>3</sup></th></tr></thead><tbody data-v-22c77eeb><tr data-v-22c77eeb><td data-v-22c77eeb>1. Eldhandvapen nyttjandes centralantänd patron med fast eller löstagbart axelstöd/kolv som kan monteras för genomförandet av en skjutstation.<sup data-v-22c77eeb>1</sup></td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>2. Möjlighet att fästa ett magasin till vapnet om minst 20 patroner.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>3. Vapenrem kan monteras.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>4. Elektroniska och/eller optiska riktmedel.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>5. Benstöd.</td><td data-v-22c77eeb>Maximal tillåtna höjd, 400 mm från kärnlinjen.<sup data-v-22c77eeb>2</sup></td><td data-v-22c77eeb>Maximal tillåtna höjd, 400 mm från kärnlinjen.<sup data-v-22c77eeb>2</sup></td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>6. Främre grepp eller motsvarande.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Maximal längd om 152 mm från vapnets kärnlinje.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>7. Förbättra/byta ut trycke.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>8. Förändra vapnets ytskikt.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen, utom vapentejp/grepptejp och av FM godkänd vapenfärg.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>9. Mindre mekaniska förändringar av vapnets mekanism.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>10. Montering av eftermarknadssäkring.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>11. Mynningsbroms och kompensatorer.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>12. Signaturdämpare och för ändamålet liknande utrustning.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>13. Vapenlampor, fungerande.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr></tbody></table><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>1</sup> Lång eller kort gevär/karbin alternativt karbin i pistolkaliber (PCC).</p><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>2</sup> Mätning av stödbenen görs från kärnlinjen rakt ner när benen är i sitt utfällda läge och maximalt utdragna.</p><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>3</sup> Standard finns inte som division i Sverige.</p><a id="bilaga3" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 3 — Pistol och revolver</h2><table class="appendix" data-v-22c77eeb><thead data-v-22c77eeb><tr data-v-22c77eeb><th data-v-22c77eeb></th><th data-v-22c77eeb>Öppen</th><th data-v-22c77eeb>Militär standard</th><th data-v-22c77eeb>Standard (Vakio)<sup data-v-22c77eeb>3</sup></th></tr></thead><tbody data-v-22c77eeb><tr data-v-22c77eeb><td data-v-22c77eeb>1. Minsta tillåtna kaliber.</td><td data-v-22c77eeb>9 mm.</td><td data-v-22c77eeb>9 mm.</td><td data-v-22c77eeb>9 mm.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>2. Axelstöd/kolv.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>3. Öppna riktmedel.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>4. Elektroniska och optiska riktmedel.</td><td data-v-22c77eeb>Tillåtet, optiska och elektroniska riktmedel ska vara fästa i mantel, laser ska vara fäst i stommen.<sup data-v-22c77eeb>1</sup></td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>5. Tilläggsvikter.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>6. Tumhylla.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>7. Tryckesförändring.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>8. Tryckesviktsförändring.</td><td data-v-22c77eeb>Begränsat.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Begränsat.<sup data-v-22c77eeb>2</sup></td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>9. Förändra vapnets ytskikt och grepp.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen, utom vapentejp/grepptejp och av FM godkänd vapenfärg.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>10. Mindre mekaniska förändringar av vapnets mekanism.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>11. Montering av eftermarknadsdelar för säkring och mantelspärr.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>12. Mynningsbroms och kompensatorer.</td><td data-v-22c77eeb>Ej tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>13. Signaturdämpare.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>14. Vapenlampor, fungerande.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr></tbody></table><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>1</sup> Det föreligger inga restriktioner om vart ett optiskt eller elektroniskt riktmedel monteras på en revolver.</p><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>2</sup> Om vapnet saknar en yttre säkring och/eller mekanism för att slacka hanen ska avfyrningstrycket vara som minst 1500 g.</p><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>3</sup> Standard finns inte som division i Sverige.</p><a id="bilaga4" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 4 — Skarp- och prickskyttegevär</h2><table class="appendix" data-v-22c77eeb><thead data-v-22c77eeb><tr data-v-22c77eeb><th data-v-22c77eeb></th><th data-v-22c77eeb>Öppen</th><th data-v-22c77eeb>Militär standard</th><th data-v-22c77eeb>Standard (Vakio)<sup data-v-22c77eeb>1</sup></th></tr></thead><tbody data-v-22c77eeb><tr data-v-22c77eeb><td data-v-22c77eeb>1. Ett hel- eller halvautomatiskt gevär som skjuts från axeln och nyttjar centralantända patroner.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>2. Viktbegränsning i brukbart skick.</td><td data-v-22c77eeb>Max 25 kg.</td><td data-v-22c77eeb>Max 25 kg.</td><td data-v-22c77eeb>Max 25 kg.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>3. Sikten.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>4. Mekaniska förändringar av vapnet i syfte att förbättra driftsäkerhet och hantering.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Ej tillåtet på tjänstevapen.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>5. Mynningsbromsar, kompensatorer och signaturdämpare.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>6. Stödkuddar och benstöd.</td><td data-v-22c77eeb>Tillåtet så länge stationsbeskrivning inte anger annat.</td><td data-v-22c77eeb>Stödkuddar och av försvarsmakten tilldelat benstöd tillåtet så länge stationsbeskrivning inte anger annat.</td><td data-v-22c77eeb>Tillåtet när så stationsbeskrivning tillåter.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>7. Vapenlampor, fungerande.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>8. Tilläggsvikter.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr></tbody></table><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>1</sup> Standard finns inte som division i Sverige.</p><a id="bilaga5" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 5 — Hagelvapen</h2><table class="appendix" data-v-22c77eeb><thead data-v-22c77eeb><tr data-v-22c77eeb><th data-v-22c77eeb></th><th data-v-22c77eeb>Öppen</th><th data-v-22c77eeb>Militär standard</th><th data-v-22c77eeb>Standard (Vakio)<sup data-v-22c77eeb>1</sup></th></tr></thead><tbody data-v-22c77eeb><tr data-v-22c77eeb><td data-v-22c77eeb>1. Ett eldhandvapen som nyttjar hagelammunition.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td><td data-v-22c77eeb>Tvingande.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>2. Öppna riktmedel.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>3. Elektroniska och optiska riktmedel.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Ej tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>4. Mekaniska förändringar av vapnet i syfte att förbättra driftsäkerhet och hantering.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>5. Mynningsbromsar, kompensatorer och signaturdämpare.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>6. Snabbladdare och magasin.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr><tr data-v-22c77eeb><td data-v-22c77eeb>7. Vapenlampor, fungerande.</td><td data-v-22c77eeb>Tillåtet.</td><td data-v-22c77eeb>Av försvarsmakten tilldelat, tillåtet.</td><td data-v-22c77eeb>Tillåtet.</td></tr></tbody></table><p class="footnote" data-v-22c77eeb><sup data-v-22c77eeb>1</sup> Standard finns inte som division i Sverige.</p><a id="bilaga6" data-v-22c77eeb></a><h2 data-v-22c77eeb>Bilaga 6 — Utrustning för militära divisionerna</h2><p data-v-22c77eeb>Tävlande i militärdivisionen skall minst medföra följande utrustning vid skjutstationens början:</p><ol data-v-22c77eeb><li data-v-22c77eeb>Den pistol som nyttjas i tävlingen, oladdad i hölstret. Om pistolen ej nyttjas under skjutstationen så får ett tomt magasin sitta i pistolen under skjutstationen såvida domaren (RO) medger det.</li><li data-v-22c77eeb>Vid starten av en skjutstation ska minst 90 patroner till karbin/gevär i minst tre (3) magasin om 30 skott medföras. För vapen som nyttjar större patroner såsom 7,62×51 (ptr 10 m.fl.) är fyra (4) magasin om 20 skott tillräckligt.</li><li data-v-22c77eeb>Vid starten av en skjutstation ska minst 30 patroner till pistol i minst två magasin medföras.</li><li data-v-22c77eeb>Vid starten av en skjutstation ska minst en (1) liter vatten bäras.</li><li data-v-22c77eeb>Kniv eller annat eggvapen. Bladlängden skall vara minst 9 cm.</li><li data-v-22c77eeb>Ficklampa, vapenlampa eller annan typ av ficklampa.</li><li data-v-22c77eeb>Vapenrem, fastsatt på vapnet eller medförd i buren utrustning.</li><li data-v-22c77eeb>Sjukvårdsutrustning, minst bestående av en tourniquet och första förband (i internationella regler är nödfilt ett godkänt alternativ till första förband) som medförs i buren utrustning.</li><li data-v-22c77eeb>Stridsväst, kroppsskydd med bäranordning eller stridsgördel.</li><li data-v-22c77eeb>Handskar, lämpliga för fältbruk och i diskret färg. Burna eller medförda i buren utrustning.</li><li data-v-22c77eeb>Klädsel lämpad för fältbruk. <ul data-v-22c77eeb><li data-v-22c77eeb>Lämplig för tjänstebruk.</li><li data-v-22c77eeb>Diskret färg.</li><li data-v-22c77eeb>Långa ärmar och byxben.</li><li data-v-22c77eeb>Vid Försvarsmaktstävling ska svensk fältuniform/stridsuniform bäras.</li></ul></li><li data-v-22c77eeb>Kängor lämpade för fältbruk. <ul data-v-22c77eeb><li data-v-22c77eeb>Lämpliga för tjänstebruk.</li><li data-v-22c77eeb>Diskret färg.</li><li data-v-22c77eeb>Skaften skall täcka fotknölarna.</li></ul></li></ol><p data-v-22c77eeb>Vikten på den tävlandes burna utrustning skall vara minst tolv (12) kg. I vägning ingår utrustning 1–9 enligt lista ovan samt:</p><ul data-v-22c77eeb><li data-v-22c77eeb>Utrustnings-/stridsbälte.</li><li data-v-22c77eeb>Hjälm. All utrustning fast i hjälmen räknas med. Även hörselskydd och skyddsglasögon (som saknar skalmar) m.m. räknas in om skytten bär hjälm.</li><li data-v-22c77eeb>All annan utrustning som medförs i skyttens burna utrustning, t.ex. i en ryggsäck eller väst (och som bärs under varje genomförande).</li><li data-v-22c77eeb>Knä- och armbågsskydd.</li></ul><p data-v-22c77eeb>Avsiktlig lättnad av buren utrustning under en skjutstation är förbjuden.</p><p data-v-22c77eeb>Den obligatoriska utrustningen 1–8 samt 10 enligt ovanstående lista måste kunna nås av den tävlande med minst en hand.</p><p data-v-22c77eeb>Vid skjutstationer som innefattar skjutning med hagelgevär eller skarp-/prickskyttegevär (men inte karbin/gevär) behöver den tävlande inte medföra de obligatoriska magasinen till karbin/gevär såvida viktkraven ändå uppfylls.</p>`,391)]])}var v=c(h,[[`render`,_],[`__scopeId`,`data-v-22c77eeb`]]),y=n({__name:`RulesView`,setup(n){let{locale:a}=l(),o=i(()=>a.value===`fi`?m:v);return(n,i)=>(t(),r(e(o.value)))}});export{y as default};